        if (area <= 0.0) return 0.0;

        const dhdx: number = (hUp - hDown) / this.length;
        const sf: number = this.frictionSlope(Qold, area);

        const Qnew: number = Qold + dt * GRAVITY
                             * area * (dhdx - sf);

