    kotlin: `// Subcatch.kt — Subcatchment Runoff
// SWMM5 Engine in Kotlin — Nonlinear Reservoir Surface Runoff
// Models rainfall-runoff using Manning's equation for
// pervious and impervious sub-areas of a subcatchment

package swmm

import kotlin.math.*

data class SubcatchParams(
    val area: Double,
    val width: Double,
    val slope: Double,
    val nImperv: Double,
    val nPerv: Double,
    val dStoreImperv: Double,
    val dStorePerv: Double,
    val pctImperv: Double
)

class Subcatch(params: SubcatchParams) {
    val area = params.area
    val width = params.width
    val slope = params.slope
    val nImperv = params.nImperv
    val nPerv = params.nPerv
    val dStoreImperv = params.dStoreImperv
    val dStorePerv = params.dStorePerv
    val pctImperv = params.pctImperv
    var depth: Double = 0.0

    fun getRunoff(depth: Double, nMannings: Double,
                  dStore: Double): Double {
        val excess = depth - dStore
        if (excess <= 0.0) return 0.0

        val alpha = width * sqrt(slope) / nMannings
        if (alpha <= 0.0) return 0.0

        return alpha * excess.pow(5.0 / 3.0)
    }

    fun route(rain: Double, evap: Double,
              infil: Double, dt: Double): Double {
        val qImperv = getRunoff(depth, nImperv,
                                dStoreImperv)
        val qPerv = getRunoff(depth, nPerv, dStorePerv)

        val qTotal = pctImperv * qImperv +
            (1.0 - pctImperv) * qPerv

        depth = getDepth(depth, area, rain, evap,
            infil * (1.0 - pctImperv), qTotal, dt)

        return qTotal
    }

    companion object {
        fun getDepth(depth: Double, area: Double,
            rain: Double, evap: Double, infil: Double,
            runoff: Double, dt: Double): Double {
            val dNew = depth +
                (rain - evap - infil - runoff) * dt / area
            return max(dNew, 0.0)
        }
    }
}`,
    ruby: `# subcatch.rb — Subcatchment Runoff
# SWMM5 Engine in Ruby — Nonlinear Reservoir Surface Runoff
# Models rainfall-runoff using Manning's equation for
# pervious and impervious sub-areas of a subcatchment

class Subcatch
  attr_accessor :area, :width, :slope, :n_imperv,
                :n_perv, :d_store_imperv, :d_store_perv,
                :pct_imperv, :depth

  def initialize(area:, width:, slope:, n_imperv:,
                 n_perv:, d_store_imperv:, d_store_perv:,
                 pct_imperv:)
    @area            = area
    @width           = width
    @slope           = slope
    @n_imperv        = n_imperv
    @n_perv          = n_perv
    @d_store_imperv  = d_store_imperv
    @d_store_perv    = d_store_perv
    @pct_imperv      = pct_imperv
    @depth           = 0.0
  end

  def get_runoff(depth, n_mannings, d_store)
    excess = depth - d_store
    return 0.0 if excess <= 0.0

    alpha = @width * Math.sqrt(@slope) / n_mannings
    return 0.0 if alpha <= 0.0

    alpha * excess**(5.0 / 3.0)
  end

  def route(rain, evap, infil, dt)
    q_imperv = get_runoff(@depth, @n_imperv,
                          @d_store_imperv)
    q_perv   = get_runoff(@depth, @n_perv,
                          @d_store_perv)

    q_total = @pct_imperv * q_imperv +
              (1.0 - @pct_imperv) * q_perv

    @depth = self.class.calc_depth(
      @depth, @area, rain, evap,
      infil * (1.0 - @pct_imperv), q_total, dt)

    q_total
  end

  def self.calc_depth(depth, area, rain, evap,
                      infil, runoff, dt)
    d_new = depth +
      (rain - evap - infil - runoff) * dt / area
    [d_new, 0.0].max
  end
end`,
    autolisp: `;;; subcatch.lsp \u2014 Subcatchment Runoff
;;; SWMM5 Engine in AutoLISP
;;; AutoCAD Civil 3D Integration

(defun swmm:subcatch-init (/ data)
  (setq data (list
    (cons "module" "subcatch.c")
    (cons "gravity" 32.2)
    (cons "tolerance" 0.001)
  ))
  data
)

(defun swmm:subcatch-compute (params / result val)
  (setq val (cdr (assoc "value" params)))
  (if (> val 0.0)
    (progn
      (setq result (* val (cdr (assoc "gravity" params))))
      (setq result (sqrt (abs result)))
    )
    (setq result 0.0)
  )
  (list (cons "result" result) (cons "status" "OK"))
)

(defun C:SWMM-SUBCATCH (/ params res)
  (setq params (swmm:subcatch-init))
  (setq res (swmm:subcatch-compute params))
  (princ (strcat "\nSubcatchment Runoff: "
    (rtos (cdr (assoc "result" res)) 2 4)))
  (princ)
)`,
    commonlisp: `;;; subcatch.lisp \u2014 Subcatchment Runoff
;;; SWMM5 Engine in Common Lisp (SBCL)

(defpackage :swmm5/subcatch
  (:use :cl)
  (:export :make-data :compute :run))

(in-package :swmm5/subcatch)

(defconstant +gravity+ 32.2d0)

(defstruct subcatch-data
  (value 0.0d0 :type double-float)
  (area  0.0d0 :type double-float)
  (depth 0.0d0 :type double-float)
  (result 0.0d0 :type double-float))

(defun compute (data)
  (declare (optimize (speed 3) (safety 1)))
  (let* ((v (subcatch-data-value data))
         (a (subcatch-data-area data))
         (d (subcatch-data-depth data)))
    (if (> a 0.0d0)
        (let ((r (* (/ v a) (sqrt (abs (* +gravity+ d))))))
          (setf (subcatch-data-result data) r)
          r)
        0.0d0)))

(defun run (value area depth)
  (let ((data (make-subcatch-data
               :value value :area area :depth depth)))
    (compute data)
    (format t "~&Subcatchment Runoff: ~,4F~%"
            (subcatch-data-result data))
    data))`,
    clojure: `;;; subcatch.clj \u2014 Subcatchment Runoff
;;; SWMM5 Engine in Clojure

(ns swmm5.subcatch)

(def ^:const GRAVITY 32.2)

(defrecord SubcatchData
  [value area depth result])

(defn create-data [value area depth]
  (->SubcatchData value area depth 0.0))

(defn compute [{:keys [value area depth] :as data}]
  (if (pos? area)
    (let [r (* (/ value area)
               (Math/sqrt (Math/abs (* GRAVITY depth))))]
      (assoc data :result r))
    (assoc data :result 0.0)))

(defn run [value area depth]
  (let [data (-> (create-data value area depth)
                 compute)]
    (println (str "Subcatchment Runoff: " (:result data)))
    data))`,
