    ruby: `# lid.rb — LID/Green Infrastructure Controls
# SWMM5 Engine in Ruby — Low Impact Development
# Models bioretention, permeable pavement, infiltration
# trenches, and vegetated swales with layered water balance

module LidType
  BIO_CELL     = :bio_cell
  PERM_PAVE    = :perm_pave
  INFIL_TRENCH = :infil_trench
  VEG_SWALE    = :veg_swale
end

class LidLayer
  attr_reader :depth, :void_frac, :conductivity

  def initialize(depth:, void_frac:, conductivity:)
    @depth        = depth
    @void_frac    = void_frac
    @conductivity = conductivity
  end
end

class LidUnit
  attr_reader :type, :surface, :soil, :storage,
              :drain_coeff, :drain_exp

  def initialize(type:, surface:, soil:, storage:,
                 drain_coeff:, drain_exp:)
    @type        = type
    @surface     = surface
    @soil        = soil
    @storage     = storage
    @drain_coeff = drain_coeff
    @drain_exp   = drain_exp
  end

  def soil_perc(soil_moist, storage_depth)
    deficit = @soil.void_frac - soil_moist
    return 0.0 if deficit <= 0.0

    max_storage = @storage.depth * @storage.void_frac
    return 0.0 if storage_depth >= max_storage

    @soil.conductivity *
      (1.0 + @soil.depth * deficit /
       (soil_moist + 0.001))
  end

  def drain_flow(storage_depth)
    return 0.0 if @drain_coeff <= 0.0
    return 0.0 if storage_depth <= 0.0

    @drain_coeff * storage_depth**@drain_exp
  end

  def get_runoff(rainfall, surf_depth, soil_moist,
                 storage_depth, dt)
    sp = soil_perc(soil_moist, storage_depth)
    surf_inflow  = [rainfall - sp, 0.0].max
    surf_capacity = @surface.depth * @surface.void_frac
    overflow = surf_depth + surf_inflow * dt -
               surf_capacity
    [overflow, 0.0].max
  end
end`,
    autolisp: `;;; lid.lsp \u2014 LID/Green Infrastructure
;;; SWMM5 Engine in AutoLISP
;;; AutoCAD Civil 3D Integration

(defun swmm:lid-init (/ data)
  (setq data (list
    (cons "module" "lid.c")
    (cons "gravity" 32.2)
    (cons "tolerance" 0.001)
  ))
  data
)

(defun swmm:lid-compute (params / result val)
  (setq val (cdr (assoc "value" params)))
  (if (> val 0.0)
    (progn
      (setq result (* val (cdr (assoc "gravity" params))))
      (setq result (sqrt (abs result)))
    )
    (setq result 0.0)
  )
  (list (cons "result" result) (cons "status" "OK"))
)

(defun C:SWMM-LID (/ params res)
  (setq params (swmm:lid-init))
  (setq res (swmm:lid-compute params))
  (princ (strcat "\nLID/Green Infrastructure: "
    (rtos (cdr (assoc "result" res)) 2 4)))
  (princ)
)`,
    commonlisp: `;;; lid.lisp \u2014 LID/Green Infrastructure
;;; SWMM5 Engine in Common Lisp (SBCL)

(defpackage :swmm5/lid
  (:use :cl)
  (:export :make-data :compute :run))

(in-package :swmm5/lid)

(defconstant +gravity+ 32.2d0)

(defstruct lid-data
  (value 0.0d0 :type double-float)
  (area  0.0d0 :type double-float)
  (depth 0.0d0 :type double-float)
  (result 0.0d0 :type double-float))

(defun compute (data)
  (declare (optimize (speed 3) (safety 1)))
  (let* ((v (lid-data-value data))
         (a (lid-data-area data))
         (d (lid-data-depth data)))
    (if (> a 0.0d0)
        (let ((r (* (/ v a) (sqrt (abs (* +gravity+ d))))))
          (setf (lid-data-result data) r)
          r)
        0.0d0)))

(defun run (value area depth)
  (let ((data (make-lid-data
               :value value :area area :depth depth)))
    (compute data)
    (format t "~&LID/Green Infrastructure: ~,4F~%"
            (lid-data-result data))
    data))`,
    clojure: `;;; lid.clj \u2014 LID/Green Infrastructure
;;; SWMM5 Engine in Clojure

(ns swmm5.lid)

(def ^:const GRAVITY 32.2)

(defrecord LidData
  [value area depth result])

(defn create-data [value area depth]
  (->LidData value area depth 0.0))

(defn compute [{:keys [value area depth] :as data}]
  (if (pos? area)
    (let [r (* (/ value area)
               (Math/sqrt (Math/abs (* GRAVITY depth))))]
      (assoc data :result r))
    (assoc data :result 0.0)))

(defn run [value area depth]
  (let [data (-> (create-data value area depth)
                 compute)]
    (println (str "LID/Green Infrastructure: " (:result data)))
    data))`,
