    ruby: `# link.rb — Conduit Hydraulics (Circular Cross Section)
# SWMM5 Engine in Ruby — Pipe Geometry & Manning's Equation
# Computes area, hydraulic radius, normal depth, and
# critical depth for circular conduits

GRAVITY   = 32.174
MAX_ITER  = 50
TOLERANCE = 1.0e-6

class Xsect
  attr_reader :y_full, :a_full, :r_full, :w_max

  def initialize(y_full:, a_full:, r_full:, w_max:)
    @y_full = y_full
    @a_full = a_full
    @r_full = r_full
    @w_max  = w_max
  end

  def get_area(depth)
    r = @y_full / 2.0
    y_norm = depth / @y_full
    return 0.0 if y_norm <= 0.0
    return @a_full if y_norm >= 1.0

    theta = 2.0 * Math.acos(1.0 - 2.0 * y_norm)
    r * r * (theta - Math.sin(theta)) / 2.0
  end

  def get_hyd_radius(depth)
    r = @y_full / 2.0
    y_norm = depth / @y_full
    return 0.0 if y_norm <= 0.0
    return @r_full if y_norm >= 1.0

    theta = 2.0 * Math.acos(1.0 - 2.0 * y_norm)
    area  = r * r * (theta - Math.sin(theta)) / 2.0
    perim = r * theta
    return 0.0 if perim <= 0.0
    area / perim
  end

  def normal_depth(n_manning, slope, q_target)
    return 0.0 if q_target <= 0.0 || slope <= 0.0

    y_lo = 0.0
    y_hi = @y_full

    MAX_ITER.times do
      y_mid   = (y_lo + y_hi) / 2.0
      area    = get_area(y_mid)
      hyd_rad = get_hyd_radius(y_mid)
      q_calc  = (1.0 / n_manning) * area *
                hyd_rad**(2.0 / 3.0) *
                Math.sqrt(slope)

      break if (q_calc - q_target).abs < TOLERANCE
      q_calc < q_target ? y_lo = y_mid : y_hi = y_mid
    end
    (y_lo + y_hi) / 2.0
  end

  def critical_depth(q_target)
    return 0.0 if q_target <= 0.0

    rhs  = (q_target * q_target) / GRAVITY
    y_lo = 0.0
    y_hi = @y_full

    MAX_ITER.times do
      y_mid  = (y_lo + y_hi) / 2.0
      r      = @y_full / 2.0
      y_norm = y_mid / @y_full
      if y_norm <= 0.0; y_lo = y_mid; next; end
      if y_norm >= 1.0; y_hi = y_mid; next; end

      theta = 2.0 * Math.acos(1.0 - 2.0 * y_norm)
      area  = r * r * (theta - Math.sin(theta)) / 2.0
      top_w = 2.0 * r * Math.sin(theta / 2.0)

      if top_w <= 0.0; y_lo = y_mid; next; end
      lhs = area**3 / top_w

      break if (lhs - rhs).abs < TOLERANCE
      lhs < rhs ? y_lo = y_mid : y_hi = y_mid
    end
    (y_lo + y_hi) / 2.0
  end
end`,
    autolisp: `;;; link.lsp \u2014 Conduit Hydraulics
;;; SWMM5 Engine in AutoLISP
;;; AutoCAD Civil 3D Integration

(defun swmm:link-init (/ data)
  (setq data (list
    (cons "module" "link.c")
    (cons "gravity" 32.2)
    (cons "tolerance" 0.001)
  ))
  data
)

(defun swmm:link-compute (params / result val)
  (setq val (cdr (assoc "value" params)))
  (if (> val 0.0)
    (progn
      (setq result (* val (cdr (assoc "gravity" params))))
      (setq result (sqrt (abs result)))
    )
    (setq result 0.0)
  )
  (list (cons "result" result) (cons "status" "OK"))
)

(defun C:SWMM-LINK (/ params res)
  (setq params (swmm:link-init))
  (setq res (swmm:link-compute params))
  (princ (strcat "\nConduit Hydraulics: "
    (rtos (cdr (assoc "result" res)) 2 4)))
  (princ)
)`,
    commonlisp: `;;; link.lisp \u2014 Conduit Hydraulics
;;; SWMM5 Engine in Common Lisp (SBCL)

(defpackage :swmm5/link
  (:use :cl)
  (:export :make-data :compute :run))

(in-package :swmm5/link)

(defconstant +gravity+ 32.2d0)

(defstruct link-data
  (value 0.0d0 :type double-float)
  (area  0.0d0 :type double-float)
  (depth 0.0d0 :type double-float)
  (result 0.0d0 :type double-float))

(defun compute (data)
  (declare (optimize (speed 3) (safety 1)))
  (let* ((v (link-data-value data))
         (a (link-data-area data))
         (d (link-data-depth data)))
    (if (> a 0.0d0)
        (let ((r (* (/ v a) (sqrt (abs (* +gravity+ d))))))
          (setf (link-data-result data) r)
          r)
        0.0d0)))

(defun run (value area depth)
  (let ((data (make-link-data
               :value value :area area :depth depth)))
    (compute data)
    (format t "~&Conduit Hydraulics: ~,4F~%"
            (link-data-result data))
    data))`,
    clojure: `;;; link.clj \u2014 Conduit Hydraulics
;;; SWMM5 Engine in Clojure

(ns swmm5.link)

(def ^:const GRAVITY 32.2)

(defrecord LinkData
  [value area depth result])

(defn create-data [value area depth]
  (->LinkData value area depth 0.0))

(defn compute [{:keys [value area depth] :as data}]
  (if (pos? area)
    (let [r (* (/ value area)
               (Math/sqrt (Math/abs (* GRAVITY depth))))]
      (assoc data :result r))
    (assoc data :result 0.0)))

(defn run [value area depth]
  (let [data (-> (create-data value area depth)
                 compute)]
    (println (str "Conduit Hydraulics: " (:result data)))
    data))`,
