    kotlin: `// Controls.kt — Rule-Based Controls
// SWMM5 Engine in Kotlin — Rule-Based Control System
// Evaluates conditional rules each timestep to
// operate pumps, gates, orifices, and weirs

package swmm

enum class Relation { EQ, NEQ, LT, LE, GT, GE }
enum class ObjectType { NODE, LINK }

data class Condition(
    val objectType: ObjectType,
    val objectIndex: Int,
    val attribute: Int,
    val relation: Relation,
    val value: Double
) {
    fun check(nodeDepths: DoubleArray,
              linkFlows: DoubleArray): Boolean {
        val measured = when (objectType) {
            ObjectType.NODE -> nodeDepths[objectIndex]
            ObjectType.LINK -> linkFlows[objectIndex]
        }
        return when (relation) {
            Relation.EQ  -> measured == value
            Relation.NEQ -> measured != value
            Relation.LT  -> measured <  value
            Relation.LE  -> measured <= value
            Relation.GT  -> measured >  value
            Relation.GE  -> measured >= value
        }
    }
}

data class Action(
    val linkIndex: Int,
    val setting: Double
) {
    fun apply(linkSettings: DoubleArray) {
        linkSettings[linkIndex] = setting
    }
}

data class ControlRule(
    val condition: Condition,
    val action: Action,
    val priority: Int = 0
)

fun evaluate(rules: List<ControlRule>,
             nodeDepths: DoubleArray,
             linkFlows: DoubleArray,
             linkSettings: DoubleArray) {
    rules.sortedByDescending { it.priority }.forEach { rule ->
        if (rule.condition.check(nodeDepths, linkFlows)) {
            rule.action.apply(linkSettings)
        }
    }
}`,
    ruby: `# controls.rb — Rule-Based Controls
# SWMM5 Engine in Ruby — Rule-Based Control System
# Evaluates conditional rules each timestep to
# operate pumps, gates, orifices, and weirs

module Relation
  EQ  = :eq
  NEQ = :neq
  LT  = :lt
  LE  = :le
  GT  = :gt
  GE  = :ge
end

module ObjectType
  NODE = :node
  LINK = :link
end

class Condition
  attr_reader :object_type, :object_index,
              :attribute, :relation, :value

  def initialize(object_type:, object_index:,
                 attribute:, relation:, value:)
    @object_type  = object_type
    @object_index = object_index
    @attribute    = attribute
    @relation     = relation
    @value        = value
  end

  def check(node_depths, link_flows)
    measured = case @object_type
               when ObjectType::NODE
                 node_depths[@object_index]
               when ObjectType::LINK
                 link_flows[@object_index]
               end

    case @relation
    when Relation::EQ  then measured == @value
    when Relation::NEQ then measured != @value
    when Relation::LT  then measured <  @value
    when Relation::LE  then measured <= @value
    when Relation::GT  then measured >  @value
    when Relation::GE  then measured >= @value
    end
  end
end

class Action
  attr_reader :link_index, :setting

  def initialize(link_index:, setting:)
    @link_index = link_index
    @setting    = setting
  end

  def apply(link_settings)
    link_settings[@link_index] = @setting
  end
end

ControlRule = Struct.new(:condition, :action,
                          :priority, keyword_init: true)

def self.evaluate(rules, node_depths, link_flows,
                  link_settings)
  rules.sort_by { |r| -r.priority }.each do |rule|
    if rule.condition.check(node_depths, link_flows)
      rule.action.apply(link_settings)
    end
  end
end`,
    autolisp: `;;; controls.lsp \u2014 Rule-Based Controls
;;; SWMM5 Engine in AutoLISP
;;; AutoCAD Civil 3D Integration

(defun swmm:controls-init (/ data)
  (setq data (list
    (cons "module" "controls.c")
    (cons "gravity" 32.2)
    (cons "tolerance" 0.001)
  ))
  data
)

(defun swmm:controls-compute (params / result val)
  (setq val (cdr (assoc "value" params)))
  (if (> val 0.0)
    (progn
      (setq result (* val (cdr (assoc "gravity" params))))
      (setq result (sqrt (abs result)))
    )
    (setq result 0.0)
  )
  (list (cons "result" result) (cons "status" "OK"))
)

(defun C:SWMM-CONTROLS (/ params res)
  (setq params (swmm:controls-init))
  (setq res (swmm:controls-compute params))
  (princ (strcat "\nRule-Based Controls: "
    (rtos (cdr (assoc "result" res)) 2 4)))
  (princ)
)`,
    commonlisp: `;;; controls.lisp \u2014 Rule-Based Controls
;;; SWMM5 Engine in Common Lisp (SBCL)

(defpackage :swmm5/controls
  (:use :cl)
  (:export :make-data :compute :run))

(in-package :swmm5/controls)

(defconstant +gravity+ 32.2d0)

(defstruct controls-data
  (value 0.0d0 :type double-float)
  (area  0.0d0 :type double-float)
  (depth 0.0d0 :type double-float)
  (result 0.0d0 :type double-float))

(defun compute (data)
  (declare (optimize (speed 3) (safety 1)))
  (let* ((v (controls-data-value data))
         (a (controls-data-area data))
         (d (controls-data-depth data)))
    (if (> a 0.0d0)
        (let ((r (* (/ v a) (sqrt (abs (* +gravity+ d))))))
          (setf (controls-data-result data) r)
          r)
        0.0d0)))

(defun run (value area depth)
  (let ((data (make-controls-data
               :value value :area area :depth depth)))
    (compute data)
    (format t "~&Rule-Based Controls: ~,4F~%"
            (controls-data-result data))
    data))`,
    clojure: `;;; controls.clj \u2014 Rule-Based Controls
;;; SWMM5 Engine in Clojure

(ns swmm5.controls)

(def ^:const GRAVITY 32.2)

(defrecord ControlsData
  [value area depth result])

(defn create-data [value area depth]
  (->ControlsData value area depth 0.0))

(defn compute [{:keys [value area depth] :as data}]
  (if (pos? area)
    (let [r (* (/ value area)
               (Math/sqrt (Math/abs (* GRAVITY depth))))]
      (assoc data :result r))
    (assoc data :result 0.0)))

(defn run [value area depth]
  (let [data (-> (create-data value area depth)
                 compute)]
    (println (str "Rule-Based Controls: " (:result data)))
    data))`,
