    go: `// culvert.go — Culvert Inlet/Outlet Control
// SWMM5 Engine in Go — FHWA Culvert Flow Calculator
// Computes flow under inlet and outlet control
// for circular, box, and arch culverts

package swmm

import "math"

const Gravity = 32.2

type CulvertShape int

const (
    Circular CulvertShape = iota
    Box
    Arch
)

type Culvert struct {
    Shape     CulvertShape
    Diameter  float64
    Width     float64
    Length    float64
    Roughness float64
    KEntry    float64
    KExit     float64
}

func (c *Culvert) Area() float64 {
    if c.Shape == Circular {
        return math.Pi * c.Diameter * c.Diameter / 4.0
    }
    return c.Width * c.Diameter
}

func (c *Culvert) InletFlow(hw float64) float64 {
    if hw <= 0.0 {
        return 0.0
    }
    a := c.Area()
    cd := 0.62
    if hw/c.Diameter >= 1.5 {
        cd = 0.80
    }
    return cd * a * math.Sqrt(2.0*Gravity*hw)
}

func (c *Culvert) OutletFlow(hw, tw float64) float64 {
    if hw <= tw {
        return 0.0
    }
    a := c.Area()
    perim := 2.0 * (c.Width + c.Diameter)
    hRadius := a / perim

    headLoss := c.KEntry + c.KExit +
        c.Roughness*c.Roughness*c.Length/
            (2.21*math.Pow(hRadius, 4.0/3.0))

    if headLoss <= 0.0 {
        headLoss = 0.01
    }
    vel := math.Sqrt(2.0 * Gravity * (hw - tw) / headLoss)
    return a * vel
}

func (c *Culvert) GetFlow(hw, tw float64) float64 {
    qi := c.InletFlow(hw)
    qo := c.OutletFlow(hw, tw)
    if qo < qi && qo > 0.0 {
        return qo
    }
    return qi
}`,
