    cpp: `// culvert.cpp — Culvert Inlet/Outlet Control
// SWMM5 Engine in C++ — FHWA Culvert Flow Calculator
// Computes flow under inlet and outlet control
// for circular, box, and arch culverts

#include <cmath>
#include <algorithm>

namespace swmm {

constexpr double GRAVITY = 32.2;

enum class CulvertShape { Circular, Box, Arch };

struct Culvert {
    CulvertShape shape;
    double diameter;
    double width;
    double length;
    double roughness;
    double kEntry;
    double kExit;

    double area() const {
        if (shape == CulvertShape::Circular)
            return M_PI * diameter * diameter / 4.0;
        return width * diameter;
    }

    double inletFlow(double hw) const {
        if (hw <= 0.0) return 0.0;
        double a = area();
        double cd = (hw / diameter < 1.5) ? 0.62 : 0.80;
        return cd * a * std::sqrt(2.0 * GRAVITY * hw);
    }

    double outletFlow(double hw, double tw) const {
        if (hw <= tw) return 0.0;
        double a = area();
        double perim = 2.0 * (width + diameter);
        double hRadius = a / perim;

        double headLoss = kEntry + kExit
            + roughness * roughness * length
            / (2.21 * std::pow(hRadius, 4.0 / 3.0));

        headLoss = std::max(headLoss, 0.01);
        double vel = std::sqrt(2.0 * GRAVITY * (hw - tw)
                               / headLoss);
        return a * vel;
    }

    double getFlow(double hw, double tw) const {
        double qi = inletFlow(hw);
        double qo = outletFlow(hw, tw);
        return (qo < qi && qo > 0.0) ? qo : qi;
    }
};

} // namespace swmm`,
