    delphi: `{ culvert.pas — Culvert Inlet/Outlet Control }
{ SWMM5 Engine in Delphi — FHWA Culvert Flow Calculator }
{ Computes flow under inlet and outlet control }
{ for circular, box, and arch culverts }

unit Culvert;

interface

const
  GRAVITY = 32.2;

type
  TCulvertShape = (csCircular, csBox, csArch);

  TCulvert = class
  private
    FShape: TCulvertShape;
    FDiameter, FWidth, FLength: Double;
    FRoughness, FKEntry, FKExit: Double;
  public
    constructor Create(AShape: TCulvertShape;
      ADiameter, AWidth, ALength,
      ARoughness, AKEntry, AKExit: Double);
    function Area: Double;
    function InletFlow(HW: Double): Double;
    function OutletFlow(HW, TW: Double): Double;
    function GetFlow(HW, TW: Double): Double;
  end;

implementation

uses Math;

constructor TCulvert.Create(AShape: TCulvertShape;
    ADiameter, AWidth, ALength,
    ARoughness, AKEntry, AKExit: Double);
begin
  FShape := AShape;     FDiameter := ADiameter;
  FWidth := AWidth;     FLength := ALength;
  FRoughness := ARoughness;
  FKEntry := AKEntry;   FKExit := AKExit;
end;

function TCulvert.Area: Double;
begin
  if FShape = csCircular then
    Result := Pi * FDiameter * FDiameter / 4.0
  else
    Result := FWidth * FDiameter;
end;

function TCulvert.InletFlow(HW: Double): Double;
var A, Cd: Double;
begin
  if HW <= 0.0 then Exit(0.0);
  A := Area;
  if HW / FDiameter < 1.5 then Cd := 0.62
  else Cd := 0.80;
  Result := Cd * A * Sqrt(2.0 * GRAVITY * HW);
end;

function TCulvert.OutletFlow(HW, TW: Double): Double;
var A, Perim, HR, HL, Vel: Double;
begin
  if HW <= TW then Exit(0.0);
  A := Area;
  Perim := 2.0 * (FWidth + FDiameter);
  HR := A / Perim;
  HL := FKEntry + FKExit
      + FRoughness * FRoughness * FLength
      / (2.21 * Power(HR, 4.0/3.0));
  if HL <= 0.0 then HL := 0.01;
  Vel := Sqrt(2.0 * GRAVITY * (HW - TW) / HL);
  Result := A * Vel;
end;

function TCulvert.GetFlow(HW, TW: Double): Double;
var Qi, Qo: Double;
begin
  Qi := InletFlow(HW);
  Qo := OutletFlow(HW, TW);
  if (Qo < Qi) and (Qo > 0.0) then Result := Qo
  else Result := Qi;
end;

end.`,
    typescript: `// culvert.ts — Culvert Inlet/Outlet Control
// SWMM5 Engine in TypeScript — FHWA Culvert Flow Calculator
// Computes flow under inlet and outlet control
// for circular, box, and arch culverts

const GRAVITY: number = 32.2;

enum CulvertShape { Circular, Box, Arch }

interface CulvertParams {
    shape: CulvertShape;
    diameter: number;
    width: number;
    length: number;
    roughness: number;
    kEntry: number;
    kExit: number;
}

class Culvert {
    readonly shape: CulvertShape;
    readonly diameter: number;
    readonly width: number;
    readonly length: number;
    readonly roughness: number;
    readonly kEntry: number;
    readonly kExit: number;

    constructor(p: CulvertParams) {
        Object.assign(this, p);
    }

    area(): number {
        if (this.shape === CulvertShape.Circular)
            return Math.PI * this.diameter ** 2 / 4.0;
        return this.width * this.diameter;
    }

    inletFlow(hw: number): number {
        if (hw <= 0.0) return 0.0;
        const a: number = this.area();
        const cd: number = hw / this.diameter < 1.5
                           ? 0.62 : 0.80;
        return cd * a * Math.sqrt(2.0 * GRAVITY * hw);
    }

    outletFlow(hw: number, tw: number): number {
        if (hw <= tw) return 0.0;
        const a: number = this.area();
        const perim: number = 2.0 * (this.width
                                     + this.diameter);
        const hRadius: number = a / perim;

        let headLoss: number = this.kEntry + this.kExit
            + this.roughness ** 2 * this.length
            / (2.21 * Math.pow(hRadius, 4.0 / 3.0));

        headLoss = Math.max(headLoss, 0.01);
        const vel: number = Math.sqrt(2.0 * GRAVITY
                            * (hw - tw) / headLoss);
        return a * vel;
    }

    getFlow(hw: number, tw: number): number {
        const qi: number = this.inletFlow(hw);
        const qo: number = this.outletFlow(hw, tw);
        return (qo < qi && qo > 0.0) ? qo : qi;
    }
}

export { Culvert, CulvertShape, GRAVITY };`,
    cuda: `// culvert.cu — Culvert Inlet/Outlet Control
// SWMM5 Engine in CUDA — FHWA Culvert Flow Calculator
// Computes flow under inlet and outlet control
// for circular, box, and arch culverts

#include <math.h>

#define GRAVITY 32.2f
#define CIRCULAR 0
#define BOX      1
#define ARCH     2

struct Culvert {
    int   shape;
    float diameter;
    float width;
    float length;
    float roughness;
    float kEntry;
    float kExit;
};

__device__ float culvertArea(const Culvert* c)
{
    if (c->shape == CIRCULAR)
        return 3.14159f * c->diameter * c->diameter / 4.0f;
    return c->width * c->diameter;
}

__device__ float inletFlow(const Culvert* c, float hw)
{
    if (hw <= 0.0f) return 0.0f;
    float a = culvertArea(c);
    float cd = (hw / c->diameter < 1.5f) ? 0.62f : 0.80f;
    return cd * a * sqrtf(2.0f * GRAVITY * hw);
}

__device__ float outletFlow(const Culvert* c, float hw,
                             float tw)
{
    if (hw <= tw) return 0.0f;
    float a = culvertArea(c);
    float perim = 2.0f * (c->width + c->diameter);
    float hR = a / perim;

    float hL = c->kEntry + c->kExit
        + c->roughness * c->roughness * c->length
        / (2.21f * powf(hR, 4.0f / 3.0f));

    if (hL <= 0.0f) hL = 0.01f;
    float vel = sqrtf(2.0f * GRAVITY * (hw - tw) / hL);
    return a * vel;
}

__global__ void culvertKernel(Culvert* culverts,
    float* hw, float* tw, float* Qout, int n)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    float qi = inletFlow(&culverts[idx], hw[idx]);
    float qo = outletFlow(&culverts[idx], hw[idx], tw[idx]);
    Qout[idx] = (qo < qi && qo > 0.0f) ? qo : qi;
}`,
    wasm: `;; culvert.wat — Culvert Inlet/Outlet Control
;; SWMM5 Engine in WebAssembly — FHWA Culvert Flow Calculator
;; Computes flow under inlet and outlet control

(module
  (func $culvert_area (param $shape i32) (param $diam f64)
        (param $width f64) (result f64)
    (if (result f64) (i32.eqz (local.get $shape))
      (then
        (f64.mul (f64.mul (f64.const 3.14159)
                          (local.get $diam))
                 (f64.div (local.get $diam)
                          (f64.const 4.0))))
      (else
        (f64.mul (local.get $width) (local.get $diam)))))

  (func $inlet_flow (param $shape i32) (param $diam f64)
        (param $width f64) (param $hw f64) (result f64)
    (local $a f64) (local $cd f64)
    (if (result f64) (f64.le (local.get $hw)
                              (f64.const 0.0))
      (then (f64.const 0.0))
      (else
        (local.set $a (call $culvert_area
          (local.get $shape) (local.get $diam)
          (local.get $width)))
        (local.set $cd
          (if (result f64) (f64.lt
            (f64.div (local.get $hw) (local.get $diam))
            (f64.const 1.5))
            (then (f64.const 0.62))
            (else (f64.const 0.80))))
        (f64.mul (local.get $cd)
          (f64.mul (local.get $a)
            (f64.sqrt (f64.mul (f64.const 64.4)
                               (local.get $hw))))))))

  (export "culvert_area" (func $culvert_area))
  (export "inlet_flow" (func $inlet_flow)))`,
