    julia: `# forcmain.jl — Pressurized Force Main Flow
# SWMM5 Engine in Julia — Force Main Flow Calculator
# Hazen-Williams and Darcy-Weisbach friction models
# for pressurized pipe systems

const GRAVITY = 32.2

@enum FrictionMode HW_MODE DW_MODE

struct ForceMain
    diameter::Float64
    length::Float64
    area::Float64
    roughness::Float64
    mode::FrictionMode
end

hyd_radius(fm::ForceMain) = fm.diameter / 4.0

function hazen_williams(fm::ForceMain, slope::Float64)
    slope ≤ 0.0 && return 0.0
    R = hyd_radius(fm)
    1.318 * fm.roughness * R^0.63 * slope^0.54
end

function darcy_weisbach(fm::ForceMain, head_diff::Float64)
    head_diff ≤ 0.0 && return 0.0
    sqrt(2.0 * GRAVITY * head_diff * fm.diameter
         / (fm.roughness * fm.length))
end

function friction_loss(fm::ForceMain, vel::Float64)
    vel == 0.0 && return 0.0
    R = hyd_radius(fm)

    if fm.mode == HW_MODE
        s = (vel / (1.318 * fm.roughness * R^0.63))^(1.0/0.54)
        return s * fm.length
    else
        return fm.roughness * fm.length * vel^2 /
               (2.0 * GRAVITY * fm.diameter)
    end
end

function get_flow(fm::ForceMain, head_diff::Float64)
    slope = head_diff / fm.length
    vel = fm.mode == HW_MODE ?
          hazen_williams(fm, slope) :
          darcy_weisbach(fm, head_diff)
    return vel * fm.area
end`,
    javascript: `// forcmain.js — Pressurized Force Main Flow
// SWMM5 Engine in JavaScript — Force Main Flow Calculator
// Hazen-Williams and Darcy-Weisbach friction models
// for pressurized pipe systems

const GRAVITY = 32.2;
const HW_MODE = 0, DW_MODE = 1;

class ForceMain {
    constructor(diameter, length, area, roughness, mode) {
        this.diameter = diameter;
        this.length = length;
        this.area = area;
        this.roughness = roughness;
        this.mode = mode;
    }

    hydRadius() {
        return this.diameter / 4.0;
    }

    hazenWilliams(slope) {
        if (slope <= 0.0) return 0.0;
        const R = this.hydRadius();
        return 1.318 * this.roughness
            * Math.pow(R, 0.63) * Math.pow(slope, 0.54);
    }

    darcyWeisbach(headDiff) {
        if (headDiff <= 0.0) return 0.0;
        return Math.sqrt(2.0 * GRAVITY * headDiff
            * this.diameter
            / (this.roughness * this.length));
    }

    frictionLoss(vel) {
        if (vel === 0.0) return 0.0;
        const R = this.hydRadius();

        if (this.mode === HW_MODE) {
            const s = Math.pow(
                vel / (1.318 * this.roughness
                * Math.pow(R, 0.63)), 1.0 / 0.54);
            return s * this.length;
        }
        return this.roughness * this.length * vel * vel
               / (2.0 * GRAVITY * this.diameter);
    }

    getFlow(headDiff) {
        const slope = headDiff / this.length;
        const vel = this.mode === HW_MODE
            ? this.hazenWilliams(slope)
            : this.darcyWeisbach(headDiff);
        return vel * this.area;
    }
}

export { ForceMain, GRAVITY };`,
    go: `// forcmain.go — Pressurized Force Main Flow
// SWMM5 Engine in Go — Force Main Flow Calculator
// Hazen-Williams and Darcy-Weisbach friction models
// for pressurized pipe systems

package swmm

import "math"

const Gravity = 32.2

type FrictionMode int

const (
    HWMode FrictionMode = iota
    DWMode
)

type ForceMain struct {
    Diameter  float64
    Length    float64
    Area      float64
    Roughness float64
    Mode      FrictionMode
}

func (fm *ForceMain) HydRadius() float64 {
    return fm.Diameter / 4.0
}

func (fm *ForceMain) HazenWilliams(slope float64) float64 {
    if slope <= 0.0 {
        return 0.0
    }
    R := fm.HydRadius()
    return 1.318 * fm.Roughness *
        math.Pow(R, 0.63) * math.Pow(slope, 0.54)
}

func (fm *ForceMain) DarcyWeisbach(headDiff float64) float64 {
    if headDiff <= 0.0 {
        return 0.0
    }
    return math.Sqrt(2.0 * Gravity * headDiff *
        fm.Diameter / (fm.Roughness * fm.Length))
}

func (fm *ForceMain) FrictionLoss(vel float64) float64 {
    if vel == 0.0 {
        return 0.0
    }
    R := fm.HydRadius()

    if fm.Mode == HWMode {
        s := math.Pow(vel/(1.318*fm.Roughness*
            math.Pow(R, 0.63)), 1.0/0.54)
        return s * fm.Length
    }
    return fm.Roughness * fm.Length * vel * vel /
        (2.0 * Gravity * fm.Diameter)
}

func (fm *ForceMain) GetFlow(headDiff float64) float64 {
    slope := headDiff / fm.Length
    var vel float64
    if fm.Mode == HWMode {
        vel = fm.HazenWilliams(slope)
    } else {
        vel = fm.DarcyWeisbach(headDiff)
    }
    return vel * fm.Area
}`,
