    ada: `-- forcmain.adb — Pressurized Force Main Flow
-- SWMM5 Engine in Ada — Force Main Flow Calculator
-- Hazen-Williams and Darcy-Weisbach friction models
-- for pressurized pipe systems

with Ada.Numerics.Elementary_Functions;
use  Ada.Numerics.Elementary_Functions;

package body ForceMain_Module is

   Gravity : constant := 32.2;

   type Friction_Mode is (Hazen_Williams, Darcy_Weisbach);

   type Force_Main is record
      Diameter  : Float;
      Length    : Float;
      Area      : Float;
      Roughness : Float;
      Mode      : Friction_Mode;
   end record;

   function Hyd_Radius (FM : Force_Main) return Float is
   begin
      return FM.Diameter / 4.0;
   end Hyd_Radius;

   function HW_Velocity (FM : Force_Main;
                          Slope : Float) return Float is
      R : Float;
   begin
      if Slope <= 0.0 then return 0.0; end if;
      R := Hyd_Radius (FM);
      return 1.318 * FM.Roughness
           * R ** 0.63 * Slope ** 0.54;
   end HW_Velocity;

   function DW_Velocity (FM : Force_Main;
                          Head_Diff : Float) return Float is
   begin
      if Head_Diff <= 0.0 then return 0.0; end if;
      return Sqrt (2.0 * Gravity * Head_Diff
          * FM.Diameter / (FM.Roughness * FM.Length));
   end DW_Velocity;

   function Get_Flow (FM : Force_Main;
                       Head_Diff : Float) return Float is
      Slope, Vel : Float;
   begin
      Slope := Head_Diff / FM.Length;
      case FM.Mode is
         when Hazen_Williams =>
            Vel := HW_Velocity (FM, Slope);
         when Darcy_Weisbach =>
            Vel := DW_Velocity (FM, Head_Diff);
      end case;
      return Vel * FM.Area;
   end Get_Flow;

end ForceMain_Module;`,
