    delphi: `{ roadway.pas — Roadway/Street Overtopping Flow }
{ SWMM5 Engine in Delphi — Broad-Crested Weir Calculator }
{ Computes overtopping flow over roadway crossings }
{ with submergence correction }

unit Roadway;

interface

const
  GRAVITY = 32.2;

type
  TRoadway = class
  private
    FWidth: Double;
    FCrestElev: Double;
    FCd: Double;
  public
    constructor Create(AWidth, ACrestElev, ACd: Double);
    class function Submergence(Ht, Hw: Double): Double;
    function FreeFlow(HeadUp: Double): Double;
    function GetFlow(HeadUp, HeadDown: Double): Double;
    function GetHead(Q: Double): Double;
  end;

implementation

uses Math;

constructor TRoadway.Create(AWidth, ACrestElev,
                             ACd: Double);
begin
  FWidth := AWidth;
  FCrestElev := ACrestElev;
  FCd := ACd;
end;

class function TRoadway.Submergence(Ht, Hw: Double): Double;
var Ratio: Double;
begin
  if Hw <= 0.0 then Exit(0.0);
  Ratio := Ht / Hw;
  if Ratio <= 0.0 then Exit(1.0);
  if Ratio >= 1.0 then Exit(0.0);
  Result := Max(1.0 - Ratio * Ratio, 0.0);
end;

function TRoadway.FreeFlow(HeadUp: Double): Double;
var H: Double;
begin
  H := HeadUp - FCrestElev;
  if H <= 0.0 then Exit(0.0);
  Result := FCd * FWidth * Power(H, 1.5);
end;

function TRoadway.GetFlow(HeadUp, HeadDown: Double): Double;
var H, Ht, Cf, QFree: Double;
begin
  H := HeadUp - FCrestElev;
  if H <= 0.0 then Exit(0.0);
  QFree := FreeFlow(HeadUp);
  Ht := HeadDown - FCrestElev;
  if Ht <= 0.0 then Exit(QFree);
  Cf := Submergence(Ht, H);
  Result := Cf * QFree;
end;

function TRoadway.GetHead(Q: Double): Double;
var H: Double;
begin
  if (Q <= 0.0) or (FCd <= 0.0) or (FWidth <= 0.0) then
    Exit(FCrestElev);
  H := Power(Q / (FCd * FWidth), 2.0/3.0);
  Result := FCrestElev + H;
end;

end.`,
