    cuda: `// roadway.cu — Roadway/Street Overtopping Flow
// SWMM5 Engine in CUDA — Broad-Crested Weir Calculator
// Computes overtopping flow over roadway crossings
// with submergence correction

#include <math.h>

#define GRAVITY 32.2f

struct Roadway {
    float width;
    float crestElev;
    float cd;
};

__device__ float submergence(float ht, float hw)
{
    if (hw <= 0.0f) return 0.0f;
    float ratio = ht / hw;
    if (ratio <= 0.0f) return 1.0f;
    if (ratio >= 1.0f) return 0.0f;
    float cf = 1.0f - ratio * ratio;
    return fmaxf(cf, 0.0f);
}

__device__ float freeFlow(const Roadway* r, float headUp)
{
    float H = headUp - r->crestElev;
    if (H <= 0.0f) return 0.0f;
    return r->cd * r->width * powf(H, 1.5f);
}

__global__ void roadwayKernel(Roadway* roads,
    float* headUp, float* headDown,
    float* Qout, int n)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    Roadway r = roads[idx];
    float H = headUp[idx] - r.crestElev;
    if (H <= 0.0f) {
        Qout[idx] = 0.0f;
        return;
    }

    float qFree = freeFlow(&r, headUp[idx]);
    float ht = headDown[idx] - r.crestElev;
    if (ht <= 0.0f) {
        Qout[idx] = qFree;
        return;
    }

    float cf = submergence(ht, H);
    Qout[idx] = cf * qFree;
}`,
    wasm: `;; roadway.wat — Roadway/Street Overtopping Flow
;; SWMM5 Engine in WebAssembly — Broad-Crested Weir Calculator
;; Computes overtopping flow with submergence correction

(module
  (func $submergence (param $ht f64) (param $hw f64)
        (result f64)
    (local $ratio f64)
    (if (result f64) (f64.le (local.get $hw) (f64.const 0.0))
      (then (f64.const 0.0))
      (else
        (local.set $ratio
          (f64.div (local.get $ht) (local.get $hw)))
        (if (result f64) (f64.le (local.get $ratio)
                                  (f64.const 0.0))
          (then (f64.const 1.0))
          (else
            (if (result f64) (f64.ge (local.get $ratio)
                                      (f64.const 1.0))
              (then (f64.const 0.0))
              (else
                (f64.max
                  (f64.sub (f64.const 1.0)
                    (f64.mul (local.get $ratio)
                             (local.get $ratio)))
                  (f64.const 0.0)))))))))

  (func $free_flow (param $width f64) (param $crest f64)
        (param $cd f64) (param $head_up f64) (result f64)
    (local $h f64)
    (local.set $h
      (f64.sub (local.get $head_up) (local.get $crest)))
    (if (result f64) (f64.le (local.get $h) (f64.const 0.0))
      (then (f64.const 0.0))
      (else
        (f64.mul (local.get $cd)
          (f64.mul (local.get $width)
            (f64.mul (local.get $h)
              (f64.sqrt (local.get $h))))))))

  (export "submergence" (func $submergence))
  (export "free_flow" (func $free_flow)))`,
