    ada: `-- roadway.adb — Roadway/Street Overtopping Flow
-- SWMM5 Engine in Ada — Broad-Crested Weir Calculator
-- Computes overtopping flow over roadway crossings
-- with submergence correction

with Ada.Numerics.Elementary_Functions;
use  Ada.Numerics.Elementary_Functions;

package body Roadway_Module is

   Gravity : constant := 32.2;

   type Roadway is record
      Width      : Float;
      Crest_Elev : Float;
      Cd         : Float;
   end record;

   function Submergence (Ht, Hw : Float) return Float is
      Ratio, Cf : Float;
   begin
      if Hw <= 0.0 then return 0.0; end if;
      Ratio := Ht / Hw;
      if Ratio <= 0.0 then return 1.0; end if;
      if Ratio >= 1.0 then return 0.0; end if;
      Cf := 1.0 - Ratio * Ratio;
      return Float'Max (Cf, 0.0);
   end Submergence;

   function Free_Flow (R : Roadway;
                        Head_Up : Float) return Float is
      H : Float;
   begin
      H := Head_Up - R.Crest_Elev;
      if H <= 0.0 then return 0.0; end if;
      return R.Cd * R.Width * H ** 1.5;
   end Free_Flow;

   function Get_Flow (R : Roadway;
                       Head_Up, Head_Down : Float)
      return Float is
      H, Ht, Cf, Q_Free : Float;
   begin
      H := Head_Up - R.Crest_Elev;
      if H <= 0.0 then return 0.0; end if;
      Q_Free := Free_Flow (R, Head_Up);
      Ht := Head_Down - R.Crest_Elev;
      if Ht <= 0.0 then return Q_Free; end if;
      Cf := Submergence (Ht, H);
      return Cf * Q_Free;
   end Get_Flow;

   function Get_Head (R : Roadway;
                       Q : Float) return Float is
      H : Float;
   begin
      if Q <= 0.0 or else R.Cd <= 0.0
         or else R.Width <= 0.0 then
         return R.Crest_Elev;
      end if;
      H := (Q / (R.Cd * R.Width)) ** (2.0 / 3.0);
      return R.Crest_Elev + H;
   end Get_Head;

end Roadway_Module;`,
