    c: `// runoff.c — Surface Runoff Generation
// EPA SWMM5 Engine — Nonlinear Reservoir Method
// Models overland flow from subcatchments using
// Manning's equation and water balance

#include <math.h>

typedef struct {
    double area;       // subcatchment area (ft²)
    double slope;      // average slope
    double width;      // overland flow width (ft)
    double nImperv;    // Manning's n impervious
    double nPerv;      // Manning's n pervious
    double dStoreImperv; // depression storage imperv (ft)
    double dStorePerv;   // depression storage perv (ft)
    double pctImperv;    // fraction impervious (0-1)
} TSubcatch;

typedef struct {
    double depth;      // current ponded depth (ft)
    double runoff;     // current runoff rate (cfs)
} TRunoffState;

double runoff_getSurfaceOutflow(double depth, double dstore,
    double width, double slope, double n)
{
    double d = depth - dstore;
    if (d <= 0.0) return 0.0;

    return width * sqrt(slope) / n * pow(d, 5.0 / 3.0);
}

double runoff_getDepthChange(double rainfall, double evap,
    double infil, double outflow, double area)
{
    if (area <= 0.0) return 0.0;
    return rainfall - evap - infil - outflow / area;
}

void runoff_getRunoff(TSubcatch *s, TRunoffState *state,
    double rainfall, double evap, double infil,
    double dt)
{
    double qImperv, qPerv, dImperv, dPerv;

    qImperv = runoff_getSurfaceOutflow(state->depth,
        s->dStoreImperv, s->width, s->slope, s->nImperv);
    qPerv = runoff_getSurfaceOutflow(state->depth,
        s->dStorePerv, s->width, s->slope, s->nPerv);

    state->runoff = s->pctImperv * qImperv
                  + (1.0 - s->pctImperv) * qPerv;

    dImperv = runoff_getDepthChange(rainfall, evap,
        0.0, qImperv, s->area);
    dPerv = runoff_getDepthChange(rainfall, evap,
        infil, qPerv, s->area);

    state->depth += (s->pctImperv * dImperv
                  + (1.0 - s->pctImperv) * dPerv) * dt;
    if (state->depth < 0.0) state->depth = 0.0;
}`,
