    zig: `// gage.zig — Rain Gauge Management
// SWMM5 Engine in Zig — Rainfall Data Handling
// Reads rain gauge recordings, converts units,
// provides rainfall at each timestep

const std = @import("std");

const RainType = enum { intensity, cumulative, volume };

const Reading = struct {
    time: f64,
    value: f64,
};

const Gage = struct {
    rain_type: RainType,
    interval: f64,
    units_factor: f64,
    rainfall: f64 = 0.0,
    previous_total: f64 = 0.0,
    readings: [1000]Reading = undefined,
    n_readings: usize = 0,

    pub fn init(rt: RainType, interval: f64,
                factor: f64) Gage {
        return Gage{
            .rain_type = rt,
            .interval = interval,
            .units_factor = factor,
        };
    }

    pub fn addReading(self: *Gage, time: f64,
                      value: f64) void {
        if (self.n_readings < 1000) {
            self.readings[self.n_readings] = Reading{
                .time = time, .value = value,
            };
            self.n_readings += 1;
        }
    }

    pub fn getRainfall(self: *Gage, time: f64) f64 {
        const dt_hr = self.interval / 3600.0;
        var i: usize = self.n_readings;
        while (i > 0) {
            i -= 1;
            const r = self.readings[i];
            if (r.time <= time) {
                const v = r.value * self.units_factor;
                switch (self.rain_type) {
                    .intensity => self.rainfall = v,
                    .cumulative => {
                        self.rainfall =
                            (v - self.previous_total) / dt_hr;
                        self.previous_total = v;
                    },
                    .volume =>
                        self.rainfall = v / dt_hr,
                }
                return self.rainfall;
            }
        }
        self.rainfall = 0.0;
        return 0.0;
    }
};`,
