    delphi: `{ gage.pas — Rain Gauge Management }
{ SWMM5 Engine in Delphi — Rainfall Data Handling }
{ Reads rain gauge recordings, converts units, }
{ provides rainfall at each timestep }

unit GageUnit;

interface

type
  TRainType = (rtIntensity, rtCumulative, rtVolume);

  TReading = record
    Time: Double;
    Value: Double;
  end;

  TGage = class
  private
    FRainType: TRainType;
    FInterval: Double;
    FUnitsFactor: Double;
    FRainfall: Double;
    FPreviousTotal: Double;
    FReadings: array of TReading;
  public
    constructor Create(ARainType: TRainType;
        AInterval, AFactor: Double);
    procedure AddReading(ATime, AValue: Double);
    function GetRainfall(ATime: Double): Double;
    property Rainfall: Double read FRainfall;
  end;

implementation

constructor TGage.Create(ARainType: TRainType;
    AInterval, AFactor: Double);
begin
  FRainType := ARainType;
  FInterval := AInterval;
  FUnitsFactor := AFactor;
  FRainfall := 0.0;
  FPreviousTotal := 0.0;
end;

procedure TGage.AddReading(ATime, AValue: Double);
begin
  SetLength(FReadings, Length(FReadings) + 1);
  FReadings[High(FReadings)].Time := ATime;
  FReadings[High(FReadings)].Value := AValue;
end;

function TGage.GetRainfall(ATime: Double): Double;
var
  I: Integer;
  V, DtHr: Double;
begin
  DtHr := FInterval / 3600.0;

  for I := High(FReadings) downto 0 do begin
    if FReadings[I].Time <= ATime then begin
      V := FReadings[I].Value * FUnitsFactor;
      case FRainType of
        rtIntensity:  FRainfall := V;
        rtCumulative: begin
          FRainfall := (V - FPreviousTotal) / DtHr;
          FPreviousTotal := V;
        end;
        rtVolume: FRainfall := V / DtHr;
      end;
      Exit(FRainfall);
    end;
  end;

  FRainfall := 0.0;
  Result := 0.0;
end;

end.`,
