    cuda: `// gage.cu — Rain Gauge Management
// SWMM5 Engine in CUDA — Rainfall Data Handling
// Reads rain gauge recordings and converts to
// intensity values for parallel subcatchment processing

#include <math.h>

#define INTENSITY  0
#define CUMULATIVE 1
#define VOLUME     2

struct Reading {
    float time;
    float value;
};

struct GageParams {
    int   rainType;
    float interval;
    float unitsFactor;
};

__device__ float getRainfallDevice(
    const GageParams* gp, const Reading* readings,
    int nReadings, float time, float* prevTotal)
{
    float dtHr = gp->interval / 3600.0f;
    int i;

    for (i = nReadings - 1; i >= 0; i--) {
        if (readings[i].time <= time) {
            float v = readings[i].value
                      * gp->unitsFactor;

            switch (gp->rainType) {
                case INTENSITY:  return v;
                case CUMULATIVE: {
                    float rf = (v - *prevTotal) / dtHr;
                    *prevTotal = v;
                    return rf;
                }
                case VOLUME: return v / dtHr;
            }
        }
    }
    return 0.0f;
}

__global__ void rainfallKernel(
    GageParams* gages, Reading* readings,
    int* readingCounts, int* readingOffsets,
    float* prevTotals, float time,
    float* output, int nGages)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= nGages) return;

    int offset = readingOffsets[idx];
    int count = readingCounts[idx];

    output[idx] = getRainfallDevice(&gages[idx],
        &readings[offset], count, time,
        &prevTotals[idx]);
}`,
    wasm: `;; gage.wat — Rain Gauge Management
;; SWMM5 Engine in WebAssembly — Rainfall Data
;; Reads rain gauge recordings and converts formats

(module
  (memory (export "mem") 1)

  ;; Layout: readings at 0 (16 bytes each: f64 time, f64 val)
  ;; Gage params at 16000: rain_type(i32), interval(f64),
  ;;   units_factor(f64), rainfall(f64), prev_total(f64)

  (func $get_rainfall
    (param $time f64) (param $n_readings i32)
    (result f64)
    (local $i i32) (local $addr i32)
    (local $v f64) (local $dt_hr f64)
    (local $rain_type i32) (local $prev f64)

    (local.set $rain_type (i32.load (i32.const 16000)))
    (local.set $dt_hr
      (f64.div (f64.load (i32.const 16008))
               (f64.const 3600.0)))
    (local.set $prev (f64.load (i32.const 16032)))

    (local.set $i (i32.sub (local.get $n_readings)
                           (i32.const 1)))
    (block $break
      (loop $loop
        (br_if $break (i32.lt_s (local.get $i)
                                (i32.const 0)))
        (local.set $addr
          (i32.mul (local.get $i) (i32.const 16)))

        (if (f64.le (f64.load (local.get $addr))
                    (local.get $time))
          (then
            (local.set $v
              (f64.mul (f64.load (i32.add (local.get $addr)
                                          (i32.const 8)))
                       (f64.load (i32.const 16016))))
            (f64.store (i32.const 16024) (local.get $v))
            (return (local.get $v))))

        (local.set $i (i32.sub (local.get $i)
                               (i32.const 1)))
        (br $loop)))

    (f64.store (i32.const 16024) (f64.const 0.0))
    (f64.const 0.0))
)`,
    mojo: `# gage.mojo — Rain Gauge Management
# SWMM5 Engine in Mojo — Rainfall Data Handling
# Reads rain gauge recordings, converts units,
# provides rainfall at each timestep

@value
struct Reading:
    var time: Float64
    var value: Float64

@value
struct Gage:
    var rain_type: Int
    var interval: Float64
    var units_factor: Float64
    var rainfall: Float64
    var previous_total: Float64

fn create_gage(rain_type: Int, interval: Float64,
               units_factor: Float64) -> Gage:
    return Gage(rain_type, interval, units_factor,
                0.0, 0.0)

fn get_rainfall(inout g: Gage,
                readings: DynamicVector[Reading],
                time: Float64) -> Float64:
    let dt_hr = g.interval / 3600.0
    let n = len(readings)

    var i = n - 1
    while i >= 0:
        let r = readings[i]
        if r.time <= time:
            let v = r.value * g.units_factor

            if g.rain_type == 0:
                g.rainfall = v
            elif g.rain_type == 1:
                g.rainfall = (v - g.previous_total) / dt_hr
                g.previous_total = v
            elif g.rain_type == 2:
                g.rainfall = v / dt_hr

            return g.rainfall
        i -= 1

    g.rainfall = 0.0
    return 0.0`,
