    ada: `-- gage.adb — Rain Gauge Management
-- SWMM5 Engine in Ada — Rainfall Data Handling
-- Reads rain gauge recordings, converts units,
-- provides rainfall at each timestep

package body Gage_Pkg is

   type Rain_Type is (Intensity, Cumulative, Volume_T);

   type Reading is record
      Time  : Long_Float;
      Value : Long_Float;
   end record;

   type Reading_Array is array (1 .. 1000) of Reading;

   type Gage is record
      R_Type         : Rain_Type;
      Interval       : Long_Float;
      Units_Factor   : Long_Float;
      Rainfall       : Long_Float := 0.0;
      Previous_Total : Long_Float := 0.0;
      Readings       : Reading_Array;
      N_Readings     : Natural := 0;
   end record;

   procedure Init (G : out Gage; RT : Rain_Type;
                   Intv, Factor : Long_Float) is
   begin
      G.R_Type       := RT;
      G.Interval     := Intv;
      G.Units_Factor := Factor;
      G.Rainfall     := 0.0;
      G.Previous_Total := 0.0;
      G.N_Readings   := 0;
   end Init;

   procedure Add_Reading (G : in out Gage;
                          T, V : Long_Float) is
   begin
      if G.N_Readings < 1000 then
         G.N_Readings := G.N_Readings + 1;
         G.Readings(G.N_Readings) := (Time => T,
                                       Value => V);
      end if;
   end Add_Reading;

   function Get_Rainfall (G : in out Gage;
                          T : Long_Float)
      return Long_Float is
      Dt_Hr : constant Long_Float :=
         G.Interval / 3600.0;
      V : Long_Float;
   begin
      for I in reverse 1 .. G.N_Readings loop
         if G.Readings(I).Time <= T then
            V := G.Readings(I).Value * G.Units_Factor;
            case G.R_Type is
               when Intensity =>
                  G.Rainfall := V;
               when Cumulative =>
                  G.Rainfall :=
                     (V - G.Previous_Total) / Dt_Hr;
                  G.Previous_Total := V;
               when Volume_T =>
                  G.Rainfall := V / Dt_Hr;
            end case;
            return G.Rainfall;
         end if;
      end loop;
      G.Rainfall := 0.0;
      return 0.0;
   end Get_Rainfall;

end Gage_Pkg;`,
