    r: `# surfqual.R — Surface Water Quality / Washoff
# SWMM5 Engine in R — Pollutant washoff from surfaces
# Supports exponential, rating curve, and EMC models

EXPONENTIAL  <- 0L
RATING_CURVE <- 1L
EMC_TYPE     <- 2L

create_surfqual <- function(buildup, washoff_type,
                             c1, c2) {
    list(
        buildup      = buildup,
        pollut_load  = 0.0,
        washoff_type = washoff_type,
        c1 = c1, c2 = c2
    )
}

get_washoff <- function(sq, runoff, area, dt) {
    if (runoff <= 0.0 || sq$buildup <= 0.0)
        return(list(washoff = 0.0, sq = sq))

    washoff <- switch(as.character(sq$washoff_type),
        "0" = sq$c1 * runoff^sq$c2 * sq$buildup,
        "1" = sq$c1 * runoff^sq$c2,
        "2" = sq$c1 * runoff,
        0.0
    )

    if (washoff * dt > sq$buildup)
        washoff <- sq$buildup / dt

    sq$buildup <- sq$buildup - washoff * dt
    if (sq$buildup < 0.0) sq$buildup <- 0.0
    sq$pollut_load <- washoff

    list(washoff = washoff, sq = sq)
}

get_concentration <- function(washoff, flow) {
    if (flow <= 0.0) return(0.0)
    washoff / flow
}`,
    delphi: `{ surfqual.pas — Surface Water Quality / Washoff }
{ SWMM5 Engine in Delphi — Pollutant washoff }
{ Supports exponential, rating curve, and EMC models }

unit SurfQual;

interface

uses Math;

type
  TWashoffType = (wtExponential, wtRatingCurve, wtEmc);

  TSurfQual = class
  private
    FBuildup: Double;
    FPollutLoad: Double;
    FWashoffType: TWashoffType;
    FC1, FC2: Double;
    FSweepRemoval: Double;
  public
    constructor Create(ABuildup: Double;
                       AWashoffType: TWashoffType;
                       AC1, AC2: Double);
    function GetWashoff(Runoff, Area,
                        Dt: Double): Double;
    class function GetConcentration(Washoff,
                        Flow: Double): Double;
    property Buildup: Double read FBuildup;
    property PollutLoad: Double read FPollutLoad;
  end;

implementation

constructor TSurfQual.Create(ABuildup: Double;
    AWashoffType: TWashoffType; AC1, AC2: Double);
begin
  FBuildup     := ABuildup;
  FPollutLoad  := 0.0;
  FWashoffType := AWashoffType;
  FC1 := AC1;  FC2 := AC2;
  FSweepRemoval := 0.0;
end;

function TSurfQual.GetWashoff(Runoff, Area,
                               Dt: Double): Double;
begin
  Result := 0.0;
  if (Runoff <= 0.0) or (FBuildup <= 0.0) then Exit;

  case FWashoffType of
    wtExponential:
      Result := FC1 * Power(Runoff, FC2) * FBuildup;
    wtRatingCurve:
      Result := FC1 * Power(Runoff, FC2);
    wtEmc:
      Result := FC1 * Runoff;
  end;

  if Result * Dt > FBuildup then
    Result := FBuildup / Dt;

  FBuildup := FBuildup - Result * Dt;
  if FBuildup < 0.0 then FBuildup := 0.0;
  FPollutLoad := Result;
end;

class function TSurfQual.GetConcentration(
    Washoff, Flow: Double): Double;
begin
  if Flow <= 0.0 then Exit(0.0);
  Result := Washoff / Flow;
end;

end.`,
