    cuda: `// surfqual.cu — Surface Water Quality / Washoff
// SWMM5 Engine in CUDA — Pollutant washoff
// Supports exponential, rating curve, and EMC models

#include <math.h>

#define EXPONENTIAL  0
#define RATING_CURVE 1
#define EMC_TYPE     2

struct SurfQual {
    float buildup;
    float pollutLoad;
    int   washoffType;
    float c1, c2;
};

__device__ float getWashoff(SurfQual* sq, float runoff,
                             float area, float dt)
{
    if (runoff <= 0.0f || sq->buildup <= 0.0f)
        return 0.0f;

    float washoff = 0.0f;
    switch (sq->washoffType) {
        case EXPONENTIAL:
            washoff = sq->c1 * powf(runoff, sq->c2)
                      * sq->buildup;
            break;
        case RATING_CURVE:
            washoff = sq->c1 * powf(runoff, sq->c2);
            break;
        case EMC_TYPE:
            washoff = sq->c1 * runoff;
            break;
    }

    if (washoff * dt > sq->buildup)
        washoff = sq->buildup / dt;

    sq->buildup -= washoff * dt;
    if (sq->buildup < 0.0f) sq->buildup = 0.0f;
    sq->pollutLoad = washoff;
    return washoff;
}

__global__ void washoffKernel(SurfQual* quals,
    float* runoffs, float* areas,
    float dt, float* results, int n)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    results[idx] = getWashoff(&quals[idx],
                               runoffs[idx],
                               areas[idx], dt);
}`,
