    ada: `-- surfqual.adb — Surface Water Quality / Washoff
-- SWMM5 Engine in Ada — Pollutant washoff from surfaces
-- Supports exponential, rating curve, and EMC models

with Ada.Numerics.Elementary_Functions;
use  Ada.Numerics.Elementary_Functions;

package body SurfQual_Pkg is

   type Washoff_Type is
     (Exponential, Rating_Curve, Emc);

   type Surf_Qual is record
      Buildup      : Float := 0.0;
      Pollut_Load  : Float := 0.0;
      W_Type       : Washoff_Type;
      C1           : Float;
      C2           : Float;
   end record;

   function Get_Washoff
     (SQ : in out Surf_Qual; Runoff, Area,
      Dt : Float) return Float
   is
      Washoff : Float := 0.0;
   begin
      if Runoff <= 0.0 or else SQ.Buildup <= 0.0 then
         return 0.0;
      end if;

      case SQ.W_Type is
         when Exponential =>
            Washoff := SQ.C1 * Runoff ** SQ.C2
                       * SQ.Buildup;
         when Rating_Curve =>
            Washoff := SQ.C1 * Runoff ** SQ.C2;
         when Emc =>
            Washoff := SQ.C1 * Runoff;
      end case;

      if Washoff * Dt > SQ.Buildup then
         Washoff := SQ.Buildup / Dt;
      end if;

      SQ.Buildup := SQ.Buildup - Washoff * Dt;
      if SQ.Buildup < 0.0 then
         SQ.Buildup := 0.0;
      end if;

      SQ.Pollut_Load := Washoff;
      return Washoff;
   end Get_Washoff;

   function Get_Concentration
     (Washoff, Flow : Float) return Float is
   begin
      if Flow <= 0.0 then return 0.0; end if;
      return Washoff / Flow;
   end Get_Concentration;

end SurfQual_Pkg;`,
