    go: `// inflow.go — External Inflow Handling
// SWMM5 Engine in Go — Direct, dry-weather, RDII
// Combines multiple inflow sources at network nodes

package swmm

import "math"

const MaxPeriods = 24

type Inflow struct {
    Baseline    float64
    ScaleFactor float64
    Pattern     []float64
    TsValue     float64
}

func (inf *Inflow) GetPattern(time float64) float64 {
    n := len(inf.Pattern)
    if n == 0 {
        return 1.0
    }

    period := int(math.Mod(time, float64(n)))
    if period < 0 {
        period += n
    }
    return inf.Pattern[period]
}

func (inf *Inflow) GetDirectInflow(
    time float64) float64 {
    return inf.Baseline +
           inf.ScaleFactor * inf.TsValue
}

func (inf *Inflow) GetDryWeatherFlow(
    time float64) float64 {
    pat := inf.GetPattern(time)
    return inf.Baseline * inf.ScaleFactor * pat
}

func GetTotalInflow(direct, dwf *Inflow,
    rdii, time float64) float64 {

    total := rdii

    if direct != nil {
        total += direct.GetDirectInflow(time)
    }
    if dwf != nil {
        total += dwf.GetDryWeatherFlow(time)
    }

    return math.Max(0.0, total)
}`,
    zig: `// inflow.zig — External Inflow Handling
// SWMM5 Engine in Zig — Direct, dry-weather, RDII
// Combines multiple inflow sources at network nodes

const std = @import("std");
const math = std.math;

const MAX_PERIODS: usize = 24;

const Inflow = struct {
    baseline: f64,
    scale_factor: f64,
    pattern: [MAX_PERIODS]f64,
    n_periods: usize,
    ts_value: f64,

    pub fn getPattern(self: Inflow, time: f64) f64 {
        if (self.n_periods == 0) return 1.0;

        const n = @as(i32, @intCast(self.n_periods));
        var period = @mod(@as(i32, @intFromFloat(time)), n);
        if (period < 0) period += n;
        return self.pattern[@as(usize, @intCast(period))];
    }

    pub fn getDirectInflow(self: Inflow, time: f64) f64 {
        _ = time;
        return self.baseline +
               self.scale_factor * self.ts_value;
    }

    pub fn getDryWeatherFlow(self: Inflow,
                              time: f64) f64 {
        const pat = self.getPattern(time);
        return self.baseline * self.scale_factor * pat;
    }
};

pub fn getTotalInflow(
    direct: ?*const Inflow,
    dwf: ?*const Inflow,
    rdii: f64,
    time: f64,
) f64 {
    var total = rdii;

    if (direct) |d| {
        total += d.getDirectInflow(time);
    }
    if (dwf) |w| {
        total += w.getDryWeatherFlow(time);
    }

    return @max(total, 0.0);
}`,
    cpp: `// inflow.cpp — External Inflow Handling
// SWMM5 Engine in C++ — Direct, dry-weather, RDII
// Combines multiple inflow sources at network nodes

#include <cmath>
#include <algorithm>
#include <vector>
#include <optional>

namespace swmm {

constexpr int MAX_PERIODS = 24;

struct Inflow {
    double baseline;
    double scaleFactor;
    std::vector<double> pattern;
    double tsValue = 0.0;

    double getPattern(double time) const {
        int n = static_cast<int>(pattern.size());
        if (n == 0) return 1.0;

        int period = static_cast<int>(
            std::fmod(time, static_cast<double>(n)));
        if (period < 0) period += n;
        return pattern[period];
    }

    double getDirectInflow(double time) const {
        return baseline + scaleFactor * tsValue;
    }

    double getDryWeatherFlow(double time) const {
        double pat = getPattern(time);
        return baseline * scaleFactor * pat;
    }
};

double getTotalInflow(
    const Inflow* direct,
    const Inflow* dwf,
    double rdii,
    double time)
{
    double total = rdii;

    if (direct)
        total += direct->getDirectInflow(time);
    if (dwf)
        total += dwf->getDryWeatherFlow(time);

    return std::max(0.0, total);
}

} // namespace swmm`,
