    r: `# inflow.R — External Inflow Handling
# SWMM5 Engine in R — Direct, dry-weather, RDII
# Combines multiple inflow sources at network nodes

MAX_PERIODS <- 24L

create_inflow <- function(baseline, scale_factor,
                           pattern = numeric(0),
                           ts_value = 0.0) {
    list(
        baseline     = baseline,
        scale_factor = scale_factor,
        pattern      = pattern,
        ts_value     = ts_value
    )
}

get_pattern <- function(inf, time) {
    n <- length(inf$pattern)
    if (n == 0L) return(1.0)
    period <- (floor(time) %% n) + 1L
    inf$pattern[period]
}

get_direct_inflow <- function(inf, time) {
    inf$baseline + inf$scale_factor * inf$ts_value
}

get_dry_weather_flow <- function(inf, time) {
    pat <- get_pattern(inf, time)
    inf$baseline * inf$scale_factor * pat
}

get_total_inflow <- function(direct = NULL,
                              dwf = NULL,
                              rdii = 0.0,
                              time = 0.0) {
    total <- rdii

    if (!is.null(direct))
        total <- total + get_direct_inflow(direct, time)
    if (!is.null(dwf))
        total <- total + get_dry_weather_flow(dwf, time)

    max(0.0, total)
}`,
    delphi: `{ inflow.pas — External Inflow Handling }
{ SWMM5 Engine in Delphi — Direct, dry-weather, RDII }
{ Combines multiple inflow sources at network nodes }

unit InflowUnit;

interface

uses Math, SysUtils;

const
  MAX_PERIODS = 24;

type
  TInflow = class
  private
    FBaseline: Double;
    FScaleFactor: Double;
    FPattern: array[0..MAX_PERIODS-1] of Double;
    FNPeriods: Integer;
    FTsValue: Double;
  public
    constructor Create(ABaseline, AScaleFactor: Double;
                       ANPeriods: Integer);
    procedure SetPattern(Index: Integer;
                         Value: Double);
    function GetPattern(Time: Double): Double;
    function GetDirectInflow(Time: Double): Double;
    function GetDryWeatherFlow(Time: Double): Double;
    property TsValue: Double read FTsValue
                              write FTsValue;
  end;

function GetTotalInflow(Direct, Dwf: TInflow;
                         Rdii, Time: Double): Double;

implementation

constructor TInflow.Create(ABaseline,
    AScaleFactor: Double; ANPeriods: Integer);
begin
  FBaseline    := ABaseline;
  FScaleFactor := AScaleFactor;
  FNPeriods    := ANPeriods;
  FTsValue     := 0.0;
end;

procedure TInflow.SetPattern(Index: Integer;
                              Value: Double);
begin
  if (Index >= 0) and (Index < MAX_PERIODS) then
    FPattern[Index] := Value;
end;

function TInflow.GetPattern(Time: Double): Double;
var
  Period: Integer;
begin
  if FNPeriods <= 0 then Exit(1.0);
  Period := Trunc(Time) mod FNPeriods;
  if Period < 0 then Period := Period + FNPeriods;
  Result := FPattern[Period];
end;

function TInflow.GetDirectInflow(Time: Double): Double;
begin
  Result := FBaseline + FScaleFactor * FTsValue;
end;

function TInflow.GetDryWeatherFlow(
    Time: Double): Double;
begin
  Result := FBaseline * FScaleFactor
            * GetPattern(Time);
end;

function GetTotalInflow(Direct, Dwf: TInflow;
                         Rdii, Time: Double): Double;
begin
  Result := Rdii;
  if Direct <> nil then
    Result := Result + Direct.GetDirectInflow(Time);
  if Dwf <> nil then
    Result := Result + Dwf.GetDryWeatherFlow(Time);
  if Result < 0.0 then Result := 0.0;
end;

end.`,
