    cuda: `// inflow.cu — External Inflow Handling
// SWMM5 Engine in CUDA — Direct, dry-weather, RDII
// Combines multiple inflow sources at network nodes

#include <math.h>

#define MAX_PERIODS 24

struct Inflow {
    float baseline;
    float scaleFactor;
    float pattern[MAX_PERIODS];
    int   nPeriods;
    float tsValue;
};

__device__ float getPattern(const Inflow* inf,
                             float time)
{
    if (inf->nPeriods <= 0) return 1.0f;

    int period = (int)fmodf(time,
                  (float)inf->nPeriods);
    if (period < 0) period += inf->nPeriods;
    return inf->pattern[period];
}

__device__ float getDirectInflow(const Inflow* inf,
                                  float time)
{
    return inf->baseline
           + inf->scaleFactor * inf->tsValue;
}

__device__ float getDryWeatherFlow(const Inflow* inf,
                                    float time)
{
    float pat = getPattern(inf, time);
    return inf->baseline * inf->scaleFactor * pat;
}

__global__ void totalInflowKernel(
    Inflow* directs, Inflow* dwfs,
    float* rdiis, float time,
    float* results, int n,
    int* hasDirect, int* hasDwf)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    float total = rdiis[idx];

    if (hasDirect[idx])
        total += getDirectInflow(&directs[idx], time);
    if (hasDwf[idx])
        total += getDryWeatherFlow(&dwfs[idx], time);

    results[idx] = fmaxf(0.0f, total);
}`,
