    go: `// odesolve.go — ODE Solver (Runge-Kutta-Fehlberg)
// SWMM5 Engine in Go — Adaptive RK5 integrator

package swmm

import "math"

type OdeSolver struct {
    N    int
    K1   []float64
    K2   []float64
    K3   []float64
    K4   []float64
    K5   []float64
    K6   []float64
    YTmp []float64
}

func NewOdeSolver(n int) *OdeSolver {
    return &OdeSolver{
        N: n, K1: make([]float64, n),
        K2: make([]float64, n), K3: make([]float64, n),
        K4: make([]float64, n), K5: make([]float64, n),
        K6: make([]float64, n), YTmp: make([]float64, n),
    }
}

func (s *OdeSolver) Rk5Step(y []float64, h, t float64,
    deriv func(float64, []float64, []float64)) {
    n := s.N
    deriv(t, y, s.K1)
    for i := 0; i < n; i++ {
        s.YTmp[i] = y[i] + h*0.25*s.K1[i]
    }
    deriv(t+0.25*h, s.YTmp, s.K2)
    for i := 0; i < n; i++ {
        s.YTmp[i] = y[i] + h*(3.0/32*s.K1[i]+9.0/32*s.K2[i])
    }
    deriv(t+3.0/8*h, s.YTmp, s.K3)
    for i := 0; i < n; i++ {
        s.YTmp[i] = y[i] + h*(1932.0/2197*s.K1[i]-
            7200.0/2197*s.K2[i]+7296.0/2197*s.K3[i])
    }
    deriv(t+12.0/13*h, s.YTmp, s.K4)
    for i := 0; i < n; i++ {
        s.YTmp[i] = y[i] + h*(439.0/216*s.K1[i]-
            8*s.K2[i]+3680.0/513*s.K3[i]-
            845.0/4104*s.K4[i])
    }
    deriv(t+h, s.YTmp, s.K5)
    for i := 0; i < n; i++ {
        s.YTmp[i] = y[i] + h*(-8.0/27*s.K1[i]+
            2*s.K2[i]-3544.0/2565*s.K3[i]+
            1859.0/4104*s.K4[i]-11.0/40*s.K5[i])
    }
    deriv(t+0.5*h, s.YTmp, s.K6)
}

func (s *OdeSolver) GetError(h float64) float64 {
    maxErr := 0.0
    for i := 0; i < s.N; i++ {
        err := math.Abs(h * (s.K1[i]/360 -
            128.0/4275*s.K3[i] - 2197.0/75240*s.K4[i] +
            s.K5[i]/50 + 2.0/55*s.K6[i]))
        if err > maxErr {
            maxErr = err
        }
    }
    return maxErr
}`,
