    cpp: `// odesolve.cpp — ODE Solver (Runge-Kutta-Fehlberg)
// SWMM5 Engine in C++ — Adaptive RK5 integrator

#include <cmath>
#include <vector>
#include <functional>
#include <algorithm>

namespace swmm {

class OdeSolver {
    int n;
    std::vector<double> k1, k2, k3, k4, k5, k6, yTmp;

public:
    using DerivFn = std::function<void(double, const double*,
                                        double*)>;

    OdeSolver(int nEqns) : n(nEqns),
        k1(n), k2(n), k3(n), k4(n), k5(n), k6(n), yTmp(n) {}

    void rk5Step(const double* y, double h, double t,
                 DerivFn deriv) {
        deriv(t, y, k1.data());
        for (int i = 0; i < n; i++)
            yTmp[i] = y[i] + h * 0.25 * k1[i];

        deriv(t + 0.25*h, yTmp.data(), k2.data());
        for (int i = 0; i < n; i++)
            yTmp[i] = y[i] + h*(3.0/32*k1[i]
                      + 9.0/32*k2[i]);

        deriv(t + 3.0/8*h, yTmp.data(), k3.data());
        for (int i = 0; i < n; i++)
            yTmp[i] = y[i] + h*(1932.0/2197*k1[i]
                - 7200.0/2197*k2[i] + 7296.0/2197*k3[i]);

        deriv(t + 12.0/13*h, yTmp.data(), k4.data());
        for (int i = 0; i < n; i++)
            yTmp[i] = y[i] + h*(439.0/216*k1[i]
                - 8*k2[i] + 3680.0/513*k3[i]
                - 845.0/4104*k4[i]);

        deriv(t + h, yTmp.data(), k5.data());
        for (int i = 0; i < n; i++)
            yTmp[i] = y[i] + h*(-8.0/27*k1[i] + 2*k2[i]
                - 3544.0/2565*k3[i] + 1859.0/4104*k4[i]
                - 11.0/40*k5[i]);

        deriv(t + 0.5*h, yTmp.data(), k6.data());
    }

    double getError(double h) const {
        double maxErr = 0.0;
        for (int i = 0; i < n; i++) {
            double err = std::abs(h * (k1[i]/360.0
                - 128.0/4275*k3[i] - 2197.0/75240*k4[i]
                + k5[i]/50.0 + 2.0/55*k6[i]));
            maxErr = std::max(maxErr, err);
        }
        return maxErr;
    }
};

} // namespace swmm`,
