    ada: `-- odesolve.adb — ODE Solver (Runge-Kutta-Fehlberg)
-- SWMM5 Engine in Ada — Adaptive RK5 integrator

with Ada.Numerics.Elementary_Functions;
use  Ada.Numerics.Elementary_Functions;

package body Ode_Solve is

   type Float_Array is array (Positive range <>) of Float;
   type Deriv_Func is access procedure
      (T : Float; Y : Float_Array; DYDT : out Float_Array);

   type Ode_Solver (N : Positive) is record
      K1, K2, K3, K4, K5, K6 : Float_Array (1 .. N);
      Y_Tmp : Float_Array (1 .. N);
   end record;

   procedure Rk5_Step (S : in out Ode_Solver;
      Y : Float_Array; H, T : Float;
      Deriv : Deriv_Func) is
   begin
      Deriv (T, Y, S.K1);
      for I in 1 .. S.N loop
         S.Y_Tmp (I) := Y (I) + H * 0.25 * S.K1 (I);
      end loop;
      Deriv (T + 0.25*H, S.Y_Tmp, S.K2);
      for I in 1 .. S.N loop
         S.Y_Tmp (I) := Y (I) + H * (3.0/32.0*S.K1 (I)
                         + 9.0/32.0*S.K2 (I));
      end loop;
      Deriv (T + 3.0/8.0*H, S.Y_Tmp, S.K3);
      for I in 1 .. S.N loop
         S.Y_Tmp (I) := Y (I) + H*(1932.0/2197.0*S.K1(I)
            - 7200.0/2197.0*S.K2(I)
            + 7296.0/2197.0*S.K3(I));
      end loop;
      Deriv (T + 12.0/13.0*H, S.Y_Tmp, S.K4);
      for I in 1 .. S.N loop
         S.Y_Tmp (I) := Y (I) + H*(439.0/216.0*S.K1(I)
            - 8.0*S.K2(I) + 3680.0/513.0*S.K3(I)
            - 845.0/4104.0*S.K4(I));
      end loop;
      Deriv (T + H, S.Y_Tmp, S.K5);
      for I in 1 .. S.N loop
         S.Y_Tmp (I) := Y (I) + H*(-8.0/27.0*S.K1(I)
            + 2.0*S.K2(I) - 3544.0/2565.0*S.K3(I)
            + 1859.0/4104.0*S.K4(I)
            - 11.0/40.0*S.K5(I));
      end loop;
      Deriv (T + 0.5*H, S.Y_Tmp, S.K6);
   end Rk5_Step;

   function Get_Error (S : Ode_Solver; H : Float)
      return Float is
      Max_Err, Err : Float := 0.0;
   begin
      for I in 1 .. S.N loop
         Err := abs (H * (S.K1(I)/360.0
            - 128.0/4275.0*S.K3(I)
            - 2197.0/75240.0*S.K4(I)
            + S.K5(I)/50.0 + 2.0/55.0*S.K6(I)));
         if Err > Max_Err then Max_Err := Err; end if;
      end loop;
      return Max_Err;
   end Get_Error;

end Ode_Solve;`,
    chapel: `// odesolve.chpl — ODE Solver (Runge-Kutta-Fehlberg)
// SWMM5 Engine in Chapel — Adaptive RK5 integrator

record OdeSolver {
    var n: int;
    var k1, k2, k3, k4, k5, k6: [0..#n] real;
    var yTmp: [0..#n] real;

    proc init(n: int) {
        this.n = n;
    }

    proc ref rk5Step(y: [] real, h: real, t: real,
        deriv: func(real, [] real, [] real)) {
        deriv(t, y, k1);
        forall i in 0..#n do
            yTmp[i] = y[i] + h * 0.25 * k1[i];

        deriv(t + 0.25*h, yTmp, k2);
        forall i in 0..#n do
            yTmp[i] = y[i] + h*(3.0/32*k1[i]
                      + 9.0/32*k2[i]);

        deriv(t + 3.0/8*h, yTmp, k3);
        forall i in 0..#n do
            yTmp[i] = y[i] + h*(1932.0/2197*k1[i]
                - 7200.0/2197*k2[i]
                + 7296.0/2197*k3[i]);

        deriv(t + 12.0/13*h, yTmp, k4);
        forall i in 0..#n do
            yTmp[i] = y[i] + h*(439.0/216*k1[i]
                - 8*k2[i] + 3680.0/513*k3[i]
                - 845.0/4104*k4[i]);

        deriv(t + h, yTmp, k5);
        forall i in 0..#n do
            yTmp[i] = y[i] + h*(-8.0/27*k1[i]
                + 2*k2[i] - 3544.0/2565*k3[i]
                + 1859.0/4104*k4[i] - 11.0/40*k5[i]);

        deriv(t + 0.5*h, yTmp, k6);
    }

    proc getError(h: real): real {
        var maxErr = 0.0;
        for i in 0..#n {
            var err = abs(h * (k1[i]/360.0
                - 128.0/4275*k3[i]
                - 2197.0/75240*k4[i]
                + k5[i]/50.0 + 2.0/55*k6[i]));
            if err > maxErr then maxErr = err;
        }
        return maxErr;
    }
}`,
    swift: `// odesolve.swift — ODE Solver (Runge-Kutta-Fehlberg)
// SWMM5 Engine in Swift — Adaptive RK5 integrator

import Foundation

class OdeSolver {
    let n: Int
    var k1, k2, k3, k4, k5, k6: [Double]
    var yTmp: [Double]

    typealias DerivFn = (Double, [Double]) -> [Double]

    init(n: Int) {
        self.n = n
        k1 = [Double](repeating: 0, count: n)
        k2 = k1; k3 = k1; k4 = k1; k5 = k1; k6 = k1
        yTmp = k1
    }

    func rk5Step(_ y: [Double], h: Double, t: Double,
                 deriv: DerivFn) {
        k1 = deriv(t, y)
        for i in 0..<n {
            yTmp[i] = y[i] + h * 0.25 * k1[i]
        }
        k2 = deriv(t + 0.25*h, yTmp)
        for i in 0..<n {
            yTmp[i] = y[i] + h*(3.0/32*k1[i]
                      + 9.0/32*k2[i])
        }
        k3 = deriv(t + 3.0/8*h, yTmp)
        for i in 0..<n {
            yTmp[i] = y[i] + h*(1932.0/2197*k1[i]
                - 7200.0/2197*k2[i]
                + 7296.0/2197*k3[i])
        }
        k4 = deriv(t + 12.0/13*h, yTmp)
        for i in 0..<n {
            yTmp[i] = y[i] + h*(439.0/216*k1[i]
                - 8*k2[i] + 3680.0/513*k3[i]
                - 845.0/4104*k4[i])
        }
        k5 = deriv(t + h, yTmp)
        for i in 0..<n {
            yTmp[i] = y[i] + h*(-8.0/27*k1[i]
                + 2*k2[i] - 3544.0/2565*k3[i]
                + 1859.0/4104*k4[i] - 11.0/40*k5[i])
        }
        k6 = deriv(t + 0.5*h, yTmp)
    }

    func getError(_ h: Double) -> Double {
        var maxErr = 0.0
        for i in 0..<n {
            let err = abs(h * (k1[i]/360.0
                - 128.0/4275*k3[i]
                - 2197.0/75240*k4[i]
                + k5[i]/50.0 + 2.0/55*k6[i]))
            maxErr = max(maxErr, err)
        }
        return maxErr
    }
}`,
