    r: `# findroot.R — Root Finding (Bisection & Ridder)
# SWMM5 Engine in R — Solves f(x) = 0

ROOT_TOL <- 1.0e-6
MAX_IT   <- 50

bisect <- function(f, a, b) {
    fa <- f(a)
    if (fa * f(b) > 0) return((a + b) / 2)

    for (i in seq_len(MAX_IT)) {
        mid  <- (a + b) / 2
        fmid <- f(mid)

        if (abs(fmid) < ROOT_TOL ||
            (b - a) / 2 < ROOT_TOL) return(mid)

        if (fa * fmid < 0) {
            b <- mid
        } else {
            a <- mid; fa <- fmid
        }
    }
    (a + b) / 2
}

ridder <- function(f, a, b) {
    fa <- f(a); fb <- f(b)
    if (fa * fb > 0) return((a + b) / 2)

    for (i in seq_len(MAX_IT)) {
        mid  <- (a + b) / 2
        fmid <- f(mid)
        s <- sqrt(fmid^2 - fa * fb)
        if (s == 0) return(mid)

        sgn <- ifelse(fa - fb >= 0, abs(fmid), -abs(fmid))
        xnew <- mid + (mid - a) * sgn / s
        fnew <- f(xnew)

        if (abs(fnew) < ROOT_TOL) return(xnew)

        if (fmid * fnew < 0) {
            a <- mid; fa <- fmid
            b <- xnew; fb <- fnew
        } else if (fa * fnew < 0) {
            b <- xnew; fb <- fnew
        } else {
            a <- xnew; fa <- fnew
        }
    }
    (a + b) / 2
}`,
