    java: `// FindRoot.java — Root Finding (Bisection & Ridder)
// SWMM5 Engine in Java — Solves f(x) = 0

package swmm;

import java.util.function.DoubleUnaryOperator;

public class FindRoot {
    private static final double TOL = 1.0e-6;
    private static final int MAX_IT = 50;

    public static double bisect(DoubleUnaryOperator f,
        double a, double b) {
        double fa = f.applyAsDouble(a);
        if (fa * f.applyAsDouble(b) > 0)
            return (a + b) / 2;

        for (int i = 0; i < MAX_IT; i++) {
            double mid = (a + b) / 2;
            double fmid = f.applyAsDouble(mid);
            if (Math.abs(fmid) < TOL || (b-a)/2 < TOL)
                return mid;
            if (fa * fmid < 0) b = mid;
            else { a = mid; fa = fmid; }
        }
        return (a + b) / 2;
    }

    public static double ridder(DoubleUnaryOperator f,
        double a, double b) {
        double fa = f.applyAsDouble(a);
        double fb = f.applyAsDouble(b);
        if (fa * fb > 0) return (a + b) / 2;

        for (int i = 0; i < MAX_IT; i++) {
            double mid = (a + b) / 2;
            double fmid = f.applyAsDouble(mid);
            double s = Math.sqrt(fmid*fmid - fa*fb);
            if (s == 0) return mid;

            double sgn = (fa - fb >= 0)
                ? Math.abs(fmid) : -Math.abs(fmid);
            double xnew = mid + (mid-a) * sgn / s;
            double fnew = f.applyAsDouble(xnew);

            if (Math.abs(fnew) < TOL) return xnew;

            if (fmid*fnew < 0) {
                a=mid; fa=fmid; b=xnew; fb=fnew;
            } else if (fa*fnew < 0) {
                b=xnew; fb=fnew;
            } else {
                a=xnew; fa=fnew;
            }
        }
        return (a + b) / 2;
    }
}`,
