    ada: `-- findroot.adb — Root Finding (Bisection & Ridder)
-- SWMM5 Engine in Ada — Solves f(x) = 0

with Ada.Numerics.Elementary_Functions;
use  Ada.Numerics.Elementary_Functions;

package body Find_Root is

   Tol   : constant Float := 1.0E-6;
   MaxIt : constant := 50;

   type Root_Func is access function (X : Float)
       return Float;

   function Bisect (F : Root_Func; A_In, B_In : Float)
       return Float is
      A  : Float := A_In;
      B  : Float := B_In;
      FA : Float := F (A);
      Mid, FMid : Float;
   begin
      if FA * F (B) > 0.0 then
         return (A + B) / 2.0;
      end if;
      for I in 1 .. MaxIt loop
         Mid  := (A + B) / 2.0;
         FMid := F (Mid);
         if abs (FMid) < Tol or (B-A)/2.0 < Tol then
            return Mid;
         end if;
         if FA * FMid < 0.0 then
            B := Mid;
         else
            A := Mid; FA := FMid;
         end if;
      end loop;
      return (A + B) / 2.0;
   end Bisect;

   function Ridder (F : Root_Func; A_In, B_In : Float)
       return Float is
      A, B, FA, FB : Float;
      Mid, FMid, S, Sgn, XNew, FNew : Float;
   begin
      A := A_In; B := B_In;
      FA := F (A); FB := F (B);
      if FA * FB > 0.0 then
         return (A + B) / 2.0;
      end if;
      for I in 1 .. MaxIt loop
         Mid  := (A + B) / 2.0;
         FMid := F (Mid);
         S := Sqrt (FMid*FMid - FA*FB);
         if S = 0.0 then return Mid; end if;
         if FA - FB >= 0.0 then
            Sgn := abs (FMid);
         else
            Sgn := -abs (FMid);
         end if;
         XNew := Mid + (Mid - A) * Sgn / S;
         FNew := F (XNew);
         if abs (FNew) < Tol then return XNew; end if;
         if FMid * FNew < 0.0 then
            A := Mid; FA := FMid;
            B := XNew; FB := FNew;
         elsif FA * FNew < 0.0 then
            B := XNew; FB := FNew;
         else
            A := XNew; FA := FNew;
         end if;
      end loop;
      return (A + B) / 2.0;
   end Ridder;

end Find_Root;`,
