    typescript: `// mathexpr.ts — Mathematical Expression Parser
// SWMM5 Engine in TypeScript — Recursive descent evaluator

class ExprParser {
    private expr: string;
    private pos: number = 0;
    private vars: Map<string, number> = new Map();

    constructor(expr: string) { this.expr = expr; }

    setVar(name: string, val: number): void {
        this.vars.set(name, val);
    }

    evaluate(): number {
        this.pos = 0;
        return this.parseExpr();
    }

    private skipSpaces(): void {
        while (this.pos < this.expr.length &&
               this.expr[this.pos] === ' ')
            this.pos++;
    }

    private parseExpr(): number {
        let val = this.parseTerm();
        this.skipSpaces();
        while (this.pos < this.expr.length &&
               '+-'.includes(this.expr[this.pos])) {
            const op = this.expr[this.pos++];
            const rhs = this.parseTerm();
            val = op === '+' ? val + rhs : val - rhs;
            this.skipSpaces();
        }
        return val;
    }

    private parseTerm(): number {
        let val = this.parseFactor();
        this.skipSpaces();
        while (this.pos < this.expr.length &&
               '*/'.includes(this.expr[this.pos])) {
            const op = this.expr[this.pos++];
            const rhs = this.parseFactor();
            val = op === '*' ? val * rhs : val / rhs;
            this.skipSpaces();
        }
        return val;
    }

    private parseFactor(): number {
        this.skipSpaces();
        if (this.expr[this.pos] === '(') {
            this.pos++;
            const val = this.parseExpr();
            this.pos++;
            return val;
        }
        if (/[a-zA-Z]/.test(this.expr[this.pos] || '')) {
            let name = '';
            while (/[a-zA-Z0-9]/.test(
                this.expr[this.pos] || ''))
                name += this.expr[this.pos++];
            if (this.expr[this.pos] === '(') {
                this.pos++;
                const arg = this.parseExpr();
                this.pos++;
                const fns: Record<string,
                    (x: number) => number> = {
                    sqrt: Math.sqrt, exp: Math.exp,
                    log: Math.log, abs: Math.abs,
                    sin: Math.sin, cos: Math.cos
                };
                return (fns[name] || ((x: number) => x))
                    (arg);
            }
            return this.vars.get(name) || 0;
        }
        return this.parseNumber();
    }

    private parseNumber(): number {
        const start = this.pos;
        while (/[0-9.]/.test(this.expr[this.pos] || ''))
            this.pos++;
        return parseFloat(
            this.expr.slice(start, this.pos)) || 0;
    }
}

export { ExprParser };`,
    cuda: `// mathexpr.cu — Mathematical Expression Parser
// SWMM5 Engine in CUDA — Device-side simple evaluator
// Supports basic stack-based postfix evaluation

#include <math.h>

#define MAX_STACK 32

__device__ float eval_postfix(const float* tokens,
    const int* ops, int nTokens)
{
    float stack[MAX_STACK];
    int   top = -1;
    float a, b;

    for (int i = 0; i < nTokens; i++) {
        switch (ops[i]) {
        case 0:
            stack[++top] = tokens[i];
            break;
        case '+':
            b = stack[top--]; a = stack[top--];
            stack[++top] = a + b;
            break;
        case '-':
            b = stack[top--]; a = stack[top--];
            stack[++top] = a - b;
            break;
        case '*':
            b = stack[top--]; a = stack[top--];
            stack[++top] = a * b;
            break;
        case '/':
            b = stack[top--]; a = stack[top--];
            stack[++top] = (b != 0.0f) ? a/b : 0.0f;
            break;
        case 's':
            stack[top] = sqrtf(stack[top]);
            break;
        case 'e':
            stack[top] = expf(stack[top]);
            break;
        case 'l':
            stack[top] = logf(stack[top]);
            break;
        case 'a':
            stack[top] = fabsf(stack[top]);
            break;
        }
    }
    return (top >= 0) ? stack[top] : 0.0f;
}

__global__ void evalExprKernel(const float* tokens,
    const int* ops, int nTokens, float* results, int n)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx < n)
        results[idx] = eval_postfix(tokens, ops, nTokens);
}`,
