    mojo: `# mathexpr.mojo — Mathematical Expression Parser
# SWMM5 Engine in Mojo — Recursive descent evaluator

from math import sqrt, exp, log, sin, cos
from math import abs as mabs

struct ExprParser:
    var expr: String
    var pos: Int
    var vars: DynamicVector[Tuple[String, Float64]]

    fn __init__(inout self, expr: String):
        self.expr = expr
        self.pos = 0
        self.vars = DynamicVector[Tuple[String, Float64]]()

    fn set_var(inout self, name: String, val: Float64):
        self.vars.push_back((name, val))

    fn evaluate(inout self) -> Float64:
        self.pos = 0
        return self.parse_expr()

    fn skip_spaces(inout self):
        while self.pos < len(self.expr) and \
              self.expr[self.pos] == " ":
            self.pos += 1

    fn parse_expr(inout self) -> Float64:
        var val = self.parse_term()
        self.skip_spaces()
        while self.pos < len(self.expr) and \
              (self.expr[self.pos] == "+" or \
               self.expr[self.pos] == "-"):
            let op = self.expr[self.pos]
            self.pos += 1
            let rhs = self.parse_term()
            if op == "+":
                val = val + rhs
            else:
                val = val - rhs
            self.skip_spaces()
        return val

    fn parse_term(inout self) -> Float64:
        var val = self.parse_factor()
        self.skip_spaces()
        while self.pos < len(self.expr) and \
              (self.expr[self.pos] == "*" or \
               self.expr[self.pos] == "/"):
            let op = self.expr[self.pos]
            self.pos += 1
            let rhs = self.parse_factor()
            if op == "*":
                val = val * rhs
            else:
                val = val / rhs
            self.skip_spaces()
        return val

    fn parse_factor(inout self) -> Float64:
        self.skip_spaces()
        if self.pos < len(self.expr) and \
           self.expr[self.pos] == "(":
            self.pos += 1
            let val = self.parse_expr()
            if self.pos < len(self.expr):
                self.pos += 1
            return val
        return self.parse_number()

    fn parse_number(inout self) -> Float64:
        let start = self.pos
        while self.pos < len(self.expr) and \
              (self.expr[self.pos].isdigit() or \
               self.expr[self.pos] == "."):
            self.pos += 1
        return atof(self.expr[start:self.pos])`,
    java: `// MathExpr.java — Mathematical Expression Parser
// SWMM5 Engine in Java — Recursive descent evaluator

package swmm;

import java.util.HashMap;
import java.util.Map;

public class MathExpr {
    private final String expr;
    private int pos;
    private final Map<String, Double> vars = new HashMap<>();

    public MathExpr(String expr) { this.expr = expr; }

    public void setVar(String n, double v) { vars.put(n,v); }

    public double evaluate() { pos = 0; return parseExpr(); }

    private void skipSpaces() {
        while (pos < expr.length() &&
               expr.charAt(pos) == ' ') pos++;
    }

    private double parseExpr() {
        double val = parseTerm();
        skipSpaces();
        while (pos < expr.length() &&
               (expr.charAt(pos)=='+' ||
                expr.charAt(pos)=='-')) {
            char op = expr.charAt(pos++);
            double rhs = parseTerm();
            val = (op == '+') ? val + rhs : val - rhs;
            skipSpaces();
        }
        return val;
    }

    private double parseTerm() {
        double val = parseFactor();
        skipSpaces();
        while (pos < expr.length() &&
               (expr.charAt(pos)=='*' ||
                expr.charAt(pos)=='/')) {
            char op = expr.charAt(pos++);
            double rhs = parseFactor();
            val = (op == '*') ? val * rhs : val / rhs;
            skipSpaces();
        }
        return val;
    }

    private double parseFactor() {
        skipSpaces();
        if (pos < expr.length() &&
            expr.charAt(pos) == '(') {
            pos++;
            double val = parseExpr();
            if (pos < expr.length()) pos++;
            return val;
        }
        if (pos < expr.length() &&
            Character.isLetter(expr.charAt(pos))) {
            StringBuilder name = new StringBuilder();
            while (pos < expr.length() &&
                   Character.isLetterOrDigit(
                       expr.charAt(pos)))
                name.append(expr.charAt(pos++));
            String fn = name.toString();
            if (pos < expr.length() &&
                expr.charAt(pos) == '(') {
                pos++;
                double arg = parseExpr();
                if (pos < expr.length()) pos++;
                switch (fn) {
                    case "sqrt": return Math.sqrt(arg);
                    case "exp":  return Math.exp(arg);
                    case "log":  return Math.log(arg);
                    case "abs":  return Math.abs(arg);
                    case "sin":  return Math.sin(arg);
                    case "cos":  return Math.cos(arg);
                    default:     return arg;
                }
            }
            return vars.getOrDefault(fn, 0.0);
        }
        return parseNumber();
    }

    private double parseNumber() {
        int start = pos;
        while (pos < expr.length() &&
               (Character.isDigit(expr.charAt(pos)) ||
                expr.charAt(pos) == '.')) pos++;
        return Double.parseDouble(
            expr.substring(start, pos));
    }
}`,
    nim: `# mathexpr.nim — Mathematical Expression Parser
# SWMM5 Engine in Nim — Recursive descent evaluator

import math, strutils, tables

type
  ExprParser = ref object
    expr: string
    pos: int
    vars: Table[string, float]

proc newExprParser(expr: string): ExprParser =
  ExprParser(expr: expr, pos: 0,
             vars: initTable[string, float]())

proc setVar(p: ExprParser, name: string, val: float) =
  p.vars[name] = val

proc parseExpr(p: ExprParser): float
proc parseTerm(p: ExprParser): float
proc parseFactor(p: ExprParser): float

proc skipSpaces(p: ExprParser) =
  while p.pos < p.expr.len and p.expr[p.pos] == ' ':
    inc p.pos

proc parseNumber(p: ExprParser): float =
  let start = p.pos
  while p.pos < p.expr.len and
        (p.expr[p.pos] in '0'..'9' or
         p.expr[p.pos] == '.'):
    inc p.pos
  parseFloat(p.expr[start..<p.pos])

proc parseFactor(p: ExprParser): float =
  p.skipSpaces()
  if p.pos < p.expr.len and p.expr[p.pos] == '(':
    inc p.pos
    result = p.parseExpr()
    if p.pos < p.expr.len: inc p.pos
    return
  if p.pos < p.expr.len and p.expr[p.pos] in
     {'a'..'z', 'A'..'Z'}:
    var name = ""
    while p.pos < p.expr.len and
          p.expr[p.pos] in {'a'..'z','A'..'Z','0'..'9'}:
      name.add p.expr[p.pos]; inc p.pos
    if p.pos < p.expr.len and p.expr[p.pos] == '(':
      inc p.pos
      let arg = p.parseExpr()
      if p.pos < p.expr.len: inc p.pos
      case name
      of "sqrt": return sqrt(arg)
      of "exp":  return exp(arg)
      of "log":  return ln(arg)
      of "abs":  return abs(arg)
      of "sin":  return sin(arg)
      of "cos":  return cos(arg)
      else: return arg
    return p.vars.getOrDefault(name, 0.0)
  p.parseNumber()

proc parseTerm(p: ExprParser): float =
  result = p.parseFactor()
  p.skipSpaces()
  while p.pos < p.expr.len and
        p.expr[p.pos] in {'*', '/'}:
    let op = p.expr[p.pos]; inc p.pos
    let rhs = p.parseFactor()
    result = if op == '*': result * rhs
             else: result / rhs
    p.skipSpaces()

proc parseExpr(p: ExprParser): float =
  result = p.parseTerm()
  p.skipSpaces()
  while p.pos < p.expr.len and
        p.expr[p.pos] in {'+', '-'}:
    let op = p.expr[p.pos]; inc p.pos
    let rhs = p.parseTerm()
    result = if op == '+': result + rhs
             else: result - rhs
    p.skipSpaces()

proc evaluate(p: ExprParser): float =
  p.pos = 0
  p.parseExpr()`,
