    julia: `# shape.jl — Normalized Cross-Section Shapes
# SWMM5 Engine in Julia — Shape Table Lookup
# Tabular depth-area-width relationships for
# standard and custom cross-section shapes

const MAX_SHAPE_POINTS = 51

struct ShapeEntry
    depth::Float64
    a_frac::Float64
    w_frac::Float64
end

mutable struct ShapeTable
    entries::Vector{ShapeEntry}
    ShapeTable() = new(ShapeEntry[])
end

function add_entry!(t::ShapeTable, depth::Float64,
                    a_frac::Float64, w_frac::Float64)
    length(t.entries) >= MAX_SHAPE_POINTS && return false
    push!(t.entries, ShapeEntry(depth, a_frac, w_frac))
    true
end

function _interp(x, x1, x2, y1, y2)
    abs(x2 - x1) < 1.0e-20 && return y1
    y1 + (y2 - y1) * (x - x1) / (x2 - x1)
end

function lookup_area(t::ShapeTable, y_norm::Float64)
    length(t.entries) < 2 && return y_norm
    y_norm ≤ 0.0 && return 0.0
    y_norm ≥ 1.0 && return 1.0

    for i in 2:length(t.entries)
        if t.entries[i].depth ≥ y_norm
            return _interp(y_norm,
                t.entries[i-1].depth,
                t.entries[i].depth,
                t.entries[i-1].a_frac,
                t.entries[i].a_frac)
        end
    end
    t.entries[end].a_frac
end

function lookup_width(t::ShapeTable, y_norm::Float64)
    length(t.entries) < 2 && return 1.0
    y_norm ≤ 0.0 && return 0.0
    y_norm ≥ 1.0 && return 0.0

    for i in 2:length(t.entries)
        if t.entries[i].depth ≥ y_norm
            return _interp(y_norm,
                t.entries[i-1].depth,
                t.entries[i].depth,
                t.entries[i-1].w_frac,
                t.entries[i].w_frac)
        end
    end
    t.entries[end].w_frac
end`,
