    delphi: `{ shape.pas — Normalized Cross-Section Shapes }
{ SWMM5 Engine in Delphi — Shape Table Lookup }
{ Tabular depth-area-width relationships for }
{ standard and custom cross-section shapes }

unit Shape;

interface

const
  MAX_SHAPE_POINTS = 51;

type
  TShapeEntry = record
    Depth, AFrac, WFrac: Double;
  end;

  TShapeTable = class
  private
    FEntries: array of TShapeEntry;
    FCount: Integer;
    class function Interp(X, X1, X2,
                          Y1, Y2: Double): Double;
  public
    constructor Create;
    function AddEntry(Depth, AFrac,
                      WFrac: Double): Boolean;
    function LookupArea(YNorm: Double): Double;
    function LookupWidth(YNorm: Double): Double;
  end;

implementation

uses Math;

constructor TShapeTable.Create;
begin
  SetLength(FEntries, MAX_SHAPE_POINTS);
  FCount := 0;
end;

class function TShapeTable.Interp(X, X1, X2,
    Y1, Y2: Double): Double;
begin
  if Abs(X2 - X1) < 1e-20 then
    Exit(Y1);
  Result := Y1 + (Y2 - Y1) * (X - X1) / (X2 - X1);
end;

function TShapeTable.AddEntry(Depth, AFrac,
    WFrac: Double): Boolean;
begin
  if FCount >= MAX_SHAPE_POINTS then Exit(False);
  FEntries[FCount].Depth := Depth;
  FEntries[FCount].AFrac := AFrac;
  FEntries[FCount].WFrac := WFrac;
  Inc(FCount);
  Result := True;
end;

function TShapeTable.LookupArea(YNorm: Double): Double;
var I: Integer;
begin
  if FCount < 2 then Exit(YNorm);
  if YNorm <= 0.0 then Exit(0.0);
  if YNorm >= 1.0 then Exit(1.0);

  for I := 1 to FCount - 1 do
    if FEntries[I].Depth >= YNorm then
      Exit(Interp(YNorm,
        FEntries[I-1].Depth, FEntries[I].Depth,
        FEntries[I-1].AFrac, FEntries[I].AFrac));
  Result := FEntries[FCount - 1].AFrac;
end;

function TShapeTable.LookupWidth(YNorm: Double): Double;
var I: Integer;
begin
  if FCount < 2 then Exit(1.0);
  if YNorm <= 0.0 then Exit(0.0);
  if YNorm >= 1.0 then Exit(0.0);

  for I := 1 to FCount - 1 do
    if FEntries[I].Depth >= YNorm then
      Exit(Interp(YNorm,
        FEntries[I-1].Depth, FEntries[I].Depth,
        FEntries[I-1].WFrac, FEntries[I].WFrac));
  Result := FEntries[FCount - 1].WFrac;
end;

end.`,
