    cuda: `// shape.cu — Normalized Cross-Section Shapes
// SWMM5 Engine in CUDA — Shape Table Lookup
// Tabular depth-area-width relationships for
// standard and custom cross-section shapes

#include <math.h>

#define MAX_SHAPE_POINTS 51

struct ShapeEntry {
    float depth;
    float aFrac;
    float wFrac;
};

struct ShapeTable {
    ShapeEntry entries[MAX_SHAPE_POINTS];
    int nEntries;
};

__device__ float shape_interp(float x, float x1,
    float x2, float y1, float y2)
{
    if (fabsf(x2 - x1) < 1.0e-20f) return y1;
    return y1 + (y2 - y1) * (x - x1) / (x2 - x1);
}

__device__ float shape_lookupArea(const ShapeTable* t,
    float yNorm)
{
    if (t->nEntries < 2) return yNorm;
    if (yNorm <= 0.0f) return 0.0f;
    if (yNorm >= 1.0f) return 1.0f;

    for (int i = 1; i < t->nEntries; i++) {
        if (t->entries[i].depth >= yNorm) {
            return shape_interp(yNorm,
                t->entries[i-1].depth,
                t->entries[i].depth,
                t->entries[i-1].aFrac,
                t->entries[i].aFrac);
        }
    }
    return t->entries[t->nEntries - 1].aFrac;
}

__global__ void shapeLookupKernel(
    const ShapeTable* tables, const float* yNorms,
    float* areas, float* widths, int n)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    areas[idx] = shape_lookupArea(&tables[idx],
                                   yNorms[idx]);
}`,
