    java: `// Shape.java — Normalized Cross-Section Shapes
// SWMM5 Engine in Java — Shape Table Lookup
// Tabular depth-area-width relationships for
// standard and custom cross-section shapes

import java.util.ArrayList;
import java.util.List;

public class ShapeTable {
    static final int MAX_POINTS = 51;

    record Entry(double depth, double aFrac,
                 double wFrac) {}

    private final List<Entry> entries = new ArrayList<>();

    public boolean addEntry(double depth, double aFrac,
                            double wFrac) {
        if (entries.size() >= MAX_POINTS) return false;
        entries.add(new Entry(depth, aFrac, wFrac));
        return true;
    }

    private static double interp(double x, double x1,
        double x2, double y1, double y2) {
        if (Math.abs(x2 - x1) < 1e-20) return y1;
        return y1 + (y2 - y1) * (x - x1) / (x2 - x1);
    }

    public double lookupArea(double yNorm) {
        if (entries.size() < 2) return yNorm;
        if (yNorm <= 0.0) return 0.0;
        if (yNorm >= 1.0) return 1.0;

        for (int i = 1; i < entries.size(); i++) {
            if (entries.get(i).depth() >= yNorm) {
                return interp(yNorm,
                    entries.get(i-1).depth(),
                    entries.get(i).depth(),
                    entries.get(i-1).aFrac(),
                    entries.get(i).aFrac());
            }
        }
        return entries.getLast().aFrac();
    }

    public double lookupWidth(double yNorm) {
        if (entries.size() < 2) return 1.0;
        if (yNorm <= 0.0) return 0.0;
        if (yNorm >= 1.0) return 0.0;

        for (int i = 1; i < entries.size(); i++) {
            if (entries.get(i).depth() >= yNorm) {
                return interp(yNorm,
                    entries.get(i-1).depth(),
                    entries.get(i).depth(),
                    entries.get(i-1).wFrac(),
                    entries.get(i).wFrac());
            }
        }
        return entries.getLast().wFrac();
    }
}`,
