    ada: `-- shape.adb — Normalized Cross-Section Shapes
-- SWMM5 Engine in Ada — Shape Table Lookup
-- Tabular depth-area-width relationships for
-- standard and custom cross-section shapes

with Ada.Numerics.Elementary_Functions;
use  Ada.Numerics.Elementary_Functions;

package body Shape is

   Max_Points : constant := 51;

   type Shape_Entry is record
      Depth : Long_Float := 0.0;
      AFrac : Long_Float := 0.0;
      WFrac : Long_Float := 0.0;
   end record;

   type Entry_Array is array (1 .. Max_Points)
     of Shape_Entry;

   type Shape_Table is record
      Entries  : Entry_Array;
      N_Entries : Natural := 0;
   end record;

   function Interp (X, X1, X2, Y1, Y2 : Long_Float)
     return Long_Float is
   begin
      if abs (X2 - X1) < 1.0e-20 then
         return Y1;
      end if;
      return Y1 + (Y2 - Y1) * (X - X1) / (X2 - X1);
   end Interp;

   procedure Add_Entry (T : in out Shape_Table;
                        D, A, W : Long_Float;
                        OK : out Boolean) is
   begin
      if T.N_Entries >= Max_Points then
         OK := False; return;
      end if;
      T.N_Entries := T.N_Entries + 1;
      T.Entries (T.N_Entries) :=
        (Depth => D, AFrac => A, WFrac => W);
      OK := True;
   end Add_Entry;

   function Lookup_Area (T : Shape_Table;
                         Y_Norm : Long_Float)
     return Long_Float is
   begin
      if T.N_Entries < 2 then return Y_Norm; end if;
      if Y_Norm <= 0.0 then return 0.0; end if;
      if Y_Norm >= 1.0 then return 1.0; end if;

      for I in 2 .. T.N_Entries loop
         if T.Entries (I).Depth >= Y_Norm then
            return Interp (Y_Norm,
              T.Entries (I - 1).Depth,
              T.Entries (I).Depth,
              T.Entries (I - 1).AFrac,
              T.Entries (I).AFrac);
         end if;
      end loop;
      return T.Entries (T.N_Entries).AFrac;
   end Lookup_Area;

end Shape;`,
