    go: `// transect.go — Irregular Channel Transects
// SWMM5 Engine in Go — Station-Elevation Cross Section
// Computes hydraulic properties for natural channels
// using trapezoidal integration of station-elevation data

package swmm

import "math"

type Transect struct {
    Stations   []float64
    Elevations []float64
}

func NewTransect() *Transect {
    return &Transect{}
}

func (t *Transect) AddStation(x, z float64) {
    t.Stations = append(t.Stations, x)
    t.Elevations = append(t.Elevations, z)
}

func (t *Transect) GetArea(wse float64) float64 {
    area := 0.0
    for i := 0; i < len(t.Stations)-1; i++ {
        d1 := math.Max(0, wse-t.Elevations[i])
        d2 := math.Max(0, wse-t.Elevations[i+1])

        if d1 > 0 || d2 > 0 {
            dx := t.Stations[i+1] - t.Stations[i]
            area += 0.5 * (d1 + d2) * dx
        }
    }
    return area
}

func (t *Transect) GetPerimeter(wse float64) float64 {
    perim := 0.0
    for i := 0; i < len(t.Stations)-1; i++ {
        d1 := math.Max(0, wse-t.Elevations[i])
        d2 := math.Max(0, wse-t.Elevations[i+1])

        if d1 > 0 || d2 > 0 {
            dx := t.Stations[i+1] - t.Stations[i]
            dz := t.Elevations[i+1] - t.Elevations[i]
            perim += math.Sqrt(dx*dx + dz*dz)
        }
    }
    return perim
}

func (t *Transect) GetTopWidth(wse float64) float64 {
    width := 0.0
    for i := 0; i < len(t.Stations)-1; i++ {
        d1 := wse - t.Elevations[i]
        d2 := wse - t.Elevations[i+1]
        if d1 > 0 || d2 > 0 {
            width += t.Stations[i+1] - t.Stations[i]
        }
    }
    return width
}

func (t *Transect) GetHydRadius(wse float64) float64 {
    perim := t.GetPerimeter(wse)
    if perim <= 0.0 {
        return 0.0
    }
    return t.GetArea(wse) / perim
}`,
    zig: `// transect.zig — Irregular Channel Transects
// SWMM5 Engine in Zig — Station-Elevation Cross Section
// Computes hydraulic properties for natural channels
// using trapezoidal integration of station-elevation data

const std = @import("std");
const math = std.math;

const MAX_STATIONS: usize = 200;

const Transect = struct {
    stations: [MAX_STATIONS]f64 = undefined,
    elevations: [MAX_STATIONS]f64 = undefined,
    n_stations: usize = 0,

    pub fn addStation(self: *Transect, x: f64, z: f64) void {
        if (self.n_stations >= MAX_STATIONS) return;
        self.stations[self.n_stations] = x;
        self.elevations[self.n_stations] = z;
        self.n_stations += 1;
    }

    pub fn getArea(self: Transect, wse: f64) f64 {
        var area: f64 = 0.0;
        var i: usize = 0;
        while (i < self.n_stations - 1) : (i += 1) {
            const d1 = math.max(f64, 0.0,
                                wse - self.elevations[i]);
            const d2 = math.max(f64, 0.0,
                                wse - self.elevations[i+1]);
            if (d1 > 0.0 or d2 > 0.0) {
                const dx = self.stations[i+1]
                           - self.stations[i];
                area += 0.5 * (d1 + d2) * dx;
            }
        }
        return area;
    }

    pub fn getPerimeter(self: Transect, wse: f64) f64 {
        var perim: f64 = 0.0;
        var i: usize = 0;
        while (i < self.n_stations - 1) : (i += 1) {
            const d1 = math.max(f64, 0.0,
                                wse - self.elevations[i]);
            const d2 = math.max(f64, 0.0,
                                wse - self.elevations[i+1]);
            if (d1 > 0.0 or d2 > 0.0) {
                const dx = self.stations[i+1]
                           - self.stations[i];
                const dz = self.elevations[i+1]
                           - self.elevations[i];
                perim += math.sqrt(dx * dx + dz * dz);
            }
        }
        return perim;
    }

    pub fn getTopWidth(self: Transect, wse: f64) f64 {
        var width: f64 = 0.0;
        var i: usize = 0;
        while (i < self.n_stations - 1) : (i += 1) {
            const d1 = wse - self.elevations[i];
            const d2 = wse - self.elevations[i+1];
            if (d1 > 0.0 or d2 > 0.0) {
                width += self.stations[i+1]
                         - self.stations[i];
            }
        }
        return width;
    }

    pub fn getHydRadius(self: Transect, wse: f64) f64 {
        const perim = self.getPerimeter(wse);
        if (perim <= 0.0) return 0.0;
        return self.getArea(wse) / perim;
    }
};`,
    cpp: `// transect.cpp — Irregular Channel Transects
// SWMM5 Engine in C++ — Station-Elevation Cross Section
// Computes hydraulic properties for natural channels
// using trapezoidal integration of station-elevation data

#include <cmath>
#include <vector>

namespace swmm {

struct Transect {
    std::vector<double> stations;
    std::vector<double> elevations;

    void addStation(double x, double z) {
        stations.push_back(x);
        elevations.push_back(z);
    }

    double getArea(double wse) const {
        double area = 0.0;
        for (size_t i = 0; i < stations.size() - 1; i++) {
            double d1 = std::max(0.0,
                                 wse - elevations[i]);
            double d2 = std::max(0.0,
                                 wse - elevations[i+1]);
            if (d1 > 0.0 || d2 > 0.0) {
                double dx = stations[i+1] - stations[i];
                area += 0.5 * (d1 + d2) * dx;
            }
        }
        return area;
    }

    double getPerimeter(double wse) const {
        double perim = 0.0;
        for (size_t i = 0; i < stations.size() - 1; i++) {
            double d1 = std::max(0.0,
                                 wse - elevations[i]);
            double d2 = std::max(0.0,
                                 wse - elevations[i+1]);
            if (d1 > 0.0 || d2 > 0.0) {
                double dx = stations[i+1] - stations[i];
                double dz = elevations[i+1]
                            - elevations[i];
                perim += std::sqrt(dx * dx + dz * dz);
            }
        }
        return perim;
    }

    double getTopWidth(double wse) const {
        double width = 0.0;
        for (size_t i = 0; i < stations.size() - 1; i++) {
            double d1 = wse - elevations[i];
            double d2 = wse - elevations[i + 1];
            if (d1 > 0.0 || d2 > 0.0)
                width += stations[i+1] - stations[i];
        }
        return width;
    }

    double getHydRadius(double wse) const {
        double perim = getPerimeter(wse);
        if (perim <= 0.0) return 0.0;
        return getArea(wse) / perim;
    }
};

} // namespace swmm`,
