    cuda: `// transect.cu — Irregular Channel Transects
// SWMM5 Engine in CUDA — Station-Elevation Cross Section
// Computes hydraulic properties for natural channels
// using trapezoidal integration of station-elevation data

#include <math.h>

#define MAX_STATIONS 200

struct Transect {
    float stations[MAX_STATIONS];
    float elevations[MAX_STATIONS];
    int   nStations;
};

__device__ float transect_getArea(const Transect* t,
    float wse)
{
    float area = 0.0f;
    for (int i = 0; i < t->nStations - 1; i++) {
        float d1 = fmaxf(0.0f,
                          wse - t->elevations[i]);
        float d2 = fmaxf(0.0f,
                          wse - t->elevations[i+1]);
        if (d1 > 0.0f || d2 > 0.0f) {
            float dx = t->stations[i+1]
                       - t->stations[i];
            area += 0.5f * (d1 + d2) * dx;
        }
    }
    return area;
}

__device__ float transect_getPerimeter(const Transect* t,
    float wse)
{
    float perim = 0.0f;
    for (int i = 0; i < t->nStations - 1; i++) {
        float d1 = fmaxf(0.0f,
                          wse - t->elevations[i]);
        float d2 = fmaxf(0.0f,
                          wse - t->elevations[i+1]);
        if (d1 > 0.0f || d2 > 0.0f) {
            float dx = t->stations[i+1]
                       - t->stations[i];
            float dz = t->elevations[i+1]
                       - t->elevations[i];
            perim += sqrtf(dx * dx + dz * dz);
        }
    }
    return perim;
}

__global__ void transectKernel(const Transect* transects,
    const float* wses, float* areas, float* perims,
    int n)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    areas[idx] = transect_getArea(&transects[idx],
                                   wses[idx]);
    perims[idx] = transect_getPerimeter(&transects[idx],
                                         wses[idx]);
}`,
