    r: `# input.R — INP File Parsing
# SWMM5 Engine in R — INP Input File Parser
# Reads bracketed section headers and tokenizes
# whitespace-delimited data lines

create_input_reader <- function() {
    list(
        current_section = "",
        line_num = 0L,
        tokens = character(0)
    )
}

is_section_header <- function(line) {
    trimmed <- trimws(line)
    m <- regmatches(trimmed,
                    regexpr("^\\\\[(.+)\\\\]$", trimmed))
    if (length(m) > 0 && nchar(m) > 0) {
        return(substr(m, 2, nchar(m) - 1))
    }
    return(NULL)
}

parse_tokens <- function(reader, line) {
    parts <- strsplit(trimws(line), "\\\\s+")[[1]]
    reader$tokens <- character(0)
    for (tok in parts) {
        if (startsWith(tok, ";")) break
        reader$tokens <- c(reader$tokens, tok)
    }
    reader
}

process_line <- function(reader, line) {
    reader$line_num <- reader$line_num + 1L
    trimmed <- trimws(line)

    if (nchar(trimmed) == 0 ||
        startsWith(trimmed, ";")) {
        reader$count <- 0L
        return(reader)
    }

    section <- is_section_header(trimmed)
    if (!is.null(section)) {
        reader$current_section <- section
        reader$count <- 1L
        return(reader)
    }

    reader <- parse_tokens(reader, trimmed)
    reader$count <- length(reader$tokens)
    reader
}

read_file <- function(reader, content) {
    lines <- strsplit(content, "\\n")[[1]]
    results <- list()
    for (line in lines) {
        reader <- process_line(reader, line)
        if (reader$count > 0 &&
            length(reader$tokens) > 0) {
            results[[length(results) + 1]] <- list(
                section = reader$current_section,
                tokens = reader$tokens)
        }
    }
    results
}`,
    delphi: `{ input.pas — INP File Parsing }
{ SWMM5 Engine in Delphi — INP Input File Parser }
{ Reads bracketed section headers and tokenizes }
{ whitespace-delimited data lines }

unit Input;

interface

uses Classes, SysUtils;

type
  TInputReader = class
  private
    FCurrentSection: string;
    FLineNum: Integer;
    FTokens: TStringList;
  public
    constructor Create;
    destructor Destroy; override;
    function IsSectionHeader(const Line: string;
        var Section: string): Boolean;
    procedure ParseTokens(const Line: string);
    function ProcessLine(const Line: string): Integer;
    function GetSection: string;
    function GetLineNum: Integer;
    property Tokens: TStringList read FTokens;
  end;

implementation

constructor TInputReader.Create;
begin
  inherited;
  FCurrentSection := '';
  FLineNum := 0;
  FTokens := TStringList.Create;
  FTokens.Delimiter := ' ';
  FTokens.StrictDelimiter := False;
end;

destructor TInputReader.Destroy;
begin
  FTokens.Free;
  inherited;
end;

function TInputReader.IsSectionHeader(const Line: string;
    var Section: string): Boolean;
var
  Trimmed: string;
begin
  Result := False;
  Trimmed := Trim(Line);
  if (Length(Trimmed) < 3) then Exit;
  if (Trimmed[1] = '[') and
     (Trimmed[Length(Trimmed)] = ']') then
  begin
    Section := Copy(Trimmed, 2, Length(Trimmed) - 2);
    Result := True;
  end;
end;

procedure TInputReader.ParseTokens(const Line: string);
var
  I: Integer;
begin
  FTokens.Clear;
  FTokens.DelimitedText := Trim(Line);
  for I := FTokens.Count - 1 downto 0 do
  begin
    if Pos(';', FTokens[I]) = 1 then
    begin
      while FTokens.Count > I do
        FTokens.Delete(FTokens.Count - 1);
      Break;
    end;
  end;
end;

function TInputReader.ProcessLine(
    const Line: string): Integer;
var
  Trimmed, Section: string;
begin
  Inc(FLineNum);
  Trimmed := Trim(Line);
  Result := 0;

  if (Trimmed = '') or (Trimmed[1] = ';') then
    Exit;

  if IsSectionHeader(Trimmed, Section) then
  begin
    FCurrentSection := Section;
    Result := 1;
    Exit;
  end;

  ParseTokens(Trimmed);
  Result := FTokens.Count;
end;

function TInputReader.GetSection: string;
begin
  Result := FCurrentSection;
end;

function TInputReader.GetLineNum: Integer;
begin
  Result := FLineNum;
end;

end.`,
