    cuda: `// input.cu — INP File Parsing
// SWMM5 Engine in CUDA — INP Input File Parser
// Reads bracketed section headers and tokenizes
// whitespace-delimited data lines (host-side)

#include <stdio.h>
#include <string.h>
#include <ctype.h>

#define MAX_LINE    256
#define MAX_TOKENS  20
#define MAX_SECTION 32

struct InputReader {
    char currentSection[MAX_SECTION];
    int  lineNum;
    int  tokenCount;
    char tokens[MAX_TOKENS][MAX_LINE];
};

__host__ void input_init(InputReader* r)
{
    r->currentSection[0] = '\\0';
    r->lineNum = 0;
    r->tokenCount = 0;
}

__host__ int input_isSectionHeader(const char* line,
                                    char* section)
{
    int len = strlen(line);
    if (len < 3 || line[0] != '[') return 0;
    const char* end = strchr(line, ']');
    if (!end) return 0;
    int slen = end - line - 1;
    strncpy(section, line + 1, slen);
    section[slen] = '\\0';
    return 1;
}

__host__ int input_parseTokens(const char* line,
                                InputReader* r)
{
    r->tokenCount = 0;
    const char* p = line;
    while (*p && r->tokenCount < MAX_TOKENS) {
        while (*p && isspace(*p)) p++;
        if (!*p || *p == ';') break;
        int i = 0;
        while (*p && !isspace(*p) && *p != ';')
            r->tokens[r->tokenCount][i++] = *p++;
        r->tokens[r->tokenCount][i] = '\\0';
        r->tokenCount++;
    }
    return r->tokenCount;
}

__host__ int input_processLine(InputReader* r,
                                const char* line)
{
    char section[MAX_SECTION];
    r->lineNum++;
    if (line[0] == ';' || line[0] == '\\0') return 0;
    if (input_isSectionHeader(line, section)) {
        strncpy(r->currentSection, section,
                MAX_SECTION - 1);
        return 1;
    }
    return input_parseTokens(line, r);
}

__global__ void tokenCountKernel(char* lines,
    int* lineLengths, int* tokenCounts,
    int numLines, int maxLen)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= numLines) return;
    char* line = lines + idx * maxLen;
    int count = 0;
    int inToken = 0;
    for (int i = 0; i < lineLengths[idx]; i++) {
        if (line[i] == ';') break;
        if (line[i] == ' ' || line[i] == '\\t') {
            inToken = 0;
        } else if (!inToken) {
            inToken = 1;
            count++;
        }
    }
    tokenCounts[idx] = count;
}`,
