    fortran: `! report.f90 — Simulation Report Generation
! SWMM5 Engine in Fortran — Report Writer
! Generates formatted text reports with summary
! statistics and continuity error checking

module report_module
    implicit none
    integer, parameter :: MAX_LINES = 500
    integer, parameter :: MAX_LINE_LEN = 256

    type :: ReportWriter
        character(len=MAX_LINE_LEN) :: lines(MAX_LINES)
        integer :: lineCount = 0
    end type ReportWriter

contains

    subroutine report_init(rw)
        type(ReportWriter), intent(inout) :: rw
        rw%lineCount = 0
    end subroutine

    subroutine report_addLine(rw, line)
        type(ReportWriter), intent(inout) :: rw
        character(len=*), intent(in) :: line
        if (rw%lineCount >= MAX_LINES) return
        rw%lineCount = rw%lineCount + 1
        rw%lines(rw%lineCount) = line
    end subroutine

    subroutine report_writeHeader(rw, title)
        type(ReportWriter), intent(inout) :: rw
        character(len=*), intent(in) :: title
        call report_addLine(rw, &
            '==========================================')
        call report_addLine(rw, &
            '  SWMM5 Simulation Report')
        call report_addLine(rw, &
            '==========================================')
        call report_addLine(rw, title)
        call report_addLine(rw, '')
    end subroutine

    function compute_error(totalInflow, totalOutflow) &
        result(pctError)
        real(8), intent(in) :: totalInflow, totalOutflow
        real(8) :: pctError, avg
        avg = (totalInflow + totalOutflow) / 2.0d0
        if (abs(avg) < 1.0d-10) then
            pctError = 0.0d0
        else
            pctError = 100.0d0 * &
                (totalInflow - totalOutflow) / avg
        end if
    end function

    subroutine report_writeSummaryStats(rw, &
        totalInflow, totalOutflow)
        type(ReportWriter), intent(inout) :: rw
        real(8), intent(in) :: totalInflow, totalOutflow
        character(len=MAX_LINE_LEN) :: buf
        real(8) :: pctError

        call report_addLine(rw, &
            '--- Summary Statistics ---')
        write(buf, '(A, F12.4)') &
            '  Total Inflow:  ', totalInflow
        call report_addLine(rw, buf)
        write(buf, '(A, F12.4)') &
            '  Total Outflow: ', totalOutflow
        call report_addLine(rw, buf)
        pctError = compute_error(totalInflow, &
                                  totalOutflow)
        write(buf, '(A, F8.2, A)') &
            '  Pct Error:     ', pctError, '%'
        call report_addLine(rw, buf)
    end subroutine

    function report_getLineCount(rw) result(n)
        type(ReportWriter), intent(in) :: rw
        integer :: n
        n = rw%lineCount
    end function

end module report_module`,
