    zig: `// report.zig — Simulation Report Generation
// SWMM5 Engine in Zig — Report Writer
// Generates formatted text reports with summary
// statistics and continuity error checking

const std = @import("std");

const MAX_LINES = 500;
const MAX_LINE_LEN = 256;

const ReportWriter = struct {
    lines: [MAX_LINES][MAX_LINE_LEN]u8,
    line_lens: [MAX_LINES]usize,
    line_count: usize,

    pub fn init() ReportWriter {
        return ReportWriter{
            .lines = undefined,
            .line_lens = undefined,
            .line_count = 0,
        };
    }

    pub fn addLine(self: *ReportWriter,
                   line: []const u8) void {
        if (self.line_count >= MAX_LINES) return;
        const len = @min(line.len, MAX_LINE_LEN);
        @memcpy(self.lines[self.line_count][0..len],
                line[0..len]);
        self.line_lens[self.line_count] = len;
        self.line_count += 1;
    }

    pub fn writeHeader(self: *ReportWriter,
                       title: []const u8) void {
        self.addLine("==================================");
        self.addLine("  SWMM5 Simulation Report");
        self.addLine("==================================");
        self.addLine(title);
        self.addLine("");
    }

    pub fn computeError(total_inflow: f64,
                        total_outflow: f64) f64 {
        const avg = (total_inflow + total_outflow) / 2.0;
        if (@fabs(avg) < 1e-10) return 0.0;
        return 100.0 * (total_inflow - total_outflow)
               / avg;
    }

    pub fn getLineCount(self: *const ReportWriter) usize {
        return self.line_count;
    }

    pub fn getLine(self: *const ReportWriter,
                   index: usize) []const u8 {
        if (index >= self.line_count) return "";
        return self.lines[index]
            [0..self.line_lens[index]];
    }
};`,
    cpp: `// report.cpp — Simulation Report Generation
// SWMM5 Engine in C++ — Report Writer
// Generates formatted text reports with summary
// statistics and continuity error checking

#include <string>
#include <vector>
#include <sstream>
#include <iomanip>
#include <cmath>

namespace swmm {

class ReportWriter {
    std::vector<std::string> lines_;

public:
    void addLine(const std::string& line) {
        lines_.push_back(line);
    }

    void writeHeader(const std::string& title) {
        addLine(
            "==========================================");
        addLine(
            "  SWMM5 Simulation Report");
        addLine(
            "==========================================");
        addLine(title);
        addLine("");
    }

    static std::string formatValue(double value,
                                    int decimals = 4) {
        std::ostringstream oss;
        oss << std::fixed
            << std::setprecision(decimals) << value;
        return oss.str();
    }

    static double computeError(double totalInflow,
                                double totalOutflow) {
        double avg = (totalInflow + totalOutflow) / 2.0;
        if (std::abs(avg) < 1e-10) return 0.0;
        return 100.0 * (totalInflow - totalOutflow) / avg;
    }

    void writeSummaryStats(double totalInflow,
                           double totalOutflow) {
        addLine("--- Summary Statistics ---");
        addLine("  Total Inflow:  "
                + formatValue(totalInflow));
        addLine("  Total Outflow: "
                + formatValue(totalOutflow));

        double pctError = computeError(
            totalInflow, totalOutflow);
        addLine("  Pct Error:     "
                + formatValue(pctError, 2) + "%");
    }

    const std::string& getLine(int index) const {
        static const std::string empty;
        if (index >= 0
            && index < static_cast<int>(lines_.size()))
            return lines_[index];
        return empty;
    }

    int getLineCount() const {
        return static_cast<int>(lines_.size());
    }

    std::string getReport() const {
        std::string result;
        for (size_t i = 0; i < lines_.size(); ++i) {
            if (i > 0) result += "\\n";
            result += lines_[i];
        }
        return result;
    }
};

} // namespace swmm`,
