    ada: `-- report.adb — Simulation Report Generation
-- SWMM5 Engine in Ada — Report Writer
-- Generates formatted text reports with summary
-- statistics and continuity error checking

with Ada.Strings.Unbounded;
use Ada.Strings.Unbounded;
with Ada.Float_Text_IO;

package body Report_Writer is

   Max_Lines : constant := 500;

   type Line_Array is array (1 .. Max_Lines)
       of Unbounded_String;

   type Report is record
      Lines      : Line_Array;
      Line_Count : Natural := 0;
   end record;

   procedure Init (R : out Report) is
   begin
      R.Line_Count := 0;
   end Init;

   procedure Add_Line (R : in out Report;
                       Line : String) is
   begin
      if R.Line_Count >= Max_Lines then return; end if;
      R.Line_Count := R.Line_Count + 1;
      R.Lines (R.Line_Count) :=
          To_Unbounded_String (Line);
   end Add_Line;

   procedure Write_Header (R : in out Report;
                           Title : String) is
   begin
      Add_Line (R,
          "==========================================");
      Add_Line (R,
          "  SWMM5 Simulation Report");
      Add_Line (R,
          "==========================================");
      Add_Line (R, Title);
      Add_Line (R, "");
   end Write_Header;

   function Compute_Error (Total_Inflow : Long_Float;
                           Total_Outflow : Long_Float)
       return Long_Float is
      Avg : Long_Float;
   begin
      Avg := (Total_Inflow + Total_Outflow) / 2.0;
      if abs (Avg) < 1.0e-10 then
         return 0.0;
      end if;
      return 100.0 *
          (Total_Inflow - Total_Outflow) / Avg;
   end Compute_Error;

   procedure Write_Summary (R : in out Report;
                            Inflow : Long_Float;
                            Outflow : Long_Float) is
      Err : Long_Float;
   begin
      Add_Line (R, "--- Summary Statistics ---");
      Add_Line (R, "  Total Inflow:  "
                   & Long_Float'Image (Inflow));
      Add_Line (R, "  Total Outflow: "
                   & Long_Float'Image (Outflow));
      Err := Compute_Error (Inflow, Outflow);
      Add_Line (R, "  Pct Error:     "
                   & Long_Float'Image (Err) & "%");
   end Write_Summary;

   function Get_Line_Count (R : Report)
       return Natural is
   begin
      return R.Line_Count;
   end Get_Line_Count;

end Report_Writer;`,
