    r: `# project.R — Project Data Management
# SWMM5 Engine in R — Project Object Table Manager
# Manages nodes, links, and object lookup for
# the simulation project data structure

create_project <- function(title = "") {
    list(
        title = title,
        nodes = list(),
        links = list()
    )
}

add_node <- function(p, name, invert, max_depth) {
    node <- list(name = name, invert = invert,
                 max_depth = max_depth)
    p$nodes[[length(p$nodes) + 1]] <- node
    p
}

add_link <- function(p, name, from_node, to_node,
                      len) {
    link <- list(name = name, from_node = from_node,
                 to_node = to_node, length = len)
    p$links[[length(p$links) + 1]] <- link
    p
}

find_node <- function(p, name) {
    for (i in seq_along(p$nodes)) {
        if (p$nodes[[i]]$name == name)
            return(i)
    }
    return(NULL)
}

find_link <- function(p, name) {
    for (i in seq_along(p$links)) {
        if (p$links[[i]]$name == name)
            return(i)
    }
    return(NULL)
}

clear_project <- function(p) {
    p$nodes <- list()
    p$links <- list()
    p$title <- ""
    p
}

get_object_count <- function(p) {
    length(p$nodes) + length(p$links)
}`,
    delphi: `{ project.pas — Project Data Management }
{ SWMM5 Engine in Delphi — Project Object Table Manager }
{ Manages nodes, links, and object lookup for }
{ the simulation project data structure }

unit ProjectMgr;

interface

uses Classes, SysUtils;

const
  MAX_NODES = 500;
  MAX_LINKS = 500;

type
  TNode = record
    Name: string;
    Invert: Double;
    MaxDepth: Double;
  end;

  TLink = record
    Name: string;
    FromNode: Integer;
    ToNode: Integer;
    Length: Double;
  end;

  TProject = class
  private
    FTitle: string;
    FNodes: array[0..MAX_NODES-1] of TNode;
    FNodeCount: Integer;
    FLinks: array[0..MAX_LINKS-1] of TLink;
    FLinkCount: Integer;
  public
    constructor Create(const ATitle: string);
    function AddNode(const AName: string;
        AInvert, AMaxDepth: Double): Integer;
    function AddLink(const AName: string;
        AFromNode, AToNode: Integer;
        ALength: Double): Integer;
    function FindNode(const AName: string): Integer;
    function FindLink(const AName: string): Integer;
    procedure Clear;
    function GetObjectCount: Integer;
    property Title: string read FTitle;
  end;

implementation

constructor TProject.Create(const ATitle: string);
begin
  inherited Create;
  FTitle := ATitle;
  FNodeCount := 0;
  FLinkCount := 0;
end;

function TProject.AddNode(const AName: string;
    AInvert, AMaxDepth: Double): Integer;
begin
  if FNodeCount >= MAX_NODES then Exit(-1);
  Result := FNodeCount;
  FNodes[Result].Name := AName;
  FNodes[Result].Invert := AInvert;
  FNodes[Result].MaxDepth := AMaxDepth;
  Inc(FNodeCount);
end;

function TProject.AddLink(const AName: string;
    AFromNode, AToNode: Integer;
    ALength: Double): Integer;
begin
  if FLinkCount >= MAX_LINKS then Exit(-1);
  Result := FLinkCount;
  FLinks[Result].Name := AName;
  FLinks[Result].FromNode := AFromNode;
  FLinks[Result].ToNode := AToNode;
  FLinks[Result].Length := ALength;
  Inc(FLinkCount);
end;

function TProject.FindNode(
    const AName: string): Integer;
var
  I: Integer;
begin
  for I := 0 to FNodeCount - 1 do
    if FNodes[I].Name = AName then Exit(I);
  Result := -1;
end;

function TProject.FindLink(
    const AName: string): Integer;
var
  I: Integer;
begin
  for I := 0 to FLinkCount - 1 do
    if FLinks[I].Name = AName then Exit(I);
  Result := -1;
end;

procedure TProject.Clear;
begin
  FNodeCount := 0;
  FLinkCount := 0;
  FTitle := '';
end;

function TProject.GetObjectCount: Integer;
begin
  Result := FNodeCount + FLinkCount;
end;

end.`,
    typescript: `// project.ts — Project Data Management
// SWMM5 Engine in TypeScript — Project Object Table Manager
// Manages nodes, links, and object lookup for
// the simulation project data structure

interface NodeData {
    name: string;
    invert: number;
    maxDepth: number;
}

interface LinkData {
    name: string;
    fromNode: number;
    toNode: number;
    length: number;
}

class Project {
    title: string;
    nodes: NodeData[] = [];
    links: LinkData[] = [];

    constructor(title: string = "") {
        this.title = title;
    }

    addNode(name: string, invert: number,
            maxDepth: number): number {
        const idx = this.nodes.length;
        this.nodes.push({ name, invert, maxDepth });
        return idx;
    }

    addLink(name: string, fromNode: number,
            toNode: number, length: number): number {
        const idx = this.links.length;
        this.links.push({
            name, fromNode, toNode, length });
        return idx;
    }

    findNode(name: string): number | null {
        const idx = this.nodes.findIndex(
            n => n.name === name);
        return idx >= 0 ? idx : null;
    }

    findLink(name: string): number | null {
        const idx = this.links.findIndex(
            l => l.name === name);
        return idx >= 0 ? idx : null;
    }

    clear(): void {
        this.nodes = [];
        this.links = [];
        this.title = "";
    }

    getObjectCount(): number {
        return this.nodes.length + this.links.length;
    }
}

export { Project, NodeData, LinkData };`,
    cuda: `// project.cu — Project Data Management
// SWMM5 Engine in CUDA — Project Object Table Manager
// Manages nodes, links, and object lookup for
// the simulation project data structure

#include <stdio.h>
#include <string.h>

#define MAX_NODES 500
#define MAX_LINKS 500
#define MAX_NAME  64

struct TNode {
    char   name[MAX_NAME];
    double invert;
    double maxDepth;
};

struct TLink {
    char   name[MAX_NAME];
    int    fromNode;
    int    toNode;
    double length;
};

struct Project {
    char   title[256];
    TNode  nodes[MAX_NODES];
    int    nodeCount;
    TLink  links[MAX_LINKS];
    int    linkCount;
};

__host__ void project_init(Project* p,
                            const char* title)
{
    strncpy(p->title, title, 255);
    p->nodeCount = 0;
    p->linkCount = 0;
}

__host__ int project_addNode(Project* p,
    const char* name, double invert, double maxDepth)
{
    if (p->nodeCount >= MAX_NODES) return -1;
    int idx = p->nodeCount;
    strncpy(p->nodes[idx].name, name, MAX_NAME - 1);
    p->nodes[idx].invert   = invert;
    p->nodes[idx].maxDepth = maxDepth;
    p->nodeCount++;
    return idx;
}

__host__ int project_addLink(Project* p,
    const char* name, int fromNode, int toNode,
    double length)
{
    if (p->linkCount >= MAX_LINKS) return -1;
    int idx = p->linkCount;
    strncpy(p->links[idx].name, name, MAX_NAME - 1);
    p->links[idx].fromNode = fromNode;
    p->links[idx].toNode   = toNode;
    p->links[idx].length   = length;
    p->linkCount++;
    return idx;
}

__host__ int project_findNode(Project* p,
    const char* name)
{
    for (int i = 0; i < p->nodeCount; i++)
        if (strcmp(p->nodes[i].name, name) == 0)
            return i;
    return -1;
}

__global__ void countObjectsKernel(
    int* nodeCounts, int* linkCounts,
    int* totals, int numProjects)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= numProjects) return;
    totals[idx] = nodeCounts[idx] + linkCounts[idx];
}

__host__ void project_clear(Project* p)
{
    p->nodeCount = 0;
    p->linkCount = 0;
    p->title[0] = '\\0';
}

__host__ int project_getObjectCount(Project* p)
{
    return p->nodeCount + p->linkCount;
}`,
