    java: `// Project.java — Project Data Management
// SWMM5 Engine in Java — Project Object Table Manager
// Manages nodes, links, and object lookup for
// the simulation project data structure

import java.util.ArrayList;
import java.util.List;
import java.util.OptionalInt;
import java.util.stream.IntStream;

public class Project {

    public record Node(String name, double invert,
                       double maxDepth) {}

    public record Link(String name, int fromNode,
                       int toNode, double length) {}

    private String title;
    private final List<Node> nodes = new ArrayList<>();
    private final List<Link> links = new ArrayList<>();

    public Project(String title) {
        this.title = title;
    }

    public int addNode(String name, double invert,
                       double maxDepth) {
        int idx = nodes.size();
        nodes.add(new Node(name, invert, maxDepth));
        return idx;
    }

    public int addLink(String name, int fromNode,
                       int toNode, double length) {
        int idx = links.size();
        links.add(new Link(name, fromNode,
                           toNode, length));
        return idx;
    }

    public OptionalInt findNode(String name) {
        return IntStream.range(0, nodes.size())
            .filter(i -> nodes.get(i).name()
                .equals(name))
            .findFirst();
    }

    public OptionalInt findLink(String name) {
        return IntStream.range(0, links.size())
            .filter(i -> links.get(i).name()
                .equals(name))
            .findFirst();
    }

    public void clear() {
        nodes.clear();
        links.clear();
        title = "";
    }

    public int getObjectCount() {
        return nodes.size() + links.size();
    }

    public String getTitle() { return title; }
    public List<Node> getNodes() { return nodes; }
    public List<Link> getLinks() { return links; }
}`,
