    fortran: `! stats.f90 — Runtime Statistics Collection
! SWMM5 Engine in Fortran — Simulation Statistics Tracker
! Collects max/min/mean statistics for nodes and links
! during a stormwater simulation run

module stats_module
    implicit none

    type :: NodeStats
        real(8) :: maxDepth    = 0.0d0
        real(8) :: maxFlow     = 0.0d0
        real(8) :: totalVolume = 0.0d0
        real(8) :: timeFlooded = 0.0d0
        real(8) :: maxLatFlow  = 0.0d0
        integer :: periods     = 0
    end type NodeStats

    type :: LinkStats
        real(8) :: maxFlow     = 0.0d0
        real(8) :: maxVelocity = 0.0d0
        real(8) :: maxDepth    = 0.0d0
        real(8) :: totalFlow   = 0.0d0
        integer :: periods     = 0
    end type LinkStats

contains

    subroutine init_node_stats(s)
        type(NodeStats), intent(out) :: s
        s%maxDepth    = 0.0d0
        s%maxFlow     = 0.0d0
        s%totalVolume = 0.0d0
        s%timeFlooded = 0.0d0
        s%periods     = 0
    end subroutine

    subroutine update_node_stats(s, depth, flow, volume, &
                                  fullDepth, dt)
        type(NodeStats), intent(inout) :: s
        real(8), intent(in) :: depth, flow, volume
        real(8), intent(in) :: fullDepth, dt

        if (depth > s%maxDepth) s%maxDepth = depth
        if (abs(flow) > abs(s%maxFlow)) s%maxFlow = flow

        s%totalVolume = s%totalVolume + volume * dt
        s%periods = s%periods + 1

        if (depth > fullDepth .and. fullDepth > 0.0d0) then
            s%timeFlooded = s%timeFlooded + dt / 3600.0d0
        end if
    end subroutine

    subroutine update_link_stats(s, flow, velocity, depth)
        type(LinkStats), intent(inout) :: s
        real(8), intent(in) :: flow, velocity, depth

        if (abs(flow) > abs(s%maxFlow)) s%maxFlow = flow
        if (abs(velocity) > s%maxVelocity) &
            s%maxVelocity = abs(velocity)
        if (depth > s%maxDepth) s%maxDepth = depth

        s%totalFlow = s%totalFlow + abs(flow)
        s%periods = s%periods + 1
    end subroutine

    function mean_flow(s) result(avg)
        type(LinkStats), intent(in) :: s
        real(8) :: avg
        if (s%periods <= 0) then
            avg = 0.0d0
        else
            avg = s%totalFlow / dble(s%periods)
        end if
    end function

end module stats_module`,
