    go: `// stats.go — Runtime Statistics Collection
// SWMM5 Engine in Go — Simulation Statistics Tracker
// Collects max/min/mean statistics for nodes and links
// during a stormwater simulation run

package swmm

import "math"

type NodeStats struct {
    MaxDepth    float64
    MaxFlow     float64
    TotalVolume float64
    TimeFlooded float64
    MaxLatFlow  float64
    Periods     int
}

type LinkStats struct {
    MaxFlow     float64
    MaxVelocity float64
    MaxDepth    float64
    TotalFlow   float64
    Periods     int
}

func NewNodeStats() *NodeStats {
    return &NodeStats{}
}

func NewLinkStats() *LinkStats {
    return &LinkStats{}
}

func (s *NodeStats) Update(depth, flow, volume,
    fullDepth, dt float64) {
    if depth > s.MaxDepth {
        s.MaxDepth = depth
    }
    if math.Abs(flow) > math.Abs(s.MaxFlow) {
        s.MaxFlow = flow
    }
    s.TotalVolume += volume * dt
    s.Periods++

    if depth > fullDepth && fullDepth > 0.0 {
        s.TimeFlooded += dt / 3600.0
    }
}

func (s *LinkStats) Update(flow, velocity, depth float64) {
    if math.Abs(flow) > math.Abs(s.MaxFlow) {
        s.MaxFlow = flow
    }
    if math.Abs(velocity) > s.MaxVelocity {
        s.MaxVelocity = math.Abs(velocity)
    }
    if depth > s.MaxDepth {
        s.MaxDepth = depth
    }
    s.TotalFlow += math.Abs(flow)
    s.Periods++
}

func (s *LinkStats) MeanFlow() float64 {
    if s.Periods <= 0 {
        return 0.0
    }
    return s.TotalFlow / float64(s.Periods)
}`,
