    delphi: `{ stats.pas — Runtime Statistics Collection }
{ SWMM5 Engine in Delphi — Simulation Statistics Tracker }
{ Collects max/min/mean statistics for nodes and links }
{ during a stormwater simulation run }

unit Stats;

interface

type
  TNodeStats = class
  public
    MaxDepth:    Double;
    MaxFlow:     Double;
    TotalVolume: Double;
    TimeFlooded: Double;
    MaxLatFlow:  Double;
    Periods:     Integer;
    constructor Create;
    procedure Update(Depth, Flow, Volume,
                     FullDepth, Dt: Double);
  end;

  TLinkStats = class
  public
    MaxFlow:     Double;
    MaxVelocity: Double;
    MaxDepth:    Double;
    TotalFlow:   Double;
    Periods:     Integer;
    constructor Create;
    procedure Update(Flow, Velocity, Depth: Double);
    function MeanFlow: Double;
  end;

implementation

uses Math;

constructor TNodeStats.Create;
begin
  MaxDepth    := 0.0;
  MaxFlow     := 0.0;
  TotalVolume := 0.0;
  TimeFlooded := 0.0;
  Periods     := 0;
end;

procedure TNodeStats.Update(Depth, Flow, Volume,
                             FullDepth, Dt: Double);
begin
  if Depth > MaxDepth then MaxDepth := Depth;
  if Abs(Flow) > Abs(MaxFlow) then MaxFlow := Flow;

  TotalVolume := TotalVolume + Volume * Dt;
  Inc(Periods);

  if (Depth > FullDepth) and (FullDepth > 0.0) then
    TimeFlooded := TimeFlooded + Dt / 3600.0;
end;

constructor TLinkStats.Create;
begin
  MaxFlow     := 0.0;
  MaxVelocity := 0.0;
  MaxDepth    := 0.0;
  TotalFlow   := 0.0;
  Periods     := 0;
end;

procedure TLinkStats.Update(Flow, Velocity, Depth: Double);
begin
  if Abs(Flow) > Abs(MaxFlow) then MaxFlow := Flow;
  if Abs(Velocity) > MaxVelocity then
    MaxVelocity := Abs(Velocity);
  if Depth > MaxDepth then MaxDepth := Depth;

  TotalFlow := TotalFlow + Abs(Flow);
  Inc(Periods);
end;

function TLinkStats.MeanFlow: Double;
begin
  if Periods <= 0 then Exit(0.0);
  Result := TotalFlow / Periods;
end;

end.`,
