    r: `# table.R — Lookup Table & Curves
# SWMM5 Engine in R — Table Interpolation Module
# Linear interpolation, inverse lookup, and
# trapezoidal integration for curve data

table_create <- function() {
    list(x = numeric(0), y = numeric(0))
}

table_add_entry <- function(t, x_val, y_val) {
    pos <- sum(t$x < x_val) + 1
    t$x <- append(t$x, x_val, after = pos - 1)
    t$y <- append(t$y, y_val, after = pos - 1)
    t
}

table_lookup <- function(t, x_target) {
    n <- length(t$x)
    if (n == 0) return(0.0)
    if (x_target <= t$x[1]) return(t$y[1])
    if (x_target >= t$x[n]) return(t$y[n])

    for (i in 2:n) {
        if (t$x[i] >= x_target) {
            dx <- t$x[i] - t$x[i - 1]
            if (dx == 0.0) return(t$y[i])
            frac <- (x_target - t$x[i - 1]) / dx
            return(t$y[i - 1]
                   + frac * (t$y[i] - t$y[i - 1]))
        }
    }
    t$y[n]
}

table_inverse_lookup <- function(t, y_target) {
    n <- length(t$x)
    if (n == 0) return(0.0)
    if (y_target <= t$y[1]) return(t$x[1])
    if (y_target >= t$y[n]) return(t$x[n])

    for (i in 2:n) {
        if (t$y[i] >= y_target) {
            dy <- t$y[i] - t$y[i - 1]
            if (dy == 0.0) return(t$x[i])
            frac <- (y_target - t$y[i - 1]) / dy
            return(t$x[i - 1]
                   + frac * (t$x[i] - t$x[i - 1]))
        }
    }
    t$x[n]
}

table_integrate <- function(t, x_min, x_max) {
    area <- 0.0
    for (i in 2:length(t$x)) {
        x0 <- t$x[i - 1]; x1 <- t$x[i]
        if (x1 <= x_min || x0 >= x_max) next
        y0 <- if (x0 < x_min) {
            x0 <- x_min; table_lookup(t, x_min)
        } else t$y[i - 1]
        y1 <- if (x1 > x_max) {
            x1 <- x_max; table_lookup(t, x_max)
        } else t$y[i]
        area <- area + 0.5 * (y0 + y1) * (x1 - x0)
    }
    area
}`,
    delphi: `{ table.pas — Lookup Table & Curves }
{ SWMM5 Engine in Delphi — Table Interpolation Module }
{ Linear interpolation, inverse lookup, and }
{ trapezoidal integration for curve data }

unit TableUnit;

interface

const
  MAX_TABLE_SIZE = 256;

type
  TLookupTable = class
  private
    FX: array[0..MAX_TABLE_SIZE-1] of Double;
    FY: array[0..MAX_TABLE_SIZE-1] of Double;
    FSize: Integer;
  public
    constructor Create;
    procedure AddEntry(XVal, YVal: Double);
    function Lookup(XTarget: Double): Double;
    function InverseLookup(YTarget: Double): Double;
    function Integrate(XMin, XMax: Double): Double;
  end;

implementation

uses Math;

constructor TLookupTable.Create;
begin
  FSize := 0;
end;

procedure TLookupTable.AddEntry(XVal, YVal: Double);
var
  I, J: Integer;
begin
  if FSize >= MAX_TABLE_SIZE then Exit;
  I := 0;
  while (I < FSize) and (FX[I] < XVal) do Inc(I);
  for J := FSize downto I + 1 do begin
    FX[J] := FX[J - 1];
    FY[J] := FY[J - 1];
  end;
  FX[I] := XVal;
  FY[I] := YVal;
  Inc(FSize);
end;

function TLookupTable.Lookup(XTarget: Double): Double;
var
  I: Integer;
  DX, Frac: Double;
begin
  if FSize = 0 then Exit(0.0);
  if XTarget <= FX[0] then Exit(FY[0]);
  if XTarget >= FX[FSize - 1] then Exit(FY[FSize - 1]);

  for I := 1 to FSize - 1 do begin
    if FX[I] >= XTarget then begin
      DX := FX[I] - FX[I - 1];
      if DX = 0.0 then Exit(FY[I]);
      Frac := (XTarget - FX[I - 1]) / DX;
      Exit(FY[I - 1] + Frac * (FY[I] - FY[I - 1]));
    end;
  end;
  Result := FY[FSize - 1];
end;

function TLookupTable.InverseLookup(YTarget: Double): Double;
var
  I: Integer;
  DY, Frac: Double;
begin
  if FSize = 0 then Exit(0.0);
  if YTarget <= FY[0] then Exit(FX[0]);
  if YTarget >= FY[FSize - 1] then Exit(FX[FSize - 1]);

  for I := 1 to FSize - 1 do begin
    if FY[I] >= YTarget then begin
      DY := FY[I] - FY[I - 1];
      if DY = 0.0 then Exit(FX[I]);
      Frac := (YTarget - FY[I - 1]) / DY;
      Exit(FX[I - 1] + Frac * (FX[I] - FX[I - 1]));
    end;
  end;
  Result := FX[FSize - 1];
end;

function TLookupTable.Integrate(XMin, XMax: Double): Double;
var
  I: Integer;
  X0, X1, Y0, Y1: Double;
begin
  Result := 0.0;
  for I := 1 to FSize - 1 do begin
    X0 := FX[I - 1]; X1 := FX[I];
    if (X1 <= XMin) or (X0 >= XMax) then Continue;
    if X0 < XMin then begin
      Y0 := Lookup(XMin); X0 := XMin;
    end else Y0 := FY[I - 1];
    if X1 > XMax then begin
      Y1 := Lookup(XMax); X1 := XMax;
    end else Y1 := FY[I];
    Result := Result + 0.5 * (Y0 + Y1) * (X1 - X0);
  end;
end;

end.`,
