    mojo: `# table.mojo — Lookup Table & Curves
# SWMM5 Engine in Mojo — Table Interpolation Module
# Linear interpolation, inverse lookup, and
# trapezoidal integration for curve data

from collections import List

struct LookupTable:
    var x: List[Float64]
    var y: List[Float64]

    fn __init__(inout self):
        self.x = List[Float64]()
        self.y = List[Float64]()

    fn add_entry(inout self, x_val: Float64, y_val: Float64):
        var pos: Int = 0
        while pos < len(self.x) and self.x[pos] < x_val:
            pos += 1
        self.x.insert(pos, x_val)
        self.y.insert(pos, y_val)

    fn lookup(self, x_target: Float64) -> Float64:
        let n = len(self.x)
        if n == 0: return 0.0
        if x_target <= self.x[0]: return self.y[0]
        if x_target >= self.x[n - 1]: return self.y[n - 1]

        for i in range(1, n):
            if self.x[i] >= x_target:
                let dx = self.x[i] - self.x[i - 1]
                if dx == 0.0: return self.y[i]
                let frac = (x_target - self.x[i - 1]) / dx
                return self.y[i - 1] + frac * (self.y[i] - self.y[i - 1])
        return self.y[n - 1]

    fn inverse_lookup(self, y_target: Float64) -> Float64:
        let n = len(self.x)
        if n == 0: return 0.0
        if y_target <= self.y[0]: return self.x[0]
        if y_target >= self.y[n - 1]: return self.x[n - 1]

        for i in range(1, n):
            if self.y[i] >= y_target:
                let dy = self.y[i] - self.y[i - 1]
                if dy == 0.0: return self.x[i]
                let frac = (y_target - self.y[i - 1]) / dy
                return self.x[i - 1] + frac * (self.x[i] - self.x[i - 1])
        return self.x[n - 1]

    fn integrate(self, x_min: Float64, x_max: Float64) -> Float64:
        var area: Float64 = 0.0
        for i in range(1, len(self.x)):
            var x0 = self.x[i - 1]
            var x1 = self.x[i]
            if x1 <= x_min or x0 >= x_max: continue
            var y0: Float64
            var y1: Float64
            if x0 < x_min:
                y0 = self.lookup(x_min); x0 = x_min
            else:
                y0 = self.y[i - 1]
            if x1 > x_max:
                y1 = self.lookup(x_max); x1 = x_max
            else:
                y1 = self.y[i]
            area += 0.5 * (y0 + y1) * (x1 - x0)
        return area`,
    java: `// Table.java — Lookup Table & Curves
// SWMM5 Engine in Java — Table Interpolation Module
// Linear interpolation, inverse lookup, and
// trapezoidal integration for curve data

import java.util.ArrayList;
import java.util.Collections;

public class LookupTable {
    private final ArrayList<Double> x = new ArrayList<>();
    private final ArrayList<Double> y = new ArrayList<>();

    public void addEntry(double xVal, double yVal) {
        int pos = Collections.binarySearch(x, xVal);
        if (pos < 0) pos = -(pos + 1);
        x.add(pos, xVal);
        y.add(pos, yVal);
    }

    public double lookup(double xTarget) {
        int n = x.size();
        if (n == 0) return 0.0;
        if (xTarget <= x.get(0)) return y.get(0);
        if (xTarget >= x.get(n - 1)) return y.get(n - 1);

        for (int i = 1; i < n; i++) {
            if (x.get(i) >= xTarget) {
                double dx = x.get(i) - x.get(i - 1);
                if (dx == 0.0) return y.get(i);
                double frac = (xTarget - x.get(i - 1)) / dx;
                return y.get(i - 1)
                       + frac * (y.get(i) - y.get(i - 1));
            }
        }
        return y.get(n - 1);
    }

    public double inverseLookup(double yTarget) {
        int n = x.size();
        if (n == 0) return 0.0;
        if (yTarget <= y.get(0)) return x.get(0);
        if (yTarget >= y.get(n - 1)) return x.get(n - 1);

        for (int i = 1; i < n; i++) {
            if (y.get(i) >= yTarget) {
                double dy = y.get(i) - y.get(i - 1);
                if (dy == 0.0) return x.get(i);
                double frac = (yTarget - y.get(i - 1)) / dy;
                return x.get(i - 1)
                       + frac * (x.get(i) - x.get(i - 1));
            }
        }
        return x.get(n - 1);
    }

    public double integrate(double xMin, double xMax) {
        double area = 0.0;
        for (int i = 1; i < x.size(); i++) {
            double x0 = x.get(i - 1), x1 = x.get(i);
            if (x1 <= xMin || x0 >= xMax) continue;
            double y0 = x0 < xMin
                ? lookup(xMin) : y.get(i - 1);
            double y1 = x1 > xMax
                ? lookup(xMax) : y.get(i);
            if (x0 < xMin) x0 = xMin;
            if (x1 > xMax) x1 = xMax;
            area += 0.5 * (y0 + y1) * (x1 - x0);
        }
        return area;
    }
}`,
