    julia: `# datetime.jl — Date/Time Utilities
# SWMM5 Engine in Julia — Julian Day Conversion Module
# Calendar date to/from Julian day number with
# time arithmetic for simulation timesteps

struct DateTimeSWMM
    year::Int
    month::Int
    day::Int
    hour::Int
    minute::Int
    second::Int
end

function DateTimeSWMM(y::Int, m::Int, d::Int)
    DateTimeSWMM(y, m, d, 0, 0, 0)
end

function to_julian(dt::DateTimeSWMM)::Float64
    y, m, d = Float64(dt.year), Float64(dt.month),
              Float64(dt.day)
    jd = 367.0 * y -
         floor(7.0 * (y + floor((m + 9.0) / 12.0)) / 4.0) +
         floor(275.0 * m / 9.0) + d + 1721013.5

    jd += (dt.hour + dt.minute / 60.0 +
           dt.second / 3600.0) / 24.0
    return jd
end

function from_julian(jd::Float64)::DateTimeSWMM
    L = trunc(Int, jd + 68569.5)
    N = div(4 * L, 146097)
    L -= div(146097 * N + 3, 4)
    I = div(4000 * (L + 1), 1461001)
    L = L - div(1461 * I, 4) + 31
    J = div(80 * L, 2447)

    day = L - div(2447 * J, 80)
    ll = div(J, 11)
    month = J + 2 - 12 * ll
    year = 100 * (N - 49) + I + ll

    frac = jd - floor(jd) + 0.5
    frac >= 1.0 && (frac -= 1.0)
    hour = trunc(Int, frac * 24.0)
    minute = mod(trunc(Int, frac * 1440.0), 60)
    second = mod(trunc(Int, frac * 86400.0), 60)

    return DateTimeSWMM(year, month, day,
                        hour, minute, second)
end

add_seconds(jd::Float64, sec::Float64) = jd + sec / 86400.0
diff_hours(jd1::Float64, jd2::Float64) = (jd2 - jd1) * 24.0

function days_in_month(year::Int, month::Int)::Int
    dm = [31,28,31,30,31,30,31,31,30,31,30,31]
    (month < 1 || month > 12) && return 0
    if month == 2 && ((year % 4 == 0 && year % 100 != 0)
                      || year % 400 == 0)
        return 29
    end
    return dm[month]
end`,
    javascript: `// datetime.js — Date/Time Utilities
// SWMM5 Engine in JavaScript — Julian Day Conversion Module
// Calendar date to/from Julian day number with
// time arithmetic for simulation timesteps

class DateTimeSWMM {
    constructor(year, month, day,
                hour = 0, minute = 0, second = 0) {
        this.year = year;
        this.month = month;
        this.day = day;
        this.hour = hour;
        this.minute = minute;
        this.second = second;
    }

    toJulian() {
        const y = this.year, m = this.month, d = this.day;
        let jd = 367.0 * y
            - Math.floor(7.0 * (y + Math.floor(
                (m + 9.0) / 12.0)) / 4.0)
            + Math.floor(275.0 * m / 9.0)
            + d + 1721013.5;

        jd += (this.hour + this.minute / 60.0
               + this.second / 3600.0) / 24.0;
        return jd;
    }

    static fromJulian(jd) {
        let L = Math.trunc(jd + 68569.5);
        const N = Math.trunc(4 * L / 146097);
        L -= Math.trunc((146097 * N + 3) / 4);
        const I = Math.trunc(4000 * (L + 1) / 1461001);
        L = L - Math.trunc(1461 * I / 4) + 31;
        const J = Math.trunc(80 * L / 2447);

        const day = L - Math.trunc(2447 * J / 80);
        const ll = Math.trunc(J / 11);
        const month = J + 2 - 12 * ll;
        const year = 100 * (N - 49) + I + ll;

        let frac = jd - Math.floor(jd) + 0.5;
        if (frac >= 1.0) frac -= 1.0;
        const hour = Math.trunc(frac * 24.0);
        const minute = Math.trunc(frac * 1440.0) % 60;
        const second = Math.trunc(frac * 86400.0) % 60;

        return new DateTimeSWMM(year, month, day,
                                hour, minute, second);
    }
}

function addSeconds(jd, seconds) {
    return jd + seconds / 86400.0;
}

function diffHours(jd1, jd2) {
    return (jd2 - jd1) * 24.0;
}

function daysInMonth(year, month) {
    const days = [31,28,31,30,31,30,31,31,30,31,30,31];
    if (month < 1 || month > 12) return 0;
    if (month === 2 && ((year % 4 === 0 && year % 100 !== 0)
                        || year % 400 === 0)) return 29;
    return days[month - 1];
}

export { DateTimeSWMM, addSeconds, diffHours, daysInMonth };`,
    go: `// datetime.go — Date/Time Utilities
// SWMM5 Engine in Go — Julian Day Conversion Module
// Calendar date to/from Julian day number with
// time arithmetic for simulation timesteps

package swmm

import "math"

type DateTime struct {
    Year   int
    Month  int
    Day    int
    Hour   int
    Minute int
    Second int
}

func (dt *DateTime) ToJulian() float64 {
    y := float64(dt.Year)
    m := float64(dt.Month)
    d := float64(dt.Day)

    jd := 367.0*y -
        math.Floor(7.0*(y+math.Floor((m+9.0)/12.0))/4.0) +
        math.Floor(275.0*m/9.0) + d + 1721013.5

    jd += (float64(dt.Hour) + float64(dt.Minute)/60.0 +
        float64(dt.Second)/3600.0) / 24.0
    return jd
}

func FromJulian(jd float64) DateTime {
    L := int(jd + 68569.5)
    N := 4 * L / 146097
    L -= (146097*N + 3) / 4
    I := 4000 * (L + 1) / 1461001
    L = L - 1461*I/4 + 31
    J := 80 * L / 2447

    day := L - 2447*J/80
    ll := J / 11
    month := J + 2 - 12*ll
    year := 100*(N-49) + I + ll

    frac := jd - math.Floor(jd) + 0.5
    if frac >= 1.0 { frac -= 1.0 }
    hour := int(frac * 24.0)
    minute := int(frac*1440.0) % 60
    second := int(frac*86400.0) % 60

    return DateTime{year, month, day,
                    hour, minute, second}
}

func AddSeconds(jd, seconds float64) float64 {
    return jd + seconds/86400.0
}

func DiffHours(jd1, jd2 float64) float64 {
    return (jd2 - jd1) * 24.0
}

func DaysInMonth(year, month int) int {
    days := [12]int{31,28,31,30,31,30,31,31,30,31,30,31}
    if month < 1 || month > 12 { return 0 }
    if month == 2 && ((year%4 == 0 && year%100 != 0) ||
        year%400 == 0) { return 29 }
    return days[month-1]
}`,
    zig: `// datetime.zig — Date/Time Utilities
// SWMM5 Engine in Zig — Julian Day Conversion Module
// Calendar date to/from Julian day number with
// time arithmetic for simulation timesteps

const std = @import("std");
const math = std.math;

const DateTime = struct {
    year: i32,
    month: i32,
    day: i32,
    hour: i32 = 0,
    minute: i32 = 0,
    second: i32 = 0,

    pub fn toJulian(self: DateTime) f64 {
        const y: f64 = @floatFromInt(self.year);
        const m: f64 = @floatFromInt(self.month);
        const d: f64 = @floatFromInt(self.day);

        var jd = 367.0 * y -
            @floor(7.0 * (y + @floor((m + 9.0) / 12.0)) / 4.0) +
            @floor(275.0 * m / 9.0) + d + 1721013.5;

        const h: f64 = @floatFromInt(self.hour);
        const mn: f64 = @floatFromInt(self.minute);
        const s: f64 = @floatFromInt(self.second);
        jd += (h + mn / 60.0 + s / 3600.0) / 24.0;
        return jd;
    }

    pub fn fromJulian(jd: f64) DateTime {
        var L: i64 = @intFromFloat(jd + 68569.5);
        const N: i64 = @divTrunc(4 * L, 146097);
        L -= @divTrunc(146097 * N + 3, 4);
        const I: i64 = @divTrunc(4000 * (L + 1), 1461001);
        L = L - @divTrunc(1461 * I, 4) + 31;
        const J: i64 = @divTrunc(80 * L, 2447);

        const day: i32 = @intCast(L - @divTrunc(2447 * J, 80));
        const ll: i64 = @divTrunc(J, 11);
        const month: i32 = @intCast(J + 2 - 12 * ll);
        const year: i32 = @intCast(100 * (N - 49) + I + ll);

        var frac = jd - @floor(jd) + 0.5;
        if (frac >= 1.0) frac -= 1.0;
        const hour: i32 = @intFromFloat(frac * 24.0);
        const minute: i32 = @mod(@as(i32, @intFromFloat(frac * 1440.0)), 60);
        const second: i32 = @mod(@as(i32, @intFromFloat(frac * 86400.0)), 60);

        return DateTime{ .year = year, .month = month,
            .day = day, .hour = hour,
            .minute = minute, .second = second };
    }
};

fn addSeconds(jd: f64, seconds: f64) f64 {
    return jd + seconds / 86400.0;
}

fn diffHours(jd1: f64, jd2: f64) f64 {
    return (jd2 - jd1) * 24.0;
}

fn daysInMonth(year: i32, month: i32) i32 {
    const days = [12]i32{ 31,28,31,30,31,30,31,31,30,31,30,31 };
    if (month < 1 or month > 12) return 0;
    if (month == 2 and ((@mod(year, 4) == 0 and @mod(year, 100) != 0)
        or @mod(year, 400) == 0)) return 29;
    return days[@intCast(month - 1)];
}`,
