    r: `# datetime.R — Date/Time Utilities
# SWMM5 Engine in R — Julian Day Conversion Module
# Calendar date to/from Julian day number with
# time arithmetic for simulation timesteps

to_julian <- function(year, month, day,
                       hour = 0, minute = 0, second = 0) {
    y <- year; m <- month; d <- day
    jd <- 367 * y -
          floor(7 * (y + floor((m + 9) / 12)) / 4) +
          floor(275 * m / 9) + d + 1721013.5
    jd <- jd + (hour + minute / 60 + second / 3600) / 24
    jd
}

from_julian <- function(jd) {
    L <- as.integer(jd + 68569.5)
    N <- as.integer(4 * L / 146097)
    L <- L - as.integer((146097 * N + 3) / 4)
    I <- as.integer(4000 * (L + 1) / 1461001)
    L <- L - as.integer(1461 * I / 4) + 31L
    J <- as.integer(80 * L / 2447)

    day   <- L - as.integer(2447 * J / 80)
    ll    <- as.integer(J / 11)
    month <- J + 2L - 12L * ll
    year  <- 100L * (N - 49L) + I + ll

    frac <- jd - floor(jd) + 0.5
    if (frac >= 1.0) frac <- frac - 1.0
    hour   <- as.integer(frac * 24)
    minute <- as.integer(frac * 1440) %% 60L
    second <- as.integer(frac * 86400) %% 60L

    list(year = year, month = month, day = day,
         hour = hour, minute = minute, second = second)
}

add_seconds <- function(jd, seconds) {
    jd + seconds / 86400
}

diff_hours <- function(jd1, jd2) {
    (jd2 - jd1) * 24
}

days_in_month <- function(year, month) {
    dm <- c(31,28,31,30,31,30,31,31,30,31,30,31)
    if (month < 1 || month > 12) return(0L)
    d <- dm[month]
    if (month == 2 && ((year %% 4 == 0 && year %% 100 != 0)
                       || year %% 400 == 0))
        d <- 29L
    d
}`,
    delphi: `{ datetime.pas — Date/Time Utilities }
{ SWMM5 Engine in Delphi — Julian Day Conversion Module }
{ Calendar date to/from Julian day number with }
{ time arithmetic for simulation timesteps }

unit DateTimeUnit;

interface

type
  TDateTimeSWMM = record
    Year, Month, Day: Integer;
    Hour, Minute, Second: Integer;
  end;

function ToJulian(const DT: TDateTimeSWMM): Double;
function FromJulian(JD: Double): TDateTimeSWMM;
function AddSeconds(JD, Seconds: Double): Double;
function DiffHours(JD1, JD2: Double): Double;
function DaysInMonth(Year, Month: Integer): Integer;

implementation

uses Math;

function ToJulian(const DT: TDateTimeSWMM): Double;
var
  Y, M, D: Double;
begin
  Y := DT.Year; M := DT.Month; D := DT.Day;
  Result := 367.0 * Y
    - Floor(7.0 * (Y + Floor((M + 9.0) / 12.0)) / 4.0)
    + Floor(275.0 * M / 9.0)
    + D + 1721013.5;
  Result := Result + (DT.Hour + DT.Minute / 60.0
            + DT.Second / 3600.0) / 24.0;
end;

function FromJulian(JD: Double): TDateTimeSWMM;
var
  L, N, I, J, LL: Integer;
  Frac: Double;
begin
  L := Trunc(JD + 68569.5);
  N := 4 * L div 146097;
  L := L - (146097 * N + 3) div 4;
  I := 4000 * (L + 1) div 1461001;
  L := L - 1461 * I div 4 + 31;
  J := 80 * L div 2447;

  Result.Day   := L - 2447 * J div 80;
  LL := J div 11;
  Result.Month := J + 2 - 12 * LL;
  Result.Year  := 100 * (N - 49) + I + LL;

  Frac := JD - Floor(JD) + 0.5;
  if Frac >= 1.0 then Frac := Frac - 1.0;
  Result.Hour   := Trunc(Frac * 24.0);
  Result.Minute := Trunc(Frac * 1440.0) mod 60;
  Result.Second := Trunc(Frac * 86400.0) mod 60;
end;

function AddSeconds(JD, Seconds: Double): Double;
begin
  Result := JD + Seconds / 86400.0;
end;

function DiffHours(JD1, JD2: Double): Double;
begin
  Result := (JD2 - JD1) * 24.0;
end;

function DaysInMonth(Year, Month: Integer): Integer;
const
  DM: array[1..12] of Integer =
    (31,28,31,30,31,30,31,31,30,31,30,31);
begin
  if (Month < 1) or (Month > 12) then Exit(0);
  Result := DM[Month];
  if (Month = 2) and
     ((Year mod 4 = 0) and (Year mod 100 <> 0)
      or (Year mod 400 = 0)) then
    Result := 29;
end;

end.`,
