    java: `// DateTimeSWMM.java — Date/Time Utilities
// SWMM5 Engine in Java — Julian Day Conversion Module
// Calendar date to/from Julian day number with
// time arithmetic for simulation timesteps

public class DateTimeSWMM {
    public int year, month, day;
    public int hour, minute, second;

    public DateTimeSWMM(int year, int month, int day,
                        int hour, int minute, int second) {
        this.year = year;   this.month = month;
        this.day = day;     this.hour = hour;
        this.minute = minute; this.second = second;
    }

    public DateTimeSWMM(int year, int month, int day) {
        this(year, month, day, 0, 0, 0);
    }

    public double toJulian() {
        double y = year, m = month, d = day;
        double jd = 367.0 * y
            - Math.floor(7.0 * (y + Math.floor(
                (m + 9.0) / 12.0)) / 4.0)
            + Math.floor(275.0 * m / 9.0)
            + d + 1721013.5;

        jd += (hour + minute / 60.0
               + second / 3600.0) / 24.0;
        return jd;
    }

    public static DateTimeSWMM fromJulian(double jd) {
        int L = (int)(jd + 68569.5);
        int N = 4 * L / 146097;
        L -= (146097 * N + 3) / 4;
        int I = 4000 * (L + 1) / 1461001;
        L = L - 1461 * I / 4 + 31;
        int J = 80 * L / 2447;

        int day = L - 2447 * J / 80;
        int ll = J / 11;
        int month = J + 2 - 12 * ll;
        int year = 100 * (N - 49) + I + ll;

        double frac = jd - Math.floor(jd) + 0.5;
        if (frac >= 1.0) frac -= 1.0;
        int hour = (int)(frac * 24.0);
        int minute = (int)(frac * 1440.0) % 60;
        int second = (int)(frac * 86400.0) % 60;

        return new DateTimeSWMM(year, month, day,
                                hour, minute, second);
    }

    public static double addSeconds(double jd, double sec) {
        return jd + sec / 86400.0;
    }

    public static double diffHours(double jd1, double jd2) {
        return (jd2 - jd1) * 24.0;
    }

    public static int daysInMonth(int year, int month) {
        int[] days = {31,28,31,30,31,30,31,31,30,31,30,31};
        if (month < 1 || month > 12) return 0;
        if (month == 2 && ((year % 4 == 0 && year % 100 != 0)
                           || year % 400 == 0)) return 29;
        return days[month - 1];
    }
}`,
