    ada: `-- datetime.adb — Date/Time Utilities
-- SWMM5 Engine in Ada — Julian Day Conversion Module
-- Calendar date to/from Julian day number with
-- time arithmetic for simulation timesteps

with Ada.Numerics.Elementary_Functions;
use Ada.Numerics.Elementary_Functions;

package body DateTime_Pkg is

   type DateTime_SWMM is record
      Year, Month, Day    : Integer;
      Hour, Minute, Second : Integer := 0;
   end record;

   function To_Julian (DT : DateTime_SWMM) return Long_Float is
      Y : Long_Float := Long_Float (DT.Year);
      M : Long_Float := Long_Float (DT.Month);
      D : Long_Float := Long_Float (DT.Day);
      JD : Long_Float;
   begin
      JD := 367.0 * Y
          - Long_Float'Floor (7.0 * (Y + Long_Float'Floor (
              (M + 9.0) / 12.0)) / 4.0)
          + Long_Float'Floor (275.0 * M / 9.0)
          + D + 1721013.5;

      JD := JD + (Long_Float (DT.Hour)
            + Long_Float (DT.Minute) / 60.0
            + Long_Float (DT.Second) / 3600.0) / 24.0;
      return JD;
   end To_Julian;

   function From_Julian (JD : Long_Float) return DateTime_SWMM is
      DT : DateTime_SWMM;
      L, N, I, J, LL : Integer;
      Frac : Long_Float;
   begin
      L := Integer (JD + 68569.5);
      N := 4 * L / 146097;
      L := L - (146097 * N + 3) / 4;
      I := 4000 * (L + 1) / 1461001;
      L := L - 1461 * I / 4 + 31;
      J := 80 * L / 2447;

      DT.Day   := L - 2447 * J / 80;
      LL       := J / 11;
      DT.Month := J + 2 - 12 * LL;
      DT.Year  := 100 * (N - 49) + I + LL;

      Frac := JD - Long_Float'Floor (JD) + 0.5;
      if Frac >= 1.0 then Frac := Frac - 1.0; end if;
      DT.Hour   := Integer (Frac * 24.0);
      DT.Minute := Integer (Frac * 1440.0) mod 60;
      DT.Second := Integer (Frac * 86400.0) mod 60;
      return DT;
   end From_Julian;

   function Add_Seconds (JD, Seconds : Long_Float)
      return Long_Float is
   begin
      return JD + Seconds / 86400.0;
   end Add_Seconds;

   function Diff_Hours (JD1, JD2 : Long_Float)
      return Long_Float is
   begin
      return (JD2 - JD1) * 24.0;
   end Diff_Hours;

end DateTime_Pkg;`,
