    go: `// exfil.go — Conduit Exfiltration
// SWMM5 Engine in Go — Green-Ampt Based Seepage Model
// Computes exfiltration rate from conduits into
// surrounding soil via wetted perimeter

package swmm

import "math"

type Exfil struct {
    SoilK      float64 // hydraulic conductivity (ft/s)
    CapSuction float64 // capillary suction head (ft)
    Porosity   float64 // soil porosity
    InitMoist  float64 // initial soil moisture
    CumExfil   float64 // cumulative exfiltration (ft)
}

func WettedArea(diameter, depth float64) float64 {
    if depth <= 0.0 {
        return 0.0
    }
    if depth >= diameter {
        return math.Pi * diameter
    }
    theta := 2.0 * math.Acos(1.0-2.0*depth/diameter)
    return 0.5 * diameter * theta
}

func (e *Exfil) GetRate() float64 {
    dTheta := e.Porosity - e.InitMoist
    if dTheta <= 0.0 {
        return e.SoilK
    }
    cum := math.Max(e.CumExfil, 1.0e-6)
    return e.SoilK * (1.0 + e.CapSuction*dTheta/cum)
}

func (e *Exfil) Update(rate, dt float64) {
    e.CumExfil += rate * dt
    if e.CumExfil < 0.0 {
        e.CumExfil = 0.0
    }
}

func (e *Exfil) GetLoss(diameter, depth,
    length, dt float64) float64 {
    wArea := WettedArea(diameter, depth)
    rate := e.GetRate()
    loss := rate * wArea * length * dt
    e.Update(rate, dt)
    return loss
}`,
