    julia: `# lidproc.jl — LID Process Simulation
# SWMM5 Engine in Julia — Layered Green Infrastructure
# Routes flow through surface, soil, storage, and drain
# layers using Manning, Green-Ampt, and orifice equations

mutable struct LIDLayer
    thickness::Float64
    voidFrac::Float64
    moisture::Float64
end

mutable struct LIDProc
    surface::LIDLayer
    soil::LIDLayer
    storage::LIDLayer
    drainCoeff::Float64
    drainExpon::Float64
    surfSlope::Float64
    surfRough::Float64
    soilK::Float64
    soilPsi::Float64
    surfWidth::Float64
end

function surface_outflow(lid::LIDProc)::Float64
    d = lid.surface.moisture
    d <= 0.0 && return 0.0
    (lid.surfWidth / lid.surfRough) *
        sqrt(lid.surfSlope) * d^(5.0/3.0)
end

function soil_perc(lid::LIDProc)::Float64
    dθ = lid.soil.voidFrac - lid.soil.moisture
    dθ <= 0.0 && return lid.soilK
    cumF = max(lid.soil.moisture * lid.soil.thickness,
               1.0e-6)
    lid.soilK * (1.0 + lid.soilPsi * dθ / cumF)
end

function drain_flow(lid::LIDProc)::Float64
    head = lid.storage.moisture * lid.storage.thickness
    head <= 0.0 && return 0.0
    lid.drainCoeff * head^lid.drainExpon
end

function route_flow!(lid::LIDProc, rainfall::Float64,
                     dt::Float64)
    surfVol = lid.surface.thickness * lid.surface.voidFrac
    lid.surface.moisture += rainfall * dt / surfVol

    surfOut = surface_outflow(lid) * dt
    lid.surface.moisture -= surfOut / surfVol
    lid.surface.moisture = max(lid.surface.moisture, 0.0)

    perc = soil_perc(lid) * dt
    lid.soil.moisture += perc / lid.soil.thickness
    lid.soil.moisture = min(lid.soil.moisture,
                            lid.soil.voidFrac)

    drn = drain_flow(lid) * dt
    storVol = lid.storage.thickness * lid.storage.voidFrac
    lid.storage.moisture -= drn / storVol
    lid.storage.moisture = max(lid.storage.moisture, 0.0)
end`,
