    cpp: `// lidproc.cpp — LID Process Simulation
// SWMM5 Engine in C++ — Layered Green Infrastructure
// Routes flow through surface, soil, storage, and drain
// layers using Manning, Green-Ampt, and orifice equations

#include <cmath>
#include <algorithm>

namespace swmm {

struct LIDLayer {
    double thickness;
    double voidFrac;
    double moisture = 0.0;
};

struct LIDProc {
    LIDLayer surface;
    LIDLayer soil;
    LIDLayer storage;
    double drainCoeff;
    double drainExpon;
    double surfSlope;
    double surfRough;
    double soilK;
    double soilPsi;
    double surfWidth;

    double surfaceOutflow() const {
        double d = surface.moisture;
        if (d <= 0.0) return 0.0;
        return (surfWidth / surfRough)
               * std::sqrt(surfSlope)
               * std::pow(d, 5.0 / 3.0);
    }

    double soilPerc() const {
        double dTheta = soil.voidFrac - soil.moisture;
        if (dTheta <= 0.0) return soilK;
        double cumF = std::max(soil.moisture
                      * soil.thickness, 1.0e-6);
        return soilK * (1.0 + soilPsi * dTheta / cumF);
    }

    double drainFlow() const {
        double head = storage.moisture
                      * storage.thickness;
        if (head <= 0.0) return 0.0;
        return drainCoeff * std::pow(head, drainExpon);
    }

    void routeFlow(double rainfall, double dt) {
        double surfVol = surface.thickness
                         * surface.voidFrac;
        surface.moisture += rainfall * dt / surfVol;

        double surfOut = surfaceOutflow() * dt;
        surface.moisture -= surfOut / surfVol;
        surface.moisture = std::max(surface.moisture, 0.0);

        double perc = soilPerc() * dt;
        soil.moisture += perc / soil.thickness;
        soil.moisture = std::min(soil.moisture,
                                 soil.voidFrac);

        double drn = drainFlow() * dt;
        double storVol = storage.thickness
                         * storage.voidFrac;
        storage.moisture -= drn / storVol;
        storage.moisture = std::max(storage.moisture, 0.0);
    }
};

} // namespace swmm`,
    csharp: `// LIDProc.cs — LID Process Simulation
// SWMM5 Engine in C# — Layered Green Infrastructure
// Routes flow through surface, soil, storage, and drain
// layers using Manning, Green-Ampt, and orifice equations

using System;

namespace Swmm
{
    public class LIDLayer
    {
        public double Thickness { get; set; }
        public double VoidFrac { get; set; }
        public double Moisture { get; set; }

        public LIDLayer(double thickness,
                        double voidFrac,
                        double moisture = 0.0)
        {
            Thickness = thickness;
            VoidFrac = voidFrac;
            Moisture = moisture;
        }
    }

    public class LIDProc
    {
        public LIDLayer Surface { get; set; }
        public LIDLayer Soil { get; set; }
        public LIDLayer Storage { get; set; }
        public double DrainCoeff { get; set; }
        public double DrainExpon { get; set; }
        public double SurfSlope { get; set; }
        public double SurfRough { get; set; }
        public double SoilK { get; set; }
        public double SoilPsi { get; set; }
        public double SurfWidth { get; set; }

        public double SurfaceOutflow()
        {
            double d = Surface.Moisture;
            if (d <= 0.0) return 0.0;
            return (SurfWidth / SurfRough)
                   * Math.Sqrt(SurfSlope)
                   * Math.Pow(d, 5.0 / 3.0);
        }

        public double SoilPerc()
        {
            double dTheta = Soil.VoidFrac - Soil.Moisture;
            if (dTheta <= 0.0) return SoilK;
            double cumF = Math.Max(Soil.Moisture
                          * Soil.Thickness, 1.0e-6);
            return SoilK * (1.0 + SoilPsi
                            * dTheta / cumF);
        }

        public double DrainFlow()
        {
            double head = Storage.Moisture
                          * Storage.Thickness;
            if (head <= 0.0) return 0.0;
            return DrainCoeff
                   * Math.Pow(head, DrainExpon);
        }

        public void RouteFlow(double rainfall, double dt)
        {
            double surfVol = Surface.Thickness
                             * Surface.VoidFrac;
            Surface.Moisture += rainfall * dt / surfVol;

            double surfOut = SurfaceOutflow() * dt;
            Surface.Moisture -= surfOut / surfVol;
            Surface.Moisture = Math.Max(
                Surface.Moisture, 0.0);

            double perc = SoilPerc() * dt;
            Soil.Moisture += perc / Soil.Thickness;
            Soil.Moisture = Math.Min(
                Soil.Moisture, Soil.VoidFrac);

            double drn = DrainFlow() * dt;
            double storVol = Storage.Thickness
                             * Storage.VoidFrac;
            Storage.Moisture -= drn / storVol;
            Storage.Moisture = Math.Max(
                Storage.Moisture, 0.0);
        }
    }
}`,
