    ada: `-- lidproc.adb — LID Process Simulation
-- SWMM5 Engine in Ada — Layered Green Infrastructure
-- Routes flow through surface, soil, storage, and drain
-- layers using Manning, Green-Ampt, and orifice equations

with Ada.Numerics.Elementary_Functions;
use  Ada.Numerics.Elementary_Functions;

package body LIDProc_Pkg is

   type LID_Layer is record
      Thickness : Long_Float;
      Void_Frac : Long_Float;
      Moisture  : Long_Float := 0.0;
   end record;

   type LID_Proc is record
      Surface     : LID_Layer;
      Soil        : LID_Layer;
      Storage     : LID_Layer;
      Drain_Coeff : Long_Float;
      Drain_Expon : Long_Float;
      Surf_Slope  : Long_Float;
      Surf_Rough  : Long_Float;
      Soil_K      : Long_Float;
      Soil_Psi    : Long_Float;
      Surf_Width  : Long_Float;
   end record;

   function Surface_Outflow(L : LID_Proc)
                            return Long_Float is
      D : Long_Float := L.Surface.Moisture;
   begin
      if D <= 0.0 then return 0.0; end if;
      return (L.Surf_Width / L.Surf_Rough)
             * Sqrt(L.Surf_Slope)
             * D ** (5.0 / 3.0);
   end Surface_Outflow;

   function Soil_Perc(L : LID_Proc)
                      return Long_Float is
      D_Theta : Long_Float;
      Cum_F   : Long_Float;
   begin
      D_Theta := L.Soil.Void_Frac - L.Soil.Moisture;
      if D_Theta <= 0.0 then return L.Soil_K; end if;
      Cum_F := Long_Float'Max(
          L.Soil.Moisture * L.Soil.Thickness, 1.0E-6);
      return L.Soil_K * (1.0 + L.Soil_Psi
                         * D_Theta / Cum_F);
   end Soil_Perc;

   function Drain_Flow(L : LID_Proc)
                       return Long_Float is
      Head : Long_Float;
   begin
      Head := L.Storage.Moisture * L.Storage.Thickness;
      if Head <= 0.0 then return 0.0; end if;
      return L.Drain_Coeff * Head ** L.Drain_Expon;
   end Drain_Flow;

   procedure Route_Flow(L        : in out LID_Proc;
                        Rainfall : Long_Float;
                        Dt       : Long_Float) is
      Surf_Vol, S_Out, Perc, Drn, Stor_Vol : Long_Float;
   begin
      Surf_Vol := L.Surface.Thickness * L.Surface.Void_Frac;
      L.Surface.Moisture := L.Surface.Moisture
          + Rainfall * Dt / Surf_Vol;
      S_Out := Surface_Outflow(L) * Dt;
      L.Surface.Moisture := L.Surface.Moisture
          - S_Out / Surf_Vol;
      L.Surface.Moisture := Long_Float'Max(
          L.Surface.Moisture, 0.0);

      Perc := Soil_Perc(L) * Dt;
      L.Soil.Moisture := L.Soil.Moisture
          + Perc / L.Soil.Thickness;
      L.Soil.Moisture := Long_Float'Min(
          L.Soil.Moisture, L.Soil.Void_Frac);

      Drn := Drain_Flow(L) * Dt;
      Stor_Vol := L.Storage.Thickness * L.Storage.Void_Frac;
      L.Storage.Moisture := L.Storage.Moisture
          - Drn / Stor_Vol;
      L.Storage.Moisture := Long_Float'Max(
          L.Storage.Moisture, 0.0);
   end Route_Flow;

end LIDProc_Pkg;`,
