    cuda: `// toposort.cu — Topological Sorting of Network
// SWMM5 Engine in CUDA — Kahn's Algorithm for DAG
// Determines upstream-to-downstream processing order
// for nodes in the drainage network graph

#include <stdio.h>
#include <string.h>

#define MAX_NODES 1024
#define MAX_EDGES 4096

struct Graph {
    int adjFrom[MAX_EDGES];
    int adjTo[MAX_EDGES];
    int inDegree[MAX_NODES];
    int edgeCount;
    int nodeCount;
};

__global__ void initDegreesKernel(int* inDeg,
    const int* adjTo, int edgeCount,
    int nodeCount)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= nodeCount) return;
    inDeg[idx] = 0;
}

__global__ void countDegreesKernel(int* inDeg,
    const int* adjTo, int edgeCount)
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= edgeCount) return;
    atomicAdd(&inDeg[adjTo[idx]], 1);
}

void graph_init(Graph* g, int nodeCount)
{
    g->nodeCount = nodeCount;
    g->edgeCount = 0;
    memset(g->inDegree, 0, sizeof(int) * nodeCount);
}

void graph_addEdge(Graph* g, int from, int to)
{
    g->adjFrom[g->edgeCount] = from;
    g->adjTo[g->edgeCount] = to;
    g->edgeCount++;
    g->inDegree[to]++;
}

int graph_topoSort(Graph* g, int* sorted)
{
    int queue[MAX_NODES];
    int front = 0, rear = 0, count = 0;
    int tempDeg[MAX_NODES];

    memcpy(tempDeg, g->inDegree,
           sizeof(int) * g->nodeCount);

    for (int i = 0; i < g->nodeCount; i++)
        if (tempDeg[i] == 0) queue[rear++] = i;

    while (front < rear) {
        int u = queue[front++];
        sorted[count++] = u;

        for (int i = 0; i < g->edgeCount; i++) {
            if (g->adjFrom[i] == u) {
                int v = g->adjTo[i];
                tempDeg[v]--;
                if (tempDeg[v] == 0)
                    queue[rear++] = v;
            }
        }
    }
    return count;
}

int graph_isDAG(Graph* g) {
    int sorted[MAX_NODES];
    return graph_topoSort(g, sorted) == g->nodeCount;
}`,
