    zig: `// hash.zig — Hash Table
// SWMM5 Engine in Zig — Hash Table with Separate Chaining
// Implements djb2 hashing with linked-list buckets
// for efficient key-value storage and lookup

const std = @import("std");

const TABLE_SIZE: usize = 256;

const HashEntry = struct {
    key: []const u8,
    value: i32,
    next: ?*HashEntry,
};

const HashTable = struct {
    buckets: [TABLE_SIZE]?*HashEntry,
    count: usize,
    allocator: std.mem.Allocator,

    pub fn init(alloc: std.mem.Allocator) HashTable {
        return HashTable{
            .buckets = [_]?*HashEntry{null} ** TABLE_SIZE,
            .count = 0,
            .allocator = alloc,
        };
    }

    fn hashFunc(key: []const u8) usize {
        var h: u64 = 5381;
        for (key) |c| {
            h = ((h << 5) +% h) +% @as(u64, c);
        }
        return @intCast(h % TABLE_SIZE);
    }

    pub fn insert(self: *HashTable, key: []const u8,
                  value: i32) !void {
        const idx = hashFunc(key);
        var entry = self.buckets[idx];
        while (entry) |e| {
            if (std.mem.eql(u8, e.key, key)) {
                e.value = value;
                return;
            }
            entry = e.next;
        }
        const new_entry = try self.allocator.create(HashEntry);
        new_entry.* = .{
            .key = key,
            .value = value,
            .next = self.buckets[idx],
        };
        self.buckets[idx] = new_entry;
        self.count += 1;
    }

    pub fn find(self: *const HashTable,
                key: []const u8) ?i32 {
        const idx = hashFunc(key);
        var entry = self.buckets[idx];
        while (entry) |e| {
            if (std.mem.eql(u8, e.key, key))
                return e.value;
            entry = e.next;
        }
        return null;
    }
};`,
    cpp: `// hash.cpp — Hash Table
// SWMM5 Engine in C++ — Hash Table with Separate Chaining
// Implements djb2 hashing with linked-list buckets
// for efficient key-value storage and lookup

#include <string>
#include <vector>
#include <memory>

namespace swmm {

constexpr int TABLE_SIZE = 256;

struct HashEntry {
    std::string key;
    int value;
    std::unique_ptr<HashEntry> next;

    HashEntry(const std::string& k, int v,
              std::unique_ptr<HashEntry> n = nullptr)
        : key(k), value(v), next(std::move(n)) {}
};

class HashTable {
    std::vector<std::unique_ptr<HashEntry>> buckets_;
    int count_ = 0;

    static size_t hashFunc(const std::string& key) {
        unsigned long h = 5381;
        for (char c : key)
            h = ((h << 5) + h) + static_cast<unsigned>(c);
        return h % TABLE_SIZE;
    }

public:
    HashTable() : buckets_(TABLE_SIZE) {}

    void insert(const std::string& key, int value) {
        size_t idx = hashFunc(key);
        HashEntry* e = buckets_[idx].get();
        while (e) {
            if (e->key == key) { e->value = value; return; }
            e = e->next.get();
        }
        buckets_[idx] = std::make_unique<HashEntry>(
            key, value, std::move(buckets_[idx]));
        count_++;
    }

    bool find(const std::string& key, int& value) const {
        size_t idx = hashFunc(key);
        const HashEntry* e = buckets_[idx].get();
        while (e) {
            if (e->key == key) { value = e->value; return true; }
            e = e->next.get();
        }
        return false;
    }

    int count() const { return count_; }
};

} // namespace swmm`,
