    c: `// mempool.c — Memory Pool Allocator
// EPA SWMM5 Engine — Arena/Bump Allocator
// Pre-allocates blocks and serves requests by
// advancing an offset pointer within each block

#include <stdlib.h>
#include <string.h>

#define MAX_BLOCKS 64

typedef struct {
    size_t blockSize;
    size_t freeOffset;
    int    currentBlock;
    int    numBlocks;
    char*  blocks[MAX_BLOCKS];
    size_t totalUsed;
} MemPool;

int mempool_init(MemPool* pool, size_t blockSize)
{
    pool->blockSize = blockSize;
    pool->freeOffset = 0;
    pool->currentBlock = 0;
    pool->numBlocks = 1;
    pool->totalUsed = 0;
    pool->blocks[0] = (char*)malloc(blockSize);
    if (!pool->blocks[0]) return 0;
    memset(pool->blocks[0], 0, blockSize);
    return 1;
}

static int mempool_newBlock(MemPool* pool)
{
    if (pool->numBlocks >= MAX_BLOCKS) return 0;
    pool->blocks[pool->numBlocks] =
        (char*)malloc(pool->blockSize);
    if (!pool->blocks[pool->numBlocks]) return 0;
    memset(pool->blocks[pool->numBlocks], 0,
           pool->blockSize);
    pool->currentBlock = pool->numBlocks;
    pool->numBlocks++;
    pool->freeOffset = 0;
    return 1;
}

void* mempool_alloc(MemPool* pool, size_t size)
{
    void* ptr;
    size = (size + 7) & ~7;

    if (pool->freeOffset + size > pool->blockSize) {
        if (!mempool_newBlock(pool)) return NULL;
    }

    ptr = pool->blocks[pool->currentBlock]
          + pool->freeOffset;
    pool->freeOffset += size;
    pool->totalUsed += size;
    return ptr;
}

void mempool_reset(MemPool* pool)
{
    pool->currentBlock = 0;
    pool->freeOffset = 0;
    pool->totalUsed = 0;
}

size_t mempool_getUsed(MemPool* pool)
{
    return pool->totalUsed;
}

void mempool_destroy(MemPool* pool)
{
    int i;
    for (i = 0; i < pool->numBlocks; i++)
        free(pool->blocks[i]);
    pool->numBlocks = 0;
}`,
    rust: `// mempool.rs — Memory Pool Allocator
// SWMM5 Engine in Rust — Arena/Bump Allocator
// Pre-allocates blocks and serves requests by
// advancing an offset pointer within each block

const MAX_BLOCKS: usize = 64;

pub struct MemPool {
    block_size: usize,
    free_offset: usize,
    current_block: usize,
    blocks: Vec<Vec<u8>>,
    total_used: usize,
}

impl MemPool {
    pub fn new(block_size: usize) -> Self {
        let block = vec![0u8; block_size];
        MemPool {
            block_size,
            free_offset: 0,
            current_block: 0,
            blocks: vec![block],
            total_used: 0,
        }
    }

    fn new_block(&mut self) -> bool {
        if self.blocks.len() >= MAX_BLOCKS {
            return false;
        }
        let block = vec![0u8; self.block_size];
        self.blocks.push(block);
        self.current_block = self.blocks.len() - 1;
        self.free_offset = 0;
        true
    }

    pub fn alloc(&mut self, size: usize) -> Option<usize> {
        let aligned = (size + 7) & !7;
        if self.free_offset + aligned > self.block_size {
            if !self.new_block() {
                return None;
            }
        }
        let offset = self.free_offset;
        self.free_offset += aligned;
        self.total_used += aligned;
        Some(offset)
    }

    pub fn get_slice(&self, block: usize,
                     offset: usize, size: usize) -> &[u8] {
        &self.blocks[block][offset..offset + size]
    }

    pub fn reset(&mut self) {
        self.current_block = 0;
        self.free_offset = 0;
        self.total_used = 0;
    }

    pub fn get_used(&self) -> usize {
        self.total_used
    }

    pub fn num_blocks(&self) -> usize {
        self.blocks.len()
    }
}`,
    python: `# mempool.py — Memory Pool Allocator
# SWMM5 Engine in Python — Arena/Bump Allocator
# Pre-allocates blocks and serves requests by
# advancing an offset pointer within each block

MAX_BLOCKS = 64

class MemPool:
    def __init__(self, block_size: int = 65536):
        self.block_size = block_size
        self.free_offset = 0
        self.current_block = 0
        self.blocks = [bytearray(block_size)]
        self.total_used = 0

    def _new_block(self) -> bool:
        if len(self.blocks) >= MAX_BLOCKS:
            return False
        self.blocks.append(bytearray(self.block_size))
        self.current_block = len(self.blocks) - 1
        self.free_offset = 0
        return True

    def alloc(self, size: int) -> tuple:
        aligned = (size + 7) & ~7
        if self.free_offset + aligned > self.block_size:
            if not self._new_block():
                return None
        block_idx = self.current_block
        offset = self.free_offset
        self.free_offset += aligned
        self.total_used += aligned
        return (block_idx, offset)

    def write(self, block_idx: int, offset: int,
              data: bytes):
        end = offset + len(data)
        self.blocks[block_idx][offset:end] = data

    def read(self, block_idx: int, offset: int,
             size: int) -> bytes:
        return bytes(
            self.blocks[block_idx][offset:offset + size])

    def reset(self):
        self.current_block = 0
        self.free_offset = 0
        self.total_used = 0

    def get_used(self) -> int:
        return self.total_used

    def num_blocks(self) -> int:
        return len(self.blocks)

    def destroy(self):
        self.blocks.clear()
        self.total_used = 0
        self.free_offset = 0`,
