    ada: `-- mempool.adb — Memory Pool Allocator
-- SWMM5 Engine in Ada — Arena/Bump Allocator
-- Pre-allocates blocks and serves requests by
-- advancing an offset pointer within each block

with Ada.Unchecked_Deallocation;

package Mem_Pools is

   Max_Blocks : constant := 64;
   type Byte is mod 256;
   type Byte_Array is array (Natural range <>) of Byte;
   type Byte_Array_Ptr is access Byte_Array;

   type Block_Array is array (0 .. Max_Blocks - 1)
      of Byte_Array_Ptr;

   type Mem_Pool is record
      Block_Size    : Natural;
      Free_Offset   : Natural := 0;
      Current_Block : Natural := 0;
      Num_Blocks    : Natural := 0;
      Total_Used    : Natural := 0;
      Blocks        : Block_Array := (others => null);
   end record;

   procedure Init (Pool : in out Mem_Pool;
                   Block_Size : Natural) is
   begin
      Pool.Block_Size := Block_Size;
      Pool.Free_Offset := 0;
      Pool.Current_Block := 0;
      Pool.Num_Blocks := 1;
      Pool.Total_Used := 0;
      Pool.Blocks (0) :=
         new Byte_Array (0 .. Block_Size - 1);
      Pool.Blocks (0).all := (others => 0);
   end Init;

   function New_Block (Pool : in out Mem_Pool)
      return Boolean is
   begin
      if Pool.Num_Blocks >= Max_Blocks then
         return False;
      end if;
      Pool.Blocks (Pool.Num_Blocks) :=
         new Byte_Array (0 .. Pool.Block_Size - 1);
      Pool.Blocks (Pool.Num_Blocks).all := (others => 0);
      Pool.Current_Block := Pool.Num_Blocks;
      Pool.Num_Blocks := Pool.Num_Blocks + 1;
      Pool.Free_Offset := 0;
      return True;
   end New_Block;

   function Alloc (Pool : in out Mem_Pool;
                   Size : Natural) return Natural is
      Aligned : Natural;
      Offset  : Natural;
   begin
      Aligned := (Size + 7) / 8 * 8;
      if Pool.Free_Offset + Aligned > Pool.Block_Size then
         if not New_Block (Pool) then
            return Natural'Last;
         end if;
      end if;
      Offset := Pool.Free_Offset;
      Pool.Free_Offset := Pool.Free_Offset + Aligned;
      Pool.Total_Used := Pool.Total_Used + Aligned;
      return Offset;
   end Alloc;

   procedure Reset (Pool : in out Mem_Pool) is
   begin
      Pool.Current_Block := 0;
      Pool.Free_Offset := 0;
      Pool.Total_Used := 0;
   end Reset;

   function Get_Used (Pool : Mem_Pool) return Natural is
   begin
      return Pool.Total_Used;
   end Get_Used;

end Mem_Pools;`,
