    r: `# keywords.R — Keyword/Token Lookup
# SWMM5 Engine in R — INP Section Keyword Matcher
# Manages a table of SWMM section keywords and
# provides case-insensitive lookup for the parser

MAX_KEYWORDS <- 64L

SWMM_DEFAULTS <- c(
    "TITLE", "OPTIONS", "RAINGAGES",
    "SUBCATCHMENTS", "SUBAREAS", "INFILTRATION",
    "JUNCTIONS", "OUTFALLS", "STORAGE",
    "CONDUITS", "PUMPS", "ORIFICES",
    "WEIRS", "XSECTIONS", "TRANSECTS",
    "CONTROLS", "DWF", "CURVES",
    "TIMESERIES", "REPORT", "MAP",
    "COORDINATES", "VERTICES", "LABELS"
)

keywords_create <- function(use_defaults = TRUE) {
    list(
        words = if (use_defaults) SWMM_DEFAULTS
                else character(0),
        max_keywords = MAX_KEYWORDS
    )
}

keywords_find <- function(kt, token) {
    lower_token <- tolower(trimws(token))
    matches <- which(tolower(kt$words) == lower_token)
    if (length(matches) > 0) return(matches[1])
    return(-1L)
}

keywords_add <- function(kt, word) {
    if (length(kt$words) >= kt$max_keywords) {
        return(list(kt = kt, ok = FALSE))
    }
    kt$words <- c(kt$words, word)
    list(kt = kt, ok = TRUE)
}

keywords_get_count <- function(kt) {
    length(kt$words)
}

keywords_get_word <- function(kt, index) {
    if (index >= 1 && index <= length(kt$words))
        return(kt$words[index])
    return("")
}

keywords_contains <- function(kt, token) {
    keywords_find(kt, token) > 0
}

keywords_remove <- function(kt, token) {
    idx <- keywords_find(kt, token)
    if (idx > 0) {
        kt$words <- kt$words[-idx]
        return(list(kt = kt, ok = TRUE))
    }
    list(kt = kt, ok = FALSE)
}`,
    delphi: `{ keywords.pas — Keyword/Token Lookup }
{ SWMM5 Engine in Delphi — INP Section Keyword Matcher }
{ Manages a table of SWMM section keywords and }
{ provides case-insensitive lookup for the parser }

unit KeywordsUnit;

interface

const
  MAX_KEYWORDS = 64;

type
  TKeywordTable = class
  private
    FWords: array of string;
    FCount: Integer;
  public
    constructor Create(UseDefaults: Boolean = True);
    function Find(const Token: string): Integer;
    function Add(const Word: string): Boolean;
    function GetCount: Integer;
    function GetWord(Index: Integer): string;
    function Contains(const Token: string): Boolean;
    function Remove(const Token: string): Boolean;
  end;

implementation

uses SysUtils;

constructor TKeywordTable.Create(UseDefaults: Boolean);
const
  Defaults: array[0..23] of string = (
    'TITLE', 'OPTIONS', 'RAINGAGES',
    'SUBCATCHMENTS', 'SUBAREAS', 'INFILTRATION',
    'JUNCTIONS', 'OUTFALLS', 'STORAGE',
    'CONDUITS', 'PUMPS', 'ORIFICES',
    'WEIRS', 'XSECTIONS', 'TRANSECTS',
    'CONTROLS', 'DWF', 'CURVES',
    'TIMESERIES', 'REPORT', 'MAP',
    'COORDINATES', 'VERTICES', 'LABELS');
var
  I: Integer;
begin
  inherited Create;
  FCount := 0;
  SetLength(FWords, MAX_KEYWORDS);
  if UseDefaults then begin
    for I := 0 to High(Defaults) do begin
      FWords[FCount] := Defaults[I];
      Inc(FCount);
    end;
  end;
end;

function TKeywordTable.Find(const Token: string): Integer;
var
  I: Integer;
  Lower: string;
begin
  Lower := LowerCase(Trim(Token));
  for I := 0 to FCount - 1 do begin
    if LowerCase(FWords[I]) = Lower then
      Exit(I);
  end;
  Result := -1;
end;

function TKeywordTable.Add(const Word: string): Boolean;
begin
  if FCount >= MAX_KEYWORDS then Exit(False);
  FWords[FCount] := Word;
  Inc(FCount);
  Result := True;
end;

function TKeywordTable.GetCount: Integer;
begin
  Result := FCount;
end;

function TKeywordTable.GetWord(Index: Integer): string;
begin
  if (Index >= 0) and (Index < FCount) then
    Result := FWords[Index]
  else
    Result := '';
end;

function TKeywordTable.Contains(
    const Token: string): Boolean;
begin
  Result := Find(Token) >= 0;
end;

function TKeywordTable.Remove(
    const Token: string): Boolean;
var
  Idx, I: Integer;
begin
  Idx := Find(Token);
  if Idx < 0 then Exit(False);
  for I := Idx to FCount - 2 do
    FWords[I] := FWords[I + 1];
  Dec(FCount);
  Result := True;
end;

end.`,
