    cuda: `// keywords.cu — Keyword/Token Lookup
// SWMM5 Engine in CUDA — Parallel Keyword Search
// Performs GPU-accelerated keyword matching for
// batch processing of SWMM INP tokens

#include <stdio.h>
#include <string.h>

#define MAX_KEYWORDS 64
#define MAX_KEYLEN   32

struct KeywordTable {
    char words[MAX_KEYWORDS][MAX_KEYLEN];
    int count;
};

__device__ char d_toLower(char c) {
    if (c >= 'A' && c <= 'Z') return c + 32;
    return c;
}

__device__ int d_strEqualCI(const char* a, const char* b)
{
    int i = 0;
    while (a[i] && b[i]) {
        if (d_toLower(a[i]) != d_toLower(b[i]))
            return 0;
        i++;
    }
    return (a[i] == 0 && b[i] == 0) ? 1 : 0;
}

__device__ int d_keywordFind(KeywordTable* kt,
                              const char* token)
{
    for (int i = 0; i < kt->count; i++) {
        if (d_strEqualCI(kt->words[i], token))
            return i;
    }
    return -1;
}

__global__ void keywordSearchKernel(
    KeywordTable* kt,
    char tokens[][MAX_KEYLEN],
    int* results, int n)
{
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    if (tid >= n) return;
    results[tid] = d_keywordFind(kt, tokens[tid]);
}

void keywords_init(KeywordTable* kt) {
    const char* defaults[] = {
        "TITLE", "OPTIONS", "RAINGAGES",
        "SUBCATCHMENTS", "SUBAREAS", "INFILTRATION",
        "JUNCTIONS", "OUTFALLS", "STORAGE",
        "CONDUITS", "PUMPS", "ORIFICES",
        "WEIRS", "XSECTIONS", "TRANSECTS",
        "CONTROLS", "DWF", "CURVES",
        "TIMESERIES", "REPORT", "MAP",
        "COORDINATES", "VERTICES", "LABELS"
    };
    kt->count = 24;
    for (int i = 0; i < kt->count; i++)
        strncpy(kt->words[i], defaults[i], MAX_KEYLEN);
}`,
    wasm: `;; keywords.wat — Keyword/Token Lookup
;; SWMM5 Engine in WebAssembly — Keyword Matching
;; Case-insensitive string comparison for INP
;; section keyword identification

(module
  (memory (export "memory") 1)

  ;; toLower: convert ASCII uppercase to lowercase
  (func $toLower (param $c i32) (result i32)
    (if (result i32) (i32.and
          (i32.ge_u (local.get $c) (i32.const 65))
          (i32.le_u (local.get $c) (i32.const 90)))
      (then (i32.add (local.get $c) (i32.const 32)))
      (else (local.get $c))))

  ;; strEqCI: case-insensitive string compare
  (func $strEqCI (param $a i32) (param $b i32)
                  (result i32)
    (local $ca i32) (local $cb i32)
    (block $done
      (loop $loop
        (local.set $ca
          (i32.load8_u (local.get $a)))
        (local.set $cb
          (i32.load8_u (local.get $b)))
        (br_if $done
          (i32.and
            (i32.eqz (local.get $ca))
            (i32.eqz (local.get $cb))))
        (if (i32.ne
              (call $toLower (local.get $ca))
              (call $toLower (local.get $cb)))
          (then (return (i32.const 0))))
        (local.set $a
          (i32.add (local.get $a) (i32.const 1)))
        (local.set $b
          (i32.add (local.get $b) (i32.const 1)))
        (br $loop)))
    (i32.const 1))

  ;; findKeyword: search keyword table
  ;; table_ptr: start of keyword strings (32 bytes each)
  ;; count: number of keywords
  ;; token_ptr: pointer to search token
  (func (export "findKeyword")
        (param $table_ptr i32) (param $count i32)
        (param $token_ptr i32) (result i32)
    (local $i i32)
    (local $ptr i32)
    (local.set $i (i32.const 0))
    (block $done
      (loop $loop
        (br_if $done (i32.ge_u (local.get $i)
                               (local.get $count)))
        (local.set $ptr
          (i32.add (local.get $table_ptr)
            (i32.mul (local.get $i) (i32.const 32))))
        (if (call $strEqCI (local.get $ptr)
                           (local.get $token_ptr))
          (then (return (local.get $i))))
        (local.set $i
          (i32.add (local.get $i) (i32.const 1)))
        (br $loop)))
    (i32.const -1))
)`,
