    ada: `-- keywords.adb — Keyword/Token Lookup
-- SWMM5 Engine in Ada — INP Section Keyword Matcher
-- Manages a table of SWMM section keywords and
-- provides case-insensitive lookup for the parser

with Ada.Characters.Handling;
use Ada.Characters.Handling;

package Keywords is

   Max_Keywords : constant := 64;
   Max_Key_Len  : constant := 32;

   type Keyword_Array is array (1 .. Max_Keywords)
      of String (1 .. Max_Key_Len);

   type Keyword_Table is record
      Words : Keyword_Array;
      Count : Natural := 0;
   end record;

   procedure Init (KT : in out Keyword_Table) is
      Defaults : constant array (1 .. 24) of String (1 .. Max_Key_Len) := (
         "TITLE                           ",
         "OPTIONS                         ",
         "RAINGAGES                       ",
         "SUBCATCHMENTS                   ",
         "SUBAREAS                        ",
         "INFILTRATION                    ",
         "JUNCTIONS                       ",
         "OUTFALLS                        ",
         "STORAGE                         ",
         "CONDUITS                        ",
         "PUMPS                           ",
         "ORIFICES                        ",
         "WEIRS                           ",
         "XSECTIONS                       ",
         "TRANSECTS                       ",
         "CONTROLS                        ",
         "DWF                             ",
         "CURVES                          ",
         "TIMESERIES                      ",
         "REPORT                          ",
         "MAP                             ",
         "COORDINATES                     ",
         "VERTICES                        ",
         "LABELS                          "
      );
   begin
      KT.Count := 24;
      for I in 1 .. 24 loop
         KT.Words (I) := Defaults (I);
      end loop;
   end Init;

   function Find (KT : Keyword_Table;
                  Token : String) return Integer is
      Lower_Token : constant String := To_Lower (Token);
   begin
      for I in 1 .. KT.Count loop
         if To_Lower (KT.Words (I) (1 .. Token'Length))
            = Lower_Token then
            return I;
         end if;
      end loop;
      return -1;
   end Find;

   function Add (KT : in out Keyword_Table;
                 Word : String) return Boolean is
   begin
      if KT.Count >= Max_Keywords then
         return False;
      end if;
      KT.Count := KT.Count + 1;
      KT.Words (KT.Count) := (others => ' ');
      KT.Words (KT.Count) (1 .. Word'Length) := Word;
      return True;
   end Add;

end Keywords;`,
    chapel: `// keywords.chpl — Keyword/Token Lookup
// SWMM5 Engine in Chapel — INP Section Keyword Matcher
// Manages a table of SWMM section keywords and
// provides case-insensitive lookup for the parser

param MAX_KEYWORDS = 64;

const SWMM_DEFAULTS: [0..23] string = [
    "TITLE", "OPTIONS", "RAINGAGES",
    "SUBCATCHMENTS", "SUBAREAS", "INFILTRATION",
    "JUNCTIONS", "OUTFALLS", "STORAGE",
    "CONDUITS", "PUMPS", "ORIFICES",
    "WEIRS", "XSECTIONS", "TRANSECTS",
    "CONTROLS", "DWF", "CURVES",
    "TIMESERIES", "REPORT", "MAP",
    "COORDINATES", "VERTICES", "LABELS"
];

record KeywordTable {
    var words: [0..-1] string;
    var count: int = 0;

    proc ref init(useDefaults: bool = true) {
        if useDefaults {
            for w in SWMM_DEFAULTS {
                words.push_back(w);
                count += 1;
            }
        }
    }

    proc find(token: string): int {
        var lower = token.toLower().strip();
        for i in 0..#count {
            if words[i].toLower() == lower then
                return i;
        }
        return -1;
    }

    proc ref add(word: string): bool {
        if count >= MAX_KEYWORDS then return false;
        words.push_back(word);
        count += 1;
        return true;
    }

    proc getCount(): int { return count; }

    proc getWord(index: int): string {
        if index >= 0 && index < count then
            return words[index];
        return "";
    }

    proc contains(token: string): bool {
        return find(token) >= 0;
    }

    proc ref remove(token: string): bool {
        var idx = find(token);
        if idx >= 0 {
            for i in idx..#(count - idx - 1) {
                words[i] = words[i + 1];
            }
            count -= 1;
            return true;
        }
        return false;
    }
}`,
    swift: `// keywords.swift — Keyword/Token Lookup
// SWMM5 Engine in Swift — INP Section Keyword Matcher
// Manages a table of SWMM section keywords and
// provides case-insensitive lookup for the parser

import Foundation

let MAX_KEYWORDS = 64

let swmmDefaults = [
    "TITLE", "OPTIONS", "RAINGAGES",
    "SUBCATCHMENTS", "SUBAREAS", "INFILTRATION",
    "JUNCTIONS", "OUTFALLS", "STORAGE",
    "CONDUITS", "PUMPS", "ORIFICES",
    "WEIRS", "XSECTIONS", "TRANSECTS",
    "CONTROLS", "DWF", "CURVES",
    "TIMESERIES", "REPORT", "MAP",
    "COORDINATES", "VERTICES", "LABELS"
]

class KeywordTable {
    private var words: [String]

    init(useDefaults: Bool = true) {
        words = useDefaults ? Array(swmmDefaults) : []
    }

    func find(_ token: String) -> Int {
        let lower = token.trimmingCharacters(
            in: .whitespaces).lowercased()
        for (i, word) in words.enumerated() {
            if word.lowercased() == lower { return i }
        }
        return -1
    }

    func add(_ word: String) -> Bool {
        if words.count >= MAX_KEYWORDS { return false }
        words.append(word)
        return true
    }

    func getCount() -> Int { return words.count }

    func getWord(_ index: Int) -> String {
        if index >= 0 && index < words.count {
            return words[index]
        }
        return ""
    }

    func contains(_ token: String) -> Bool {
        return find(token) >= 0
    }

    func remove(_ token: String) -> Bool {
        let idx = find(token)
        if idx >= 0 {
            words.remove(at: idx)
            return true
        }
        return false
    }
}`,
