    go: `// swmm5.go — Main Simulation API
// SWMM5 Engine in Go — Top-level Simulation Controller
// Provides Open/Start/Step/End/Close entry points
// for driving the SWMM5 simulation engine

package swmm

import (
    "errors"
)

var (
    ErrAlreadyOpen    = errors.New("project already open")
    ErrNotOpen        = errors.New("project not open")
    ErrAlreadyRunning = errors.New("already running")
    ErrNotRunning     = errors.New("not running")
)

type SwmmModel struct {
    ProjectOpen   bool
    Running       bool
    ElapsedTime   float64
    TotalDuration float64
    RouteStep     float64
    InputFile     string
    ReportFile    string
}

func NewSwmm() *SwmmModel {
    return &SwmmModel{}
}

func (s *SwmmModel) Open(inp, rpt string) error {
    if s.ProjectOpen {
        return ErrAlreadyOpen
    }
    s.InputFile = inp
    s.ReportFile = rpt
    s.ProjectOpen = true
    s.Running = false
    s.ElapsedTime = 0.0
    return nil
}

func (s *SwmmModel) Start(duration,
    step float64) error {
    if !s.ProjectOpen {
        return ErrNotOpen
    }
    if s.Running {
        return ErrAlreadyRunning
    }
    s.TotalDuration = duration
    s.RouteStep = step
    s.ElapsedTime = 0.0
    s.Running = true
    return nil
}

func (s *SwmmModel) Step() (float64, error) {
    if !s.Running {
        return 0, ErrNotRunning
    }
    s.ElapsedTime += s.RouteStep
    if s.ElapsedTime >= s.TotalDuration {
        s.ElapsedTime = s.TotalDuration
        s.Running = false
    }
    return s.ElapsedTime, nil
}

func (s *SwmmModel) GetProgress() float64 {
    if s.TotalDuration <= 0.0 {
        return 0.0
    }
    return (s.ElapsedTime / s.TotalDuration) * 100.0
}

func (s *SwmmModel) End() {
    s.Running = false
}

func (s *SwmmModel) Close() {
    s.ProjectOpen = false
    s.Running = false
    s.ElapsedTime = 0.0
    s.TotalDuration = 0.0
}`,
