    cpp: `// swmm5.cpp — Main Simulation API
// SWMM5 Engine in C++ — Top-level Simulation Controller
// Provides open/start/step/end/close entry points
// for driving the SWMM5 simulation engine

#include <string>
#include <stdexcept>

namespace swmm {

class SwmmError : public std::runtime_error {
public:
    using std::runtime_error::runtime_error;
};

class SwmmModel {
    bool projectOpen_ = false;
    bool running_ = false;
    double elapsedTime_ = 0.0;
    double totalDuration_ = 0.0;
    double routeStep_ = 0.0;
    std::string inputFile_;
    std::string reportFile_;

public:
    void open(const std::string& inp,
              const std::string& rpt) {
        if (projectOpen_)
            throw SwmmError("Project already open");
        inputFile_ = inp;
        reportFile_ = rpt;
        projectOpen_ = true;
        running_ = false;
        elapsedTime_ = 0.0;
    }

    void start(double duration, double step) {
        if (!projectOpen_)
            throw SwmmError("Project not open");
        if (running_)
            throw SwmmError("Already running");
        totalDuration_ = duration;
        routeStep_ = step;
        elapsedTime_ = 0.0;
        running_ = true;
    }

    double step() {
        if (!running_)
            throw SwmmError("Not running");
        elapsedTime_ += routeStep_;
        if (elapsedTime_ >= totalDuration_) {
            elapsedTime_ = totalDuration_;
            running_ = false;
        }
        return elapsedTime_;
    }

    double getProgress() const {
        if (totalDuration_ <= 0.0) return 0.0;
        return (elapsedTime_ / totalDuration_) * 100.0;
    }

    void end() { running_ = false; }

    void close() {
        projectOpen_ = false;
        running_ = false;
        elapsedTime_ = 0.0;
        totalDuration_ = 0.0;
    }

    bool isRunning() const { return running_; }
    bool isOpen() const { return projectOpen_; }
};

} // namespace swmm`,
